// API route that schedules a background analytics ping after the Response resolves
// This uses the runtime-provided helper `deferTask` shown in Expo/Router docs.
export async function GET(request: Request) {
  // Schedule work to run after this function resolves and the Response is sent
  deferTask(async () => {
    try {
      await fetch('https://example.com/analytics', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          event: 'api_called',
          path: new URL(request.url).pathname,
          timestamp: Date.now(),
        }),
      });
    } catch (err) {
      // Swallow errors in deferred tasks so they don't affect the main Response
      console.error('Deferred analytics failed:', err);
    }
  });

  // Normal synchronous-ish work for the route
  const res = await fetch('https://jsonplaceholder.typicode.com/todos/1');
  const data = await res.json();

  // Return using Response.json() as in the documented runtime
  return Response.json({ data });
}

import React, { useState, useTransition, useMemo } from "react";
import { SafeAreaView, View, TextInput, FlatList, Text, ActivityIndicator, StyleSheet } from "react-native";

export default function App(): JSX.Element {
  // Large dataset to simulate heavy filtering work
  const items = useMemo(() => Array.from({ length: 10000 }, (_, i) => `Item ${i + 1}`), []);

  // Immediate input state to keep the TextInput snappy
  const [inputValue, setInputValue] = useState("");
  // Deferred search query used for expensive filtering
  const [searchQuery, setSearchQuery] = useState("");

  // React transition API (available in React 18/19)
  const [isPending, startTransition] = useTransition();

  const onChangeText = (text: string) => {
    // Update immediate value so the input updates without delay
    setInputValue(text);

    // Defer the expensive update (filtering) inside a transition
    startTransition(() => {
      setSearchQuery(text);
    });
  };

  // Expensive filtering happens here but is deferred via `searchQuery`
  const filtered = useMemo(() => {
    const q = searchQuery.trim().toLowerCase();
    if (!q) return items;
    return items.filter((it) => it.toLowerCase().includes(q));
  }, [items, searchQuery]);

  return (
    <SafeAreaView style={styles.container}>
      <TextInput
        placeholder="Search items..."
        value={inputValue}
        onChangeText={onChangeText}
        style={styles.input}
        accessibilityLabel="Search input"
        autoCorrect={false}
        autoCapitalize="none"
      />

      {/* Show a subtle indicator while the transition (filter) is pending */}
      {isPending && (
        <View style={styles.pendingRow} pointerEvents="none">
          <ActivityIndicator size="small" />
          <Text style={styles.pendingText}>Updating results...</Text>
        </View>
      )}

      <Text style={styles.resultInfo}>{filtered.length} results</Text>

      <FlatList
        data={filtered}
        keyExtractor={(item) => item}
        renderItem={({ item }) => (
          <View style={styles.row}>
            <Text style={styles.rowText}>{item}</Text>
          </View>
        )}
        initialNumToRender={20}
        windowSize={10}
      />
    </SafeAreaView>
  );
}

