import React, { useState, useCallback } from 'react';
import { View, Text, Button, StyleSheet } from 'react-native';
// Using Reanimated's Animated and predefined transitions as shown in the docs
import Animated, { LinearTransition, JumpingTransition } from 'react-native-reanimated';

type Item = { id: string; label: string };

export default function App() {
  const [items, setItems] = useState<Item[]>([
    { id: '1', label: 'Item 1' },
    { id: '2', label: 'Item 2' },
    { id: '3', label: 'Item 3' },
  ]);

  // itemLayoutAnimation can be a transition or undefined
  const [transition, setTransition] = useState<any>(LinearTransition);
  const [counter, setCounter] = useState(4);

  const addItem = useCallback(() => {
    const next = String(counter);
    setItems(prev => [{ id: next, label: `Item ${next}` }, ...prev]);
    setCounter(c => c + 1);
  }, [counter]);

  const removeItem = useCallback(() => {
    setItems(prev => (prev.length ? prev.slice(1) : prev));
  }, []);

  const shuffle = useCallback(() => {
    setItems(prev => {
      const copy = [...prev];
      for (let i = copy.length - 1; i > 0; i--) {
        const j = Math.floor(Math.random() * (i + 1));
        [copy[i], copy[j]] = [copy[j], copy[i]];
      }
      return copy;
    });
  }, []);

  const changeTransition = useCallback(() => {
    setTransition(t => (t === LinearTransition ? JumpingTransition : LinearTransition));
  }, []);

  const toggleTransition = useCallback(() => {
    setTransition(t => (t ? undefined : LinearTransition));
  }, []);

  return (
    <View style={styles.container}>
      <View style={styles.controls}>
        <Button title="Add item" onPress={addItem} />
        <Button title="Remove item" onPress={removeItem} />
        <Button title="Shuffle" onPress={shuffle} />
        <Button title="Change transition" onPress={changeTransition} />
        <Button title={transition ? 'Disable transition' : 'Enable LinearTransition'} onPress={toggleTransition} />
      </View>

      <Animated.FlatList
        // itemLayoutAnimation accepts a transition (or undefined to disable)
        itemLayoutAnimation={transition}
        data={items}
        // Ensure a unique key for each item
        keyExtractor={(item) => item.id}
        renderItem={({ item }) => (
          <View style={styles.item}>
            <Text style={styles.label}>{item.label}</Text>
          </View>
        )}
        // Must be single column for itemLayoutAnimation to work
        numColumns={1}
        contentContainerStyle={styles.listContent}
      />
    </View>
  );
}

