  value: { fontWeight: "700" },
  notice: { marginTop: 12, color: "#0a84ff" }
});

import React, { useState, useMemo } from 'react';
import { View, Text, TextInput, Switch, Button, ScrollView, StyleSheet, Alert, Platform } from 'react-native';
import * as Clipboard from 'expo-clipboard';

export default function EasPrebuildYamlGenerator() {
  const [name, setName] = useState('Run prebuild script');
  const [clean, setClean] = useState(false);
  const [appleTeamId, setAppleTeamId] = useState('');
  const [showPreview, setShowPreview] = useState(true);

  const yaml = useMemo(() => {
    const indent = (level: number) => '  '.repeat(level);

    let lines: string[] = [];
    lines.push('build:');
    lines.push(`${indent(1)}name: ${escapeYamlScalar(name)}`);
    lines.push(`${indent(1)}steps:`);
    lines.push(`${indent(2)}- eas/checkout`);
    lines.push(`${indent(2)}- eas/install_node_modules`);
    // include base prebuild step
    lines.push(`${indent(2)}- eas/prebuild`);

    // create a separate reusable function step with inputs if any inputs are provided
    if (clean || appleTeamId.trim() !== '') {
      lines.push(`${indent(2)}- eas/prebuild:`);
      lines.push(`${indent(3)}inputs:`);
      if (clean) {
        lines.push(`${indent(4)}clean: true`);
      }
      if (appleTeamId.trim() !== '') {
        // quote team id to be safe in YAML
        lines.push(`${indent(4)}apple_team_id: "${escapeYamlScalar(appleTeamId)}"`);
      }
    }

    // include the info markers shown in the docs
    lines.push(`${indent(2)}# @info #`);
    lines.push(`${indent(2)}- eas/prebuild`);
    lines.push(`${indent(2)}# @end #`);

    return lines.join('\n');
  }, [name, clean, appleTeamId]);

  async function copyToClipboard() {
    try {
      await Clipboard.setStringAsync(yaml);
      Alert.alert('Copied', 'YAML copied to clipboard');
    } catch (e) {
      Alert.alert('Error', String(e));
    }
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>EAS prebuild YAML Generator</Text>

      <View style={styles.row}>
        <Text style={styles.label}>Step name</Text>
        <TextInput
          style={styles.input}
          value={name}
          onChangeText={setName}
          placeholder="Run prebuild script"
          returnKeyType="done"
        />
      </View>

      <View style={styles.rowInline}>
        <Text style={styles.label}>Use --clean</Text>
        <Switch value={clean} onValueChange={setClean} />
      </View>

      <View style={styles.row}>
        <Text style={styles.label}>Apple Team ID (optional)</Text>
        <TextInput
          style={styles.input}
          value={appleTeamId}
          onChangeText={setAppleTeamId}
          placeholder="E.g. ABCDE12345"
          autoCapitalize="characters"
        />
      </View>

      <View style={styles.buttonsRow}>
        <Button title={showPreview ? 'Hide Preview' : 'Show Preview'} onPress={() => setShowPreview(v => !v)} />
        <Button title="Copy YAML" onPress={copyToClipboard} />
      </View>

      {showPreview && (
        <ScrollView style={styles.preview} contentContainerStyle={{ padding: 12 }}>
          <Text style={styles.mono}>{yaml}</Text>
        </ScrollView>
      )}

      <Text style={styles.hint}>
        This screen generates a YAML snippet for the docs' eas/prebuild step with optional inputs.clean and
        inputs.apple_team_id.
      </Text>
    </View>
  );
}

function escapeYamlScalar(s: string) {
  if (/[:#\n\r\t]/.test(s) || s.trim() !== s) {
    return s.replace(/"/g, '\\"');
  }
  return s;
}

