import React, { useState } from 'react';
import { StyleSheet, View, Text, TextInput, Button, ActivityIndicator, Alert, Platform } from 'react-native';
import * as Clipboard from 'expo-clipboard';

export default function App() {
  const [textToCopy, setTextToCopy] = useState('Hello from Expo!');
  const [pastedText, setPastedText] = useState('');
  const [loading, setLoading] = useState(false);

  // Copy text to clipboard using expo-clipboard
  const copyToClipboard = async () => {
    try {
      setLoading(true);
      await Clipboard.setStringAsync(textToCopy);
      setLoading(false);
      Alert.alert('Copied', 'Text copied to clipboard');
    } catch (err) {
      setLoading(false);
      Alert.alert('Error', String(err));
    }
  };

  // Read (paste) text from clipboard using expo-clipboard with a web fallback
  const pasteFromClipboard = async () => {
    try {
      setLoading(true);
      // Primary: expo-clipboard API
      let content = await Clipboard.getStringAsync();

      // Fallback for some WebKit browsers where AsyncClipboard may misbehave
      if (Platform.OS === 'web' && (!content || content.length === 0)) {
        // navigator.clipboard might be available in secure contexts
        if (typeof navigator !== 'undefined' && navigator.clipboard && navigator.clipboard.readText) {
          try {
            const webText = await navigator.clipboard.readText();
            content = webText || content;
          } catch (webErr) {
            // ignore and keep expo-clipboard result
          }
        }
      }

      setPastedText(content ?? '');
      setLoading(false);
    } catch (err) {
      setLoading(false);
      Alert.alert('Error', String(err));
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.label}>Text to copy</Text>
      <TextInput
        style={styles.input}
        value={textToCopy}
        onChangeText={setTextToCopy}
        placeholder="Type something to copy"
        returnKeyType="done"
      />

      <View style={styles.buttonRow}>
        <Button title="Copy" onPress={copyToClipboard} />
        <View style={styles.buttonSpacer} />
        <Button title="Paste" onPress={pasteFromClipboard} />
      </View>

      {loading ? <ActivityIndicator style={styles.loader} /> : null}

      <Text style={styles.label}>Pasted text</Text>
      <View style={styles.pasteBox}>
        <Text selectable>{pastedText || '(empty)'}</Text>
      </View>

      {Platform.OS === 'web' ? (
        <Text style={styles.note}>
          Note: Web clipboard behavior varies across browsers (WebKit may be limited).
        </Text>
      ) : null}
    </View>
  );
}

