import React, {useCallback, useEffect, useState} from 'react';
import {
  ActivityIndicator,
  Button,
  FlatList,
  ListRenderItem,
  Pressable,
  SafeAreaView,
  StyleSheet,
  Text,
  View,
} from 'react-native';

type Item = {
  id: number;
  title: string;
  body: string;
};

const PAGE_SIZE = 10;
const API_URL = 'https://jsonplaceholder.typicode.com/posts';

export default function PaginatedListScreen(): JSX.Element {
  const [data, setData] = useState<Item[]>([]);
  const [page, setPage] = useState<number>(1);
  const [loading, setLoading] = useState<boolean>(false);
  const [refreshing, setRefreshing] = useState<boolean>(false);
  const [error, setError] = useState<string | null>(null);
  const [hasMore, setHasMore] = useState<boolean>(true);

  const fetchPage = useCallback(async (pageToFetch: number, append = false) => {
    if (loading) return;
    setLoading(true);
    setError(null);
    try {
      const url = `${API_URL}?_page=${pageToFetch}&_limit=${PAGE_SIZE}`;
      const resp = await fetch(url);
      if (!resp.ok) throw new Error(`HTTP ${resp.status}`);
      const items: Item[] = await resp.json();

      // jsonplaceholder returns empty array at end
      setHasMore(items.length >= PAGE_SIZE);

      setData(prev => (append ? [...prev, ...items] : items));
      setPage(pageToFetch);
    } catch (e: any) {
      setError(e?.message ?? 'Unknown error');
    } finally {
      setLoading(false);
      setRefreshing(false);
    }
  }, [loading]);

  useEffect(() => {
    // initial load
    fetchPage(1, false);
  }, [fetchPage]);

  const onRefresh = useCallback(() => {
    setRefreshing(true);
    fetchPage(1, false);
  }, [fetchPage]);

  const onEndReached = useCallback(() => {
    if (loading || refreshing || !hasMore) return;
    fetchPage(page + 1, true);
  }, [fetchPage, loading, refreshing, hasMore, page]);

  const renderItem: ListRenderItem<Item> = ({item}) => (
    <View style={styles.item}>
      <Text style={styles.title}>{item.title}</Text>
      <Text style={styles.body}>{item.body}</Text>
    </View>
  );

  const renderFooter = () => {
    if (loading && data.length > 0) {
      return (
        <View style={styles.footer}>
          <ActivityIndicator />
          <Text style={styles.footerText}>Loading more...</Text>
        </View>
      );
    }
    if (!hasMore) {
      return (
        <View style={styles.footer}>
          <Text style={styles.footerText}>No more items</Text>
        </View>
      );
    }
    return null;
  };

  // If initial load failed and there's no data, show big retry UI
  if (error && data.length === 0) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.center}>
          <Text style={styles.errorText}>Failed to load: {error}</Text>
          <Button title="Retry" onPress={() => fetchPage(1, false)} />
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      <FlatList
        data={data}
        keyExtractor={(item) => item.id.toString()}
        renderItem={renderItem}
        onEndReached={onEndReached}
        onEndReachedThreshold={0.5}
        ListFooterComponent={renderFooter}
        refreshing={refreshing}
        onRefresh={onRefresh}
        contentContainerStyle={data.length === 0 ? styles.center : undefined}
        ListEmptyComponent={() => (
          <View style={styles.center}>
            {loading ? <ActivityIndicator /> : <Text>No items yet</Text>}
            {error ? (
              <Pressable style={styles.retryButton} onPress={() => fetchPage(1, false)}>
                <Text style={styles.retryText}>Retry</Text>
              </Pressable>
            ) : null}
          </View>
        )}
      />
    </SafeAreaView>
  );
}

