  retryText: {color: '#fff', fontWeight: '600'},
});

import React, { useState } from 'react';
import { View, Text, TextInput, Button, StyleSheet, ActivityIndicator, Alert, Platform } from 'react-native';
import * as Clipboard from 'expo-clipboard';

export default function App() {
  const [inputText, setInputText] = useState<string>('Hello from Expo');
  const [pastedText, setPastedText] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(false);
  const [status, setStatus] = useState<string>('');

  const copyToClipboard = async () => {
    setLoading(true);
    setStatus('');
    try {
      // Primary: expo-clipboard API
      await Clipboard.setStringAsync(inputText);
      setStatus('Copied to clipboard (expo-clipboard).');
    } catch (expoErr) {
      // Fallback for Web or other environments
      if (Platform.OS === 'web' && typeof navigator !== 'undefined' && navigator.clipboard?.writeText) {
        try {
          await navigator.clipboard.writeText(inputText);
          setStatus('Copied to clipboard (navigator.clipboard fallback).');
        } catch (navErr) {
          Alert.alert('Copy failed', String(navErr));
          setStatus('Copy failed.');
        }
      } else {
        Alert.alert('Copy failed', String(expoErr));
        setStatus('Copy failed.');
      }
    } finally {
      setLoading(false);
    }
  };

  const pasteFromClipboard = async () => {
    setLoading(true);
    setStatus('');
    try {
      // Primary: expo-clipboard API
      let text = await Clipboard.getStringAsync();

      // If expo-clipboard returned empty on Web, try navigator.clipboard
      if ((!text || text.length === 0) && Platform.OS === 'web' && typeof navigator !== 'undefined' && navigator.clipboard?.readText) {
        try {
          text = await navigator.clipboard.readText();
        } catch (navErr) {
          // ignore navigator fallback error and surface the main error below
        }
      }

      setPastedText(text ?? '');
      setStatus('Pasted from clipboard.');
    } catch (err) {
      Alert.alert('Paste failed', String(err));
      setStatus('Paste failed.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Expo Clipboard Example</Text>

      <TextInput
        style={styles.input}
        value={inputText}
        onChangeText={setInputText}
        placeholder="Type text to copy"
        multiline
      />

      <View style={styles.buttonsRow}>
        <Button title="Copy" onPress={copyToClipboard} />
        <View style={styles.spacer} />
        <Button title="Paste" onPress={pasteFromClipboard} />
      </View>

      {loading ? <ActivityIndicator style={styles.loader} /> : null}

      <Text style={styles.label}>Status: {status}</Text>

      <Text style={styles.label}>Pasted text:</Text>
      <Text style={styles.pasted}>{pastedText || '(empty)'}</Text>

      <Text style={styles.hint}>
        Note: On some WebKit browsers clipboard APIs may behave differently; this component tries expo-clipboard first and falls back to navigator.clipboard when available.
      </Text>
    </View>
  );
}

