import React, { useState } from 'react';
import { View, Text, Button, StyleSheet } from 'react-native';
import Animated, { LinearTransition, JumpingTransition } from 'react-native-reanimated';

type Item = { id: string; title: string };
type TransitionType = typeof LinearTransition | typeof JumpingTransition | undefined;

const DATA: Item[] = [
  { id: '1', title: 'First Item' },
  { id: '2', title: 'Second Item' },
  { id: '3', title: 'Third Item' },
];

export default function App(): JSX.Element {
  const [items, setItems] = useState<Item[]>(DATA);
  const [transition, setTransition] = useState<TransitionType>(LinearTransition);

  const shuffleItems = () => {
    setItems(prev => {
      const copy = [...prev];
      copy.sort(() => Math.random() - 0.5);
      return copy;
    });
  };

  const changeTransition = () => {
    setTransition(prev => (prev === LinearTransition ? JumpingTransition : LinearTransition));
  };

  const toggleTransition = () => {
    setTransition(prev => (prev ? undefined : LinearTransition));
  };

  return (
    <View style={styles.container}>
      <View style={styles.buttonsRow}>
        <Button title="Shuffle Items" onPress={shuffleItems} />
        <Button title="Change Transition" onPress={changeTransition} />
        <Button title="Toggle Transition" onPress={toggleTransition} />
      </View>

      <Animated.FlatList<Item>
        data={items}
        renderItem={({ item }) => (
          <View style={styles.item}>
            <Text style={styles.title}>{item.title}</Text>
          </View>
        )}
        keyExtractor={item => item.id}
        itemLayoutAnimation={transition}
        // itemLayoutAnimation works only with single-column lists
        numColumns={1}
        contentContainerStyle={styles.listContent}
      />
    </View>
  );
}

const styles = StyleSheet.create({
  container: { flex: 1, padding: 24, backgroundColor: '#fff' },
  buttonsRow: { flexDirection: 'row', justifyContent: 'space-between', marginBottom: 12 },
  listContent: { paddingBottom: 24 },
  item: { backgroundColor: '#eee', padding: 20, marginVertical: 8, borderRadius: 8 },
  title: { fontSize: 18 },
});

// runPrebuild.ts
// A small, safe TypeScript utility to construct and run an EAS prebuild command from Node.js
// - Exports a pure helper to build the command
// - Exports an async runner that dynamically imports child_process so the module can be type-checked in RN/Expo

export type PrebuildOptions = {
  /** When true, pass --clean to `eas prebuild` */
  clean?: boolean;
  /** Working directory to run the command in (defaults to process.cwd()) */
  cwd?: string;
};

/**
 * Build the eas prebuild command string.
 * This is pure and safe to call anywhere (including in RN bundler).
 */
export function getPrebuildCommand(options: PrebuildOptions = {}): string {
  const parts = ['eas', 'prebuild'];
  if (options.clean) parts.push('--clean');
  return parts.join(' ');
}

/**
 * Run the prebuild command in Node.js. Dynamically imports child_process at runtime so
 * this module can be imported in environments (like Expo) that do not have Node APIs.
 *
 * Throws if called outside Node.js.
 */
export async function runPrebuild(stepName = 'Prebuild', options: PrebuildOptions = {}): Promise<void> {
  if (typeof process === 'undefined' || typeof (process as any).versions === 'undefined' || !(process as any).versions.node) {
    throw new Error('runPrebuild can only be executed in a Node.js environment');
  }

  // Dynamic import ensures bundlers for RN/Expo won't try to resolve child_process at bundle time
  const child = await import('child_process');
  const execSync = child.execSync;

  const cmd = getPrebuildCommand(options);
  console.log(`Running EAS step: ${stepName}`);
  try {
    execSync(cmd, { stdio: 'inherit', cwd: options.cwd ?? process.cwd() });
  } catch (err) {
    // keep error visible and rethrow for callers to handle
    console.error('Prebuild failed:', err instanceof Error ? err.message : err);
    throw err;
  }
}

export default {
  getPrebuildCommand,
  runPrebuild,
};

import React, { useState } from "react";
import { View, Text, Button, StyleSheet } from "react-native";
import Animated, { LinearTransition, JumpingTransition } from "react-native-reanimated";

type Item = { id: string; title: string };

const INITIAL_DATA: Item[] = [
  { id: "1", title: "First Item" },
  { id: "2", title: "Second Item" },
  { id: "3", title: "Third Item" },
];

export default function App(): JSX.Element {
  // Use a permissive type for the transition state to avoid strict mismatch errors.
  // The value passed to itemLayoutAnimation can be a predefined transition (e.g. LinearTransition)
  // or undefined to disable the animation.
  const [transition, setTransition] = useState<any>(LinearTransition);
  const [data, setData] = useState<Item[]>(INITIAL_DATA);

  const shuffleData = () => {
    setData((prev) => {
      const copy = [...prev];
      copy.reverse();
      return copy;
    });
  };

  const changeTransition = () => {
    // Toggle between two predefined transitions by reference comparison.
    setTransition((current: any) =>
      current === LinearTransition ? JumpingTransition : LinearTransition
    );
  };

  const toggleTransition = () => {
    // Enable/disable the layout transition.
    setTransition((current: any) => (current ? undefined : LinearTransition));
  };

  return (
    <View style={styles.container}>
      <View style={styles.controls}>
        <Button title="Shuffle Items" onPress={shuffleData} />
        <Button title="Change Transition" onPress={changeTransition} />
        <Button title="Toggle Transition" onPress={toggleTransition} />
      </View>

      <Animated.FlatList<Item>
        data={data}
        renderItem={({ item }) => (
          <View style={styles.item}>
            <Text style={styles.itemText}>{item.title}</Text>
          </View>
        )}
        keyExtractor={(item) => item.id}
        // Apply the itemLayoutAnimation. It accepts a transition or undefined.
        itemLayoutAnimation={transition}
        // Ensure a single-column list (numColumns must not be > 1 for itemLayoutAnimation).
        numColumns={1}
        contentContainerStyle={styles.listContent}
      />
    </View>
  );
}

