import { useEffect, useState } from 'react';
import { View, Text } from 'react-native';
import * as FileSystem from 'expo-file-system';

const PACKAGE_JSON_PATH = FileSystem.documentDirectory + 'package.json';

export default function ExcludedPackages() {
  const [excluded, setExcluded] = useState<string[] | null>(null);

  useEffect(() => {
    (async () => {
      try {
        const content = await FileSystem.readAsStringAsync(PACKAGE_JSON_PATH);
        const pkg = JSON.parse(content);
        const exclude = pkg?.expo?.install?.exclude ?? [];
        setExcluded(exclude);
      } catch (e) {
        setExcluded([]);
      }
    })();
  }, []);

  return (
    <View style={{ padding: 16 }}>
      <Text style={{ fontWeight: 'bold' }}>Excluded Packages:</Text>
      {excluded === null ? (
        <Text>Loading...</Text>
      ) : excluded.length === 0 ? (
        <Text>None</Text>
      ) : (
        excluded.map((pkg) => <Text key={pkg}>{pkg}</Text>)
      )}
    </View>
  );
}

