import React, { useEffect, useRef, useState } from 'react';
import { Animated, Pressable, StyleSheet, Text, View } from 'react-native';

// A self-contained, strongly-typed toggle switch with custom colors and thumb content.
// This avoids dependence on non-existent static props and compiles in a React Native / Expo project.
export default function CustomSwitchExample(): JSX.Element {
  const [on, setOn] = useState(false);
  return (
    <View style={styles.container}>
      <Text style={styles.label}>Custom Switch</Text>
      <CustomSwitch
        value={on}
        onValueChange={setOn}
        trackColor={{ true: '#4CAF50', false: '#BDBDBD' }}
        thumbColor={{ true: '#FFFFFF', false: '#757575' }}
        thumbContent={(props) => (
          <Text style={[styles.thumbIcon, { color: props.iconColor, fontSize: props.iconSize }]}>
            {props.checked ? '✓' : '✗'}
          </Text>
        )}
        accessibilityLabel="Enable feature"
      />
    </View>
  );
}

type ThumbContentProps = {
  checked: boolean;
  iconSize: number;
  iconColor: string;
};

type CustomSwitchProps = {
  value: boolean;
  onValueChange: (value: boolean) => void;
  trackColor?: { true: string; false: string };
  thumbColor?: { true: string; false: string };
  // Render prop for custom content inside the thumb
  thumbContent?: (props: ThumbContentProps) => React.ReactNode;
  accessibilityLabel?: string;
};

function CustomSwitch({
  value,
  onValueChange,
  trackColor = { true: '#4CAF50', false: '#BDBDBD' },
  thumbColor = { true: '#FFFFFF', false: '#757575' },
  thumbContent,
  accessibilityLabel,
}: CustomSwitchProps): JSX.Element {
  // Visual sizes (tweak as desired)
  const TRACK_WIDTH = 56;
  const TRACK_HEIGHT = 32;
  const THUMB_SIZE = 26;
  const HORIZONTAL_PADDING = (TRACK_HEIGHT - THUMB_SIZE) / 2; // center vertically
  const travel = TRACK_WIDTH - THUMB_SIZE - HORIZONTAL_PADDING * 2;
  const ICON_SIZE = 12; // safe default size for thumb content

  const anim = useRef(new Animated.Value(value ? 1 : 0)).current;

  useEffect(() => {
    Animated.timing(anim, {
      toValue: value ? 1 : 0,
      duration: 160,
      useNativeDriver: true,
    }).start();
  }, [value, anim]);

  const translateX = anim.interpolate({
    inputRange: [0, 1],
    outputRange: [0, travel],
  });

  const currentTrackColor = value ? trackColor.true : trackColor.false;
  const currentThumbColor = value ? thumbColor.true : thumbColor.false;

  return (
    <Pressable
      onPress={() => onValueChange(!value)}
      accessibilityRole="switch"
      accessibilityState={{ checked: value }}
      accessibilityLabel={accessibilityLabel}
      style={({ pressed }) => [
        styles.trackWrapper,
        { opacity: pressed ? 0.85 : 1 },
      ]}
    >
      <View
        style={[
          styles.track,
          {
            width: TRACK_WIDTH,
            height: TRACK_HEIGHT,
            borderRadius: TRACK_HEIGHT / 2,
            backgroundColor: currentTrackColor,
            padding: HORIZONTAL_PADDING,
          },
        ]}
      >
        <Animated.View
          style={{
            transform: [{ translateX }],
            width: THUMB_SIZE,
            height: THUMB_SIZE,
          }}
        >
          <View
            style={[
              styles.thumb,
              {
                width: THUMB_SIZE,
                height: THUMB_SIZE,
                borderRadius: THUMB_SIZE / 2,
                backgroundColor: currentThumbColor,
                alignItems: 'center',
                justifyContent: 'center',
              },
            ]}
          >
            {thumbContent ? (
              // Provide a simple props object so the render prop can size/color its content
              thumbContent({ checked: value, iconSize: ICON_SIZE, iconColor: value ? '#4CAF50' : '#757575' })
            ) : (
              <Text style={[styles.thumbIcon, { fontSize: ICON_SIZE, color: value ? '#4CAF50' : '#757575' }]}>
                {value ? '✓' : '✗'}
              </Text>
            )}
          </View>
        </Animated.View>
      </View>
    </Pressable>
  );
}

