// Allow using require dynamically without TypeScript error
declare const require: (moduleName: string) => any;

// Minimal Bugsnag shape used in this example — no external types required
type BugsnagType = {
  start?: (opts?: { apiKey?: string }) => void;
  setUser?: (id?: string | null, email?: string | null, name?: string | null) => void;
  leaveBreadcrumb?: (msg: string) => void;
  notify?: (err: Error, opts?: any) => void;
};

// Try to require @bugsnag/react-native at runtime — fall back to null if not installed
const Bugsnag: BugsnagType | null = (() => {
  try {
    const mod = require('@bugsnag/react-native');
    // CommonJS or ES default export handling
    return (mod && (mod.default ?? mod)) as BugsnagType;
  } catch (e) {
    return null;
  }
})();

export default function App(): JSX.Element {
  useEffect(() => {
    if (Bugsnag?.start) {
      // Replace with your real API key (do not commit secrets to source control)
      Bugsnag.start({ apiKey: 'REPLACE_WITH_YOUR_BUGSNAG_API_KEY' });
      Bugsnag.setUser?.('123', 'user@example.com', 'Jane Doe');
      Bugsnag.leaveBreadcrumb?.('App started');
    } else {
      // Informative fallback for development when the package isn't installed
      // This keeps the app runnable in Expo without requiring @bugsnag/react-native
      // and preserves the original intent of integrating Bugsnag when available.
      // eslint-disable-next-line no-console
      console.warn(
        "Bugsnag not available. To enable error monitoring, install '@bugsnag/react-native' and provide an API key."
      );
    }
  }, []);

  const triggerTestError = () => {
    const err = new Error('Test error for Bugsnag');
    if (Bugsnag?.notify) {
      Bugsnag.notify(err);
    } else {
      // Throwing an error lets any global error handler catch it during development.
      // Keep this behavior so the example mirrors a real crash if Bugsnag isn't present.
      throw err;
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Bugsnag Integration Example</Text>
      <Text style={styles.subtitle}>
        {Bugsnag ? 'Bugsnag is available and initialized.' : 'Bugsnag not installed (fallback mode).'}
      </Text>
      <View style={styles.button}>
        <Button title="Trigger Error" onPress={triggerTestError} />
      </View>
    </View>
  );
}

