import React, { useEffect, useState } from 'react';
import { View, Text, Button, Platform, StyleSheet } from 'react-native';
import { Barometer, BarometerMeasurement } from 'expo-sensors';

export default function App(): JSX.Element {
  const [data, setData] = useState<{ pressure: number; relativeAltitude: number }>({ pressure: 0, relativeAltitude: 0 });
  const [subscription, setSubscription] = useState<{ remove: () => void } | null>(null);

  const subscribe = () => {
    // Wrap the state updater so the listener signature matches Barometer's listener type
    const sub = Barometer.addListener((measurement: BarometerMeasurement) => {
      setData({
        pressure: measurement.pressure,
        // relativeAltitude is only available on iOS; guard with ?? 0
        relativeAltitude: measurement.relativeAltitude ?? 0,
      });
    });
    setSubscription(sub);
  };

  const unsubscribe = () => {
    if (subscription) {
      subscription.remove();
      setSubscription(null);
    }
  };

  useEffect(() => {
    // Clean up on unmount
    return () => unsubscribe();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const toggleListener = () => (subscription ? unsubscribe() : subscribe());

  return (
    <View style={styles.wrapper}>
      <Text style={styles.label}>Barometer: Listener {subscription ? 'ACTIVE' : 'INACTIVE'}</Text>
      <Text style={styles.label}>Pressure: {data.pressure} hPa</Text>
      <Text style={styles.label}>
        Relative Altitude: {Platform.OS === 'ios' ? `${data.relativeAltitude} m` : 'Only available on iOS'}
      </Text>
      <View style={styles.button}>
        <Button title="Toggle listener" onPress={toggleListener} />
      </View>
    </View>
  );
}

