type Option = { label: string; value: string };

type Colors = {
  activeContainerColor?: string;
  activeContentColor?: string;
  inactiveContainerColor?: string;
  inactiveContentColor?: string;
};

function SegmentedButtonRow({
  options,
  value,
  onValueChange,
  colors,
}: {
  options: Option[];
  value: string;
  onValueChange: (v: string) => void;
  colors?: Colors;
}) {
  const activeContainerColor = colors?.activeContainerColor ?? '#6200EE';
  const activeContentColor = colors?.activeContentColor ?? '#FFFFFF';
  const inactiveContainerColor = colors?.inactiveContainerColor ?? '#FFFFFF';
  const inactiveContentColor = colors?.inactiveContentColor ?? '#000000';

  return (
    <View accessibilityRole="radiogroup" style={styles.rowContainer}>
      {options.map((opt, index) => {
        const selected = opt.value === value;
        return (
          <Pressable
            key={opt.value}
            onPress={(e: GestureResponderEvent) => onValueChange(opt.value)}
            accessibilityRole="radio"
            accessibilityState={{ selected }}
            style={({ pressed }) => [
              styles.segment,
              index === 0 && styles.leftSegment,
              index === options.length - 1 && styles.rightSegment,
              {
                backgroundColor: selected ? activeContainerColor : inactiveContainerColor,
                opacity: pressed ? 0.85 : 1,
                borderColor: '#CCC',
              },
            ]}
          >
            <Text style={[styles.segmentText, { color: selected ? activeContentColor : inactiveContentColor }]}>
              {opt.label}
            </Text>
          </Pressable>
        );
      })}
    </View>
  );
}

