// Basic example that prefers the Expo UI SwiftUI Slider when available.
// If the Slider export is missing from the package (type or runtime), a simple
// button-based fallback is rendered so the module compiles and runs.

export default function BasicSliderExample(): JSX.Element {
  const [value, setValue] = useState<number>(0.5);

  // Access exports dynamically to avoid TypeScript error if named export is missing.
  const SliderComp = (SwiftUI as any).Slider as any | undefined;
  const HostComp = (SwiftUI as any).Host as any | undefined;

  const sliderNode = (
    <View style={styles.container}>
      <Text style={styles.label}>Value: {value.toFixed(2)}</Text>
      {SliderComp ? (
        // The Slider API mirrors SwiftUI: value, onValueChange, minimumValue, maximumValue, step
        <SliderComp
          value={value}
          onValueChange={(v: number) => setValue(v)}
          minimumValue={0}
          maximumValue={1}
          step={0}
          style={styles.slider}
        />
      ) : (
        // Fallback UI when the Expo UI Slider is not available at runtime.
        <View style={styles.fallback}>
          <Text style={styles.hint}>Expo UI Slider unavailable — use the buttons to adjust:</Text>
          <View style={styles.row}>
            <Button
              title="-"
              onPress={() => setValue((v) => Math.max(0, +(v - 0.05).toFixed(2)))}
            />
            <View style={styles.spacer} />
            <Button
              title="+"
              onPress={() => setValue((v) => Math.min(1, +(v + 0.05).toFixed(2)))}
            />
          </View>
        </View>
      )}
    </View>
  );

  // If Host is available, wrap the content so it benefits from SwiftUI hosting constraints.
  if (HostComp) {
    return <HostComp style={styles.host}>{sliderNode}</HostComp>;
  }

  return sliderNode;
}

