  Keyboard,
  KeyboardEvent,
  Platform,
  KeyboardAvoidingView,
} from 'react-native';

const FormContent: FC = () => {
  const [keyboardVisible, setKeyboardVisible] = useState(false);
  const [keyboardHeight, setKeyboardHeight] = useState(0);

  useEffect(() => {
    const onShow = (e: KeyboardEvent) => {
      setKeyboardVisible(true);
      // endCoordinates may be undefined in some environments
      setKeyboardHeight(e.endCoordinates?.height ?? 0);
    };
    const onHide = () => {
      setKeyboardVisible(false);
      setKeyboardHeight(0);
    };

    const showEvent = Platform.OS === 'ios' ? 'keyboardWillShow' : 'keyboardDidShow';
    const hideEvent = Platform.OS === 'ios' ? 'keyboardWillHide' : 'keyboardDidHide';

    const showSub = Keyboard.addListener(showEvent, onShow as (e: any) => void);
    const hideSub = Keyboard.addListener(hideEvent, onHide);

    return () => {
      showSub.remove();
      hideSub.remove();
    };
  }, []);

  return (
    <KeyboardAvoidingView
      style={styles.flex}
      behavior={Platform.OS === 'ios' ? 'padding' : undefined}
      keyboardVerticalOffset={Platform.OS === 'ios' ? 0 : 0}
    >
      <ScrollView
        contentContainerStyle={styles.container}
        keyboardShouldPersistTaps="handled"
      >
        <Text style={styles.statusText}>Keyboard visible: {keyboardVisible ? 'Yes' : 'No'}</Text>

        <TextInput style={styles.textInput} placeholder="First Name" returnKeyType="next" />
        <TextInput style={styles.textInput} placeholder="Last Name" returnKeyType="next" />
        <TextInput
          style={styles.textInput}
          placeholder="Email"
          keyboardType="email-address"
          autoCapitalize="none"
          returnKeyType="done"
        />

        <View style={styles.buttonContainer}>
          <Button title="Submit" onPress={() => { /* handle submit */ }} />
        </View>

        {keyboardVisible && (
          <Text style={styles.keyboardInfo}>Keyboard height: {Math.round(keyboardHeight)}</Text>
        )}

      </ScrollView>
    </KeyboardAvoidingView>
  );
};

