import React, { useEffect, useState } from 'react';
import { Platform, Button, View, Text, Alert } from 'react-native';
import * as Notifications from 'expo-notifications';
import * as Device from 'expo-device';
import Constants from 'expo-constants';

async function registerForPushNotificationsAsync(): Promise<string | undefined> {
  let token;
  if (Platform.OS === 'android') {
    await Notifications.setNotificationChannelAsync('myNotificationChannel', {
      name: 'A channel is needed for the permissions prompt to appear',
      importance: Notifications.AndroidImportance.MAX,
      vibrationPattern: [0, 250, 250, 250],
      lightColor: '#FF231F7C',
    });
  }
  if (Device.isDevice) {
    const { status: existingStatus } = await Notifications.getPermissionsAsync();
    let finalStatus = existingStatus;
    if (existingStatus !== 'granted') {
      const { status } = await Notifications.requestPermissionsAsync();
      finalStatus = status;
    }
    if (finalStatus !== 'granted') {
      Alert.alert('Failed to get push token for push notification!');
      return;
    }
    try {
      const projectId =
        Constants?.expoConfig?.extra?.eas?.projectId ?? Constants?.easConfig?.projectId;
      if (!projectId) {
        throw new Error('Project ID not found');
      }
      token = (await Notifications.getExpoPushTokenAsync({ projectId })).data;
    } catch (e) {
      Alert.alert('Error getting Expo push token', String(e));
      return;
    }
  } else {
    Alert.alert('Must use physical device for Push Notifications');
  }
  return token;
}

export default function PushTokenExample() {
  const [expoPushToken, setExpoPushToken] = useState<string | undefined>();

  const handleRegister = async () => {
    const token = await registerForPushNotificationsAsync();
    setExpoPushToken(token);
  };

  return (
    <View style={{ flex: 1, alignItems: 'center', justifyContent: 'center' }}>
      <Button title="Register for Push Notifications" onPress={handleRegister} />
      {expoPushToken ? (
        <Text selectable style={{ marginTop: 20 }}>
          Expo Push Token: {expoPushToken}
        </Text>
      ) : null}
    </View>
  );
}

