import React from 'react';
import { Alert, Button, Platform, StyleSheet, View } from 'react-native';
import * as Calendar from 'expo-calendar';

async function getDefaultCalendarSource(): Promise<any | null> {
  try {
    const defaultCalendar: any = await Calendar.getDefaultCalendarAsync();
    // Some platforms return an object with a `source` property, others may return the calendar itself.
    if (defaultCalendar && typeof defaultCalendar === 'object') {
      return defaultCalendar.source ?? defaultCalendar;
    }
    return null;
  } catch (error) {
    console.warn('Failed to get default calendar source:', error);
    return null;
  }
}

export async function createCalendar(): Promise<void> {
  // Ensure permissions are granted first
  const { status } = await Calendar.requestCalendarPermissionsAsync();
  if (status !== 'granted') {
    Alert.alert('Permission required', 'Calendar permission is required to create calendars.');
    return;
  }

  const isIos = Platform.OS === 'ios';
  const defaultCalendarSource = isIos ? await getDefaultCalendarSource() : null;

  // Build the payload carefully so TypeScript doesn't complain about missing `id`.
  const baseCalendar: any = {
    title: 'Expo Calendar',
    color: 'blue',
    entityType: Calendar.EntityTypes.EVENT,
    name: 'expo-internal-calendar',
    ownerAccount: 'personal',
    accessLevel: Calendar.CalendarAccessLevel.OWNER,
  };

  if (defaultCalendarSource && typeof defaultCalendarSource === 'object') {
    // Only include sourceId/source when available and when they have the expected properties
    if ('id' in defaultCalendarSource && defaultCalendarSource.id) {
      baseCalendar.sourceId = defaultCalendarSource.id;
    }
    baseCalendar.source = defaultCalendarSource;
  } else if (!isIos) {
    // On Android, provide a local account source object when no default source is available
    baseCalendar.source = { isLocalAccount: true, name: 'Expo Calendar' };
  }

  try {
    const newCalendarID = await Calendar.createCalendarAsync(baseCalendar);
    Alert.alert('Calendar Created', `New calendar ID: ${newCalendarID}`);
    console.log('Created calendar with ID:', newCalendarID);
  } catch (error: any) {
    console.error('Failed to create calendar:', error);
    Alert.alert('Error', error?.message ?? 'Failed to create calendar');
  }
}

export default function App(): JSX.Element {
  return (
    <View style={styles.container}>
      <Button title="Create Calendar" onPress={() => void createCalendar()} />
    </View>
  );
}

