// A small, local DockedSearchBar implementation that mimics the slot API
// shown in the Jetpack Compose docs. This avoids importing a missing
// export while preserving the intended usage.

type DockedSearchBarProps = {
  value: string;
  onChangeText: (text: string) => void;
  placeholder?: string;
  style?: ViewStyle;
  inputProps?: TextInputProps;
  children?: ReactNode;
};

const Placeholder: FC<{ children?: ReactNode }> = ({ children }) => {
  return <>{children}</>;
};
Placeholder.displayName = 'DockedSearchBar.Placeholder';

const LeadingIcon: FC<{ children?: ReactNode }> = ({ children }) => {
  return <>{children}</>;
};
LeadingIcon.displayName = 'DockedSearchBar.LeadingIcon';

type DockedSearchBarComponent = FC<DockedSearchBarProps> & {
  Placeholder: typeof Placeholder;
  LeadingIcon: typeof LeadingIcon;
};

const DockedSearchBar: DockedSearchBarComponent = ({
  value,
  onChangeText,
  placeholder,
  style,
  inputProps,
  children,
}) => {
  // Extract slot children if provided
  const childArray = React.Children.toArray(children) as any[];

  const placeholderNode = childArray.find(
    (c) => c?.type?.displayName === Placeholder.displayName
  );
  const leadingIconNode = childArray.find(
    (c) => c?.type?.displayName === LeadingIcon.displayName
  );

  // If the Placeholder slot was passed a simple string child, use it as placeholder text
  const placeholderTextFromSlot =
    placeholderNode && typeof placeholderNode.props.children === 'string'
      ? placeholderNode.props.children
      : undefined;

  const resolvedPlaceholder = placeholder || placeholderTextFromSlot || 'Search';

  return (
    <View style={[styles.container, style]}>
      {leadingIconNode ? (
        <View style={styles.leadingIcon}>{leadingIconNode.props.children}</View>
      ) : null}

      <TextInput
        value={value}
        onChangeText={onChangeText}
        placeholder={resolvedPlaceholder}
        style={styles.input}
        accessibilityLabel="Docked search input"
        {...inputProps}
      />

      {value.length > 0 ? (
        <TouchableOpacity onPress={() => onChangeText('')} style={styles.clearButton}>
          <Text style={styles.clearText}>✕</Text>
        </TouchableOpacity>
      ) : null}
    </View>
  );
};

DockedSearchBar.Placeholder = Placeholder;
DockedSearchBar.LeadingIcon = LeadingIcon;

