import React from 'react';
import { View, Text, StyleSheet, ViewStyle } from 'react-native';

type GaugeProps = {
  value: number;
  minimumValue?: number;
  maximumValue?: number;
  size?: number;
  strokeColor?: string;
  backgroundColor?: string;
  currentValueLabel?: React.ReactNode;
  minimumValueLabel?: React.ReactNode;
  maximumValueLabel?: React.ReactNode;
  children?: React.ReactNode; // custom center label
};

function clamp(n: number, min = 0, max = 1) {
  return Math.max(min, Math.min(max, n));
}

// A lightweight, dependency-free circular gauge (visual approximation).
// Uses the classic two-half technique to simulate a circular progress arc.
export const Gauge: React.FC<GaugeProps> = ({
  value,
  minimumValue = 0,
  maximumValue = 100,
  size = 160,
  strokeColor = '#007aff',
  backgroundColor = '#e6e6e6',
  currentValueLabel,
  minimumValueLabel,
  maximumValueLabel,
  children,
}) => {
  const clamped = clamp((value - minimumValue) / (maximumValue - minimumValue), 0, 1);
  const percent = clamped * 100;

  // For CSS-like two-half technique: right rotates 0..180 for 0..50%, left rotates 0..180 for 50..100%
  const rightRotation = percent <= 50 ? (percent / 50) * 180 : 180;
  const leftRotation = percent <= 50 ? 0 : ((percent - 50) / 50) * 180;

  const halfSize = size / 2;
  const circleStyle: ViewStyle = { width: size, height: size, borderRadius: size / 2 };

  return (
    <View style={{ alignItems: 'center' }}>
      <View style={[styles.circleContainer, circleStyle]}>
        {/* Base circle (background ring) */}
        <View
          style={[
            styles.baseCircle,
            { width: size, height: size, borderRadius: size / 2, backgroundColor },
          ]}
        />

        {/* Right half (0..180deg) */}
        <View style={[styles.halfContainer, { width: halfSize, height: size, left: halfSize }]}> 
          <View
            style={[
              styles.halfCircle,
              {
                width: size,
                height: size,
                borderRadius: size / 2,
                backgroundColor: strokeColor,
                transform: [{ translateX: -halfSize }, { rotate: `${rightRotation}deg` }],
              },
            ]}
          />
        </View>

        {/* Left half (0..180deg) */}
        <View style={[styles.halfContainer, { width: halfSize, height: size, left: 0 }]}> 
          <View
            style={[
              styles.halfCircle,
              {
                width: size,
                height: size,
                borderRadius: size / 2,
                backgroundColor: strokeColor,
                transform: [{ translateX: 0 }, { rotate: `${leftRotation}deg` }],
              },
            ]}
          />
        </View>

        {/* Inner cutout to create ring effect */}
        <View
          style={[
            styles.innerCutout,
            {
              width: size * 0.72,
              height: size * 0.72,
              borderRadius: (size * 0.72) / 2,
              top: size * 0.14,
              left: size * 0.14,
              backgroundColor: 'white',
            },
          ]}
        />

        {/* Center label/content */}
        <View style={[styles.centerContent, { width: size * 0.6, height: size * 0.6 }]}> 
          {children ? (
            children
          ) : (
            <Text style={styles.defaultLabel}>{Math.round(percent)}%</Text>
          )}
        </View>
      </View>

      {/* Value labels row */}
      <View style={styles.valueRow}>
        <View style={styles.valueCell}>{minimumValueLabel ?? <Text style={styles.valueText}>{minimumValue}</Text>}</View>
        <View style={styles.valueCell}>{currentValueLabel ?? <Text style={styles.valueText}>{Math.round(value)}</Text>}</View>
        <View style={styles.valueCell}>{maximumValueLabel ?? <Text style={styles.valueText}>{maximumValue}</Text>}</View>
      </View>
    </View>
  );
};

export default function CustomCircularGaugeDemo(): JSX.Element {
  return (
    <View style={styles.demoRoot}>
      <Gauge
        value={75}
        minimumValue={0}
        maximumValue={100}
        currentValueLabel={<Text style={styles.currentValueLabel}>75%</Text>}
        minimumValueLabel={<Text style={styles.smallLabel}>0</Text>}
        maximumValueLabel={<Text style={styles.smallLabel}>100</Text>}
