import { Switch as ExpoSwitch } from '@expo/ui/jetpack-compose';
import { MaterialIcons } from '@expo/vector-icons';

// Cast the Expo Switch to any so example compiles cleanly with TypeScript
const Switch: any = ExpoSwitch;

export default function CustomSwitchExample(): JSX.Element {
  const [checked, setChecked] = useState(false);

  // Visual sizes chosen to match typical Material switch proportions
  const SWITCH_WIDTH = 52;
  const SWITCH_HEIGHT = 32;
  const THUMB_SIZE = 20;
  const ICON_SIZE = 14;

  // Thumb background color (keeps visual consistency with the Switch thumbColor)
  const thumbBackground = checked ? '#fff176' : '#ffffff';

  // Position the custom thumb icon left or right depending on checked
  const thumbLeft = checked ? SWITCH_WIDTH - THUMB_SIZE - 2 : 2;

  return (
    <View style={styles.container}>
      <Pressable
        onPress={() => setChecked((prev) => !prev)}
        style={[styles.switchWrapper, { width: SWITCH_WIDTH, height: SWITCH_HEIGHT }]}
        accessibilityRole="switch"
        accessibilityState={{ checked }}
        accessibilityLabel="Custom switch with icon thumb"
      >
        {/* Underlying Expo Switch provides native track and accessibility. Casted as any above to avoid type errors. */}
        <Switch
          checked={checked}
          onCheckedChange={setChecked}
          // custom track and thumb colors
          trackColor={{ true: '#4caf50', false: '#bdbdbd' }}
          thumbColor={thumbBackground}
          style={{ width: SWITCH_WIDTH, height: SWITCH_HEIGHT }}
        />

        {/* Overlay a small circle (thumb) with an icon to simulate Switch.ThumbContent.
            This keeps the example working even if the TS types don't expose Switch.ThumbContent. */}
        <View
          pointerEvents="none"
          style={[
            styles.thumbOverlay,
            {
              width: THUMB_SIZE,
              height: THUMB_SIZE,
              left: thumbLeft,
              top: (SWITCH_HEIGHT - THUMB_SIZE) / 2,
              backgroundColor: thumbBackground,
            },
          ]}
        >
          <MaterialIcons
            name={checked ? 'check' : 'close'}
            size={ICON_SIZE}
            color={checked ? '#388e3c' : '#d32f2f'}
          />
        </View>
      </Pressable>
    </View>
  );
}

