import React from 'react';
import { View, Text, PanResponder, StyleSheet } from 'react-native';
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  useHandler,
} from 'react-native-reanimated';

type HandlerContext = {
  moveCount?: number;
  lastRelease?: number;
  // add other shared fields here
};

export default function SharedContextExample(): JSX.Element {
  const translateX = useSharedValue(0);
  const translateY = useSharedValue(0);

  // Shared UI-visible counters (kept in shared values so worklets can update them)
  const moveCountShared = useSharedValue(0);
  const lastReleaseShared = useSharedValue(0);

  const panResponder = React.useRef(
    PanResponder.create({
      onStartShouldSetPanResponder: () => true,
      onPanResponderMove: (_e, gestureState) => {
        translateX.value = gestureState.dx;
        translateY.value = gestureState.dy;
      },
      onPanResponderRelease: () => {
        // animate back to origin (simple spring could be used, but reset directly here)
        translateX.value = 0;
        translateY.value = 0;
      },
    })
  ).current;

  // Handlers object: keys correspond to native event names and values are worklets
  // Cast to any to avoid strict typing issues with the library's types in TS configs
  const handlers = React.useMemo(() => ({
    onMove: (event: any, context: HandlerContext) => {
      'worklet';
      // ensure context fields have sensible defaults and persist between calls
      if (context.moveCount == null) context.moveCount = 0;
      context.moveCount += 1; // safe because context is typed

      // reflect to shared value so JS/UI can read/render via shared values
      moveCountShared.value = context.moveCount;

      // optionally inspect event payload if available
      // e.g. event.x or event.translationX depending on event type
    },

    onRelease: (_event: any, context: HandlerContext) => {
      'worklet';
      context.lastRelease = Date.now();
      lastReleaseShared.value = context.lastRelease;
    },
  }) as any, []);

  // Register handlers with useHandler. Passing an empty deps array keeps worklets stable.
  // useHandler attaches these worklets to animated/native events and provides a shared context.
  useHandler(handlers, []);

  const animatedStyle = useAnimatedStyle(() => {
    return {
      transform: [
        { translateX: translateX.value },
        { translateY: translateY.value },
      ],
    } as any;
  });

  const counterStyle = useAnimatedStyle(() => ({
    // No animation here; expose shared values to the UI via style-driven text opacity/scale if desired
    opacity: 1,
  }));

  return (
    <View style={styles.container}>
      <Animated.View
        {...(panResponder.panHandlers as any)}
        style={[styles.box as any, animatedStyle as any]}
      >
        <Text style={styles.boxText}>Drag me</Text>
      </Animated.View>

      <View style={styles.infoRow}>
        <Animated.View style={[styles.infoCard, counterStyle as any]}>
          <Text style={styles.infoTitle}>Moves</Text>
          <Text style={styles.infoValue}>{moveCountShared.value}</Text>
        </Animated.View>

        <Animated.View style={[styles.infoCard, counterStyle as any]}>
          <Text style={styles.infoTitle}>Last release</Text>
          <Text style={styles.infoValue}>
            {lastReleaseShared.value ? new Date(lastReleaseShared.value).toLocaleTimeString() : '—'}
          </Text>
        </Animated.View>
      </View>

      <Text style={styles.note}>
        Handlers are registered with useHandler; the worklets share a persistent context object
        between calls (see moveCount/lastRelease). Worklets update shared values so the JS/UI
        thread can reflect changes.
      </Text>
    </View>
  );
}

