import React, { useRef, useState, useEffect } from 'react';
import {
  View,
  Text,
  StyleSheet,
  PanResponder,
  Animated,
  LayoutChangeEvent,
  GestureResponderEvent,
  NativeTouchEvent,
} from 'react-native';

// A compact, self-contained Slider-like component implemented in pure React Native.
// API mirrors the SwiftUI/Expo Slider shape used in docs: value, onValueChange, minimumValue, maximumValue.
// Exported example demonstrates usage and compiles in a TypeScript + Expo project.

type Props = {
  value: number;
  onValueChange: (v: number) => void;
  minimumValue?: number;
  maximumValue?: number;
};

function clamp(v: number, a: number, b: number) {
  return Math.max(a, Math.min(b, v));
}

function SliderNative({ value, onValueChange, minimumValue = 0, maximumValue = 1 }: Props) {
  const trackWidthRef = useRef<number>(0);
  const thumbSize = 24;
  const paddingHorizontal = thumbSize / 2;
  const maxTrackAvail = useRef<number>(0);
  const animatedX = useRef(new Animated.Value(0)).current;
  const lastGestureValue = useRef<number>(0);

  useEffect(() => {
    // Update animated thumb when external value changes
    const progress = (clamp(value, minimumValue, maximumValue) - minimumValue) / (maximumValue - minimumValue || 1);
    const x = progress * maxTrackAvail.current;
    Animated.timing(animatedX, {
      toValue: x,
      duration: 100,
      useNativeDriver: true,
    }).start();
  }, [value, minimumValue, maximumValue, animatedX]);

  const updateFromX = (x: number) => {
    const clamped = clamp(x, 0, maxTrackAvail.current);
    const progress = maxTrackAvail.current > 0 ? clamped / maxTrackAvail.current : 0;
    const newValue = minimumValue + progress * (maximumValue - minimumValue);
    onValueChange(newValue);
  };

  const pan = useRef(
    PanResponder.create({
      onStartShouldSetPanResponder: () => true,
      onMoveShouldSetPanResponder: () => true,
      onPanResponderGrant: () => {
        animatedX.stopAnimation((current) => {
          lastGestureValue.current = current || 0;
        });
      },
      onPanResponderMove: (_evt, gestureState) => {
        const x = lastGestureValue.current + gestureState.dx;
        updateFromX(x);
      },
      onPanResponderRelease: () => {
        // sync animated value to final logical value
        const progress = (clamp(value, minimumValue, maximumValue) - minimumValue) / (maximumValue - minimumValue || 1);
        const x = progress * maxTrackAvail.current;
        Animated.spring(animatedX, { toValue: x, useNativeDriver: true }).start();
      },
    })
  ).current;

  const onTrackLayout = (e: LayoutChangeEvent) => {
    const width = e.nativeEvent.layout.width;
    trackWidthRef.current = width;
    maxTrackAvail.current = Math.max(0, width - thumbSize);
    // position thumb for initial value
    const progress = (clamp(value, minimumValue, maximumValue) - minimumValue) / (maximumValue - minimumValue || 1);
    animatedX.setValue(progress * maxTrackAvail.current);
  };

  const onTrackPress = (e: GestureResponderEvent) => {
    const native: NativeTouchEvent = e.nativeEvent as NativeTouchEvent;
    const x = native.locationX - paddingHorizontal; // location relative to track content
    updateFromX(x);
  };

  // Thumb transform uses translateX; center the thumb vertically by negative half thumb size offset in styles
  const thumbStyle = {
    transform: [
      {
        translateX: animatedX,
      },
    ],
  } as const;

  return (
    <View style={styles.container}>
      <View style={styles.valueRow}>
        <Text style={styles.valueText}>{value.toFixed(2)}</Text>
      </View>

      <View
        style={styles.trackContainer}
        onLayout={onTrackLayout}
        onStartShouldSetResponder={() => true}
        onResponderGrant={onTrackPress}
      >
        <View style={styles.trackBackground} />
        <Animated.View
          style={[styles.filledTrack, { width: Animated.add(animatedX, thumbSize / 2) as unknown as number }]}
          pointerEvents="none"
        />
        <Animated.View
          {...pan.panHandlers}
          style={[styles.thumb, thumbStyle]}
          accessibilityRole="adjustable"
          accessibilityValue={{ min: minimumValue, max: maximumValue, now: value }}
        />
      </View>
    </View>
  );
}

