// Local DockedSearchBar implementation that matches the documented API shape
type DockedSearchBarProps = {
  value: string;
  onChangeText: (text: string) => void;
  style?: ViewStyle | ViewStyle[];
  inputStyle?: TextStyle | TextStyle[];
  children?: ReactNode;
};

const Placeholder: React.FC<{ children?: ReactNode }> = ({ children }) => {
  return <>{children}</>;
};

const LeadingIcon: React.FC<{ children?: ReactNode }> = ({ children }) => {
  return <>{children}</>;
};

const isPlaceholder = (child: any) => child?.type === Placeholder;
const isLeadingIcon = (child: any) => child?.type === LeadingIcon;

const DockedSearchBar: React.FC<DockedSearchBarProps> & {
  Placeholder: typeof Placeholder;
  LeadingIcon: typeof LeadingIcon;
} = ({ value, onChangeText, style, inputStyle, children }) => {
  const childrenArray = React.Children.toArray(children);

  const placeholderText = useMemo(() => {
    const ph = childrenArray.find(isPlaceholder) as any;
    if (!ph) return undefined;
    // If Placeholder has text children, join them
    const content = ph.props.children;
    if (typeof content === 'string') return content;
    if (Array.isArray(content)) return content.join('');
    return undefined;
  }, [childrenArray]);

  const leading = useMemo(() => {
    const lead = childrenArray.find(isLeadingIcon) as any;
    return lead?.props?.children ?? null;
  }, [childrenArray]);

  return (
    <View style={[styles.container, style]}>
      {leading ? <View style={styles.leading}>{leading}</View> : null}
      <TextInput
        value={value}
        onChangeText={onChangeText}
        placeholder={placeholderText}
        style={[styles.input, inputStyle]}
        accessibilityRole="search"
        returnKeyType="search"
      />
      {/* A simple clear button when there's text */}
      {value.length > 0 ? (
        <TouchableOpacity onPress={() => onChangeText('')} style={styles.clearButton}>
          <Text style={styles.clearText}>✕</Text>
        </TouchableOpacity>
      ) : null}
    </View>
  );
};

DockedSearchBar.Placeholder = Placeholder;
DockedSearchBar.LeadingIcon = LeadingIcon;

