// Attempt to load react-native-view-shot at runtime. If it's not installed, show a helpful error at runtime.
let captureRefFunc: ((ref: any, options?: any) => Promise<string>) | null = null;
try {
  // @ts-ignore: optional runtime require; suppress TS module-not-found during type checking
  const viewShot = require('react-native-view-shot');
  captureRefFunc = viewShot.captureRef;
} catch (e) {
  captureRefFunc = null;
}

export default function ScreenshotExample(): JSX.Element {
  const viewRef = useRef<View | null>(null);
  const [imageUri, setImageUri] = useState<string | null>(null);

  const handleCapture = async () => {
    if (!captureRefFunc) {
      Alert.alert(
        'Missing dependency',
        'react-native-view-shot is not installed. Install it to enable captureRef functionality.'
      );
      return;
    }

    if (!viewRef.current) {
      Alert.alert('No view', 'The view to capture is not available.');
      return;
    }

    try {
      const targetPixelCount = 1080; // FullHD target for the shorter side
      const pixelRatio = PixelRatio.get();
      // Convert desired physical pixels into logical pixels for the view dimensions
      const pixels = Math.round(targetPixelCount / pixelRatio);

      const uri = await captureRefFunc(viewRef.current, {
        result: 'tmpfile',
        height: pixels,
        width: pixels,
        quality: 1,
        format: 'png',
      });

      setImageUri(uri);
    } catch (err) {
      // Keep error message simple and helpful
      console.warn('captureRef failed:', err);
      Alert.alert('Capture failed', String(err));
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Capture a View to PNG</Text>

      <View ref={viewRef} style={styles.captureBox}>
        <Text style={styles.boxText}>Content to capture</Text>
      </View>

      <Button title="Capture Screenshot" onPress={handleCapture} />

      {imageUri ? (
        <Image source={{ uri: imageUri }} style={styles.image} />
      ) : (
        <Text style={styles.hint}>No image captured yet</Text>
      )}
    </View>
  );
}

