import React, { useCallback, useEffect, useRef, useState } from 'react';
import { View, Button, Text } from 'react-native';
import { Audio, AVPlaybackStatus } from 'expo-av';

const N = 20;

export default function LoopAudio20Times(): JSX.Element {
  const soundRef = useRef<Audio.Sound | null>(null);
  const loopsRef = useRef<number>(0);
  const [loops, setLoops] = useState<number>(0);
  const [isPlaying, setIsPlaying] = useState<boolean>(false);

  const onPlaybackStatusUpdate = useCallback((status: AVPlaybackStatus) => {
    // Guard: only proceed when loaded
    if (!status || !status.isLoaded) return;

    // When the playback item finishes once, increment the loop counter
    if (status.didJustFinish) {
      const next = loopsRef.current + 1;
      loopsRef.current = next;
      setLoops(next);

      // If we've reached the Nth play, stop looping and stop playback
      if (next >= N) {
        // Disable looping and stop playback
        soundRef.current?.setIsLoopingAsync(false).catch(() => {});
        soundRef.current?.stopAsync().catch(() => {});
        setIsPlaying(false);
      }
    }
  }, []);

  const play = async () => {
    try {
      // If there's an existing sound, unload/clear it first
      if (soundRef.current) {
        soundRef.current.setOnPlaybackStatusUpdate(null);
        await soundRef.current.unloadAsync();
        soundRef.current = null;
      }

      // Reset counters
      loopsRef.current = 0;
      setLoops(0);

      // Replace the require path with your audio asset
      const source = require('./assets/audio.mp3');

      const { sound } = await Audio.Sound.createAsync(source, { shouldPlay: true, isLooping: true });
      soundRef.current = sound;

      // Start receiving status updates
      sound.setOnPlaybackStatusUpdate(onPlaybackStatusUpdate);

      setIsPlaying(true);
    } catch (e) {
      console.warn('Failed to play sound:', e);
    }
  };

  const stop = async () => {
    try {
      if (soundRef.current) {
        soundRef.current.setOnPlaybackStatusUpdate(null);
        await soundRef.current.stopAsync();
        await soundRef.current.unloadAsync();
        soundRef.current = null;
      }
    } catch (e) {
      console.warn('Failed to stop/unload sound:', e);
    } finally {
      loopsRef.current = 0;
      setLoops(0);
      setIsPlaying(false);
    }
  };

  // Ensure cleanup on unmount
  useEffect(() => {
    return () => {
      if (soundRef.current) {
        soundRef.current.setOnPlaybackStatusUpdate(null);
        // best-effort unload
        soundRef.current.unloadAsync().catch(() => {});
        soundRef.current = null;
      }
    };
  }, []);

  return (
    <View style={{ padding: 20 }}>
      <Button title={isPlaying ? 'Stop' : `Play ${N} Loops`} onPress={isPlaying ? stop : play} />
      <Text style={{ marginTop: 12 }}>Loops completed: {loops} / {N}</Text>
      <Text style={{ marginTop: 8 }}>Status: {isPlaying ? 'Playing' : 'Stopped'}</Text>
    </View>
  );
}

import { ExpoConfig, ConfigContext } from '@expo/config';

export default function ({ config }: ConfigContext): ExpoConfig {
  const brownfieldTargets = [
    {
      ios: {
        targetName: 'MyBrownfieldTarget',
        bundleIdentifier: 'com.example.mybrownfield', // unique bundle identifier for brownfield target
        buildReactNativeFromSource: true, // building RN from source increases build time
      },
      android: {
        group: 'com.example', // Maven group ID
        libraryName: 'brownfield', // Android library module name
        package: 'com.example.brownfield', // Java/Kotlin package name
        version: '1.0.0',
      },
    },
  ];

  const extra = {
    // preserve any existing extras while adding the brownfield array
    ...((config.extra as Record<string, any>) || {}),
    brownfield: brownfieldTargets,
  };

  // Cast to ExpoConfig to satisfy the type system while preserving other fields from the incoming config.
  return ({
    ...(config as ExpoConfig),
    extra,
  } as ExpoConfig);
}

