import React, { useState, useEffect } from 'react';
import { View, Text, Button, Platform, StyleSheet } from 'react-native';
import { LightSensor } from 'expo-sensors';

export default function App() {
  const [{ illuminance }, setData] = useState({ illuminance: 0 });
  const [subscription, setSubscription] = useState<null | { remove: () => void }>(null);

  const subscribe = () => {
    setSubscription(
      LightSensor.addListener(sensorData => {
        setData(sensorData);
      })
    );
  };

  const unsubscribe = () => {
    subscription && subscription.remove();
    setSubscription(null);
  };

  const toggle = () => {
    if (subscription) {
      unsubscribe();
    } else {
      subscribe();
    }
  };

  useEffect(() => {
    subscribe();
    return () => unsubscribe();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  return (
    <View style={styles.sensor}>
      <Text style={{ fontSize: 18, marginBottom: 10 }}>Light Sensor:</Text>
      <Text style={{ fontSize: 16 }}>
        Illuminance: {Platform.OS === 'android' ? `${illuminance} lx` : 'Only available on Android'}
      </Text>
      <View style={styles.buttonContainer}>
        <View style={styles.button}>
          <Button title="Toggle" onPress={toggle} />
        </View>
      </View>
    </View>
  );
}

