import React, { useCallback, useState } from 'react';
import { View, Text, Button, StyleSheet } from 'react-native';
import * as Network from 'expo-network';

type NetworkError = { code?: string; message?: string };

export default function MacAddressExample(): JSX.Element {
  const [mac, setMac] = useState<string | null>(null);
  const [ip, setIp] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const fetchMacOrFallback = useCallback(async () => {
    setError(null);
    setMac(null);
    setIp(null);

    try {
      // Some SDK/type bundles may not expose getMacAddressAsync in the TS types
      // but the runtime implementation can still exist. Use an any-cast to call it
      // when available and fall back to getIpAddressAsync when not.
      const runtimeGetMac = (Network as any).getMacAddressAsync;

      if (typeof runtimeGetMac === 'function') {
        const address: string = await runtimeGetMac();
        setMac(address);
        return;
      }

      // Fallback: getIpAddressAsync is present in the official types
      if (typeof Network.getIpAddressAsync === 'function') {
        const ipAddress = await Network.getIpAddressAsync();
        setIp(ipAddress);
        return;
      }

      setError('No suitable Network API available in this runtime.');
    } catch (err: unknown) {
      const e = err as NetworkError;

      // Handle documented Expo Network error codes for getMacAddressAsync
      if (e?.code === 'ERR_NETWORK_SOCKET_EXCEPTION') {
        setError('Socket error occurred while fetching MAC address.');
      } else if (e?.code === 'ERR_NETWORK_INVALID_PERMISSION_INTERNET') {
        setError('Invalid permissions: ACCESS_WIFI_STATE required on Android.');
      } else if (e?.code === 'ERR_NETWORK_NO_ACCESS_NETWORKINFO') {
        setError('Unable to access network information on this device.');
      } else {
        // Generic fallback message
        setError(e?.message ?? String(err));
      }
    }
  }, []);

  return (
    <View style={styles.container}>
      <Button title="Get MAC / IP Address" onPress={fetchMacOrFallback} />
      {mac ? <Text style={styles.text}>MAC Address: {mac}</Text> : null}
      {ip ? <Text style={styles.text}>IP Address (fallback): {ip}</Text> : null}
      {error ? <Text style={[styles.text, styles.error]}>{error}</Text> : null}
    </View>
  );
}

