import React, { useCallback } from 'react';
import { Alert, Button, StyleSheet, View } from 'react-native';
import * as Location from 'expo-location';
import * as TaskManager from 'expo-task-manager';

const LOCATION_TASK_NAME = 'background-location-task';

// Define the background task. Use a type-cast to satisfy TypeScript's TaskManager typing.
// The runtime will receive an object with `data.locations` when Location.startLocationUpdatesAsync runs.
TaskManager.defineTask(
  LOCATION_TASK_NAME,
  ((taskData: any) => {
    const { error, data } = taskData;
    if (error) {
      // Error occurred - check `error.message` for more details.
      console.error('Background location task error:', error);
      return;
    }

    // `data` may contain a `locations` array when new locations are delivered.
    if (data && Array.isArray((data as any).locations)) {
      const locations = (data as any).locations as Location.LocationObject[];
      // Do something with the locations captured in the background
      console.log('Background locations received:', locations);
    }
  }) as TaskManager.TaskManagerTaskExecutor<any>
);

const PermissionsButton: React.FC = () => {
  const handlePress = useCallback(async () => {
    try {
      // Request foreground permission first.
      const { status: foregroundStatus } = await Location.requestForegroundPermissionsAsync();
      if (foregroundStatus !== 'granted') {
        Alert.alert('Permission required', 'Foreground location permission is needed.');
        return;
      }

      // Then request background permission.
      const { status: backgroundStatus } = await Location.requestBackgroundPermissionsAsync();
      if (backgroundStatus !== 'granted') {
        Alert.alert('Permission required', 'Background location permission is needed.');
        return;
      }

      // Start background location updates. Options may be adjusted for your needs.
      await Location.startLocationUpdatesAsync(LOCATION_TASK_NAME, {
        accuracy: Location.Accuracy.Balanced,
        // iOS-specific indicator flag; safe to include on both platforms.
        showsBackgroundLocationIndicator: true,
        // Only deliver updates when the device moves this many meters.
        distanceInterval: 10,
        // Do not pause updates automatically.
        pausesUpdatesAutomatically: false,
      });

      Alert.alert('Success', 'Background location updates started.');
    } catch (err) {
      console.error('Failed to start background location updates:', err);
      Alert.alert('Error', 'Could not start background location updates.');
    }
  }, []);

  return (
    <View style={styles.container}>
      <Button title="Enable Background Location" onPress={handlePress} />
    </View>
  );
};

