// This component explains the correct approach and demonstrates a normal fetch.
// Key points:
// - React Native's fetch implementation does not provide a per-request proxy agent option.
// - On macOS (Simulator), set the system proxy in System Preferences > Network (HTTP/HTTPS -> 127.0.0.1:8888)
//   and configure your proxy tool (e.g., Charles) as documented.
// - Alternative: route requests through a server-side proxy you control.

export default function ProxyFetchExample(): JSX.Element {
  const [output, setOutput] = useState<string>('');
  const [loading, setLoading] = useState<boolean>(false);

  const runFetch = useCallback(async () => {
    setLoading(true);
    setOutput('');
    try {
      const res = await fetch('https://httpbin.org/get');
      const json = await res.json();
      setOutput(JSON.stringify(json, null, 2));
    } catch (err) {
      setOutput(String(err));
    } finally {
      setLoading(false);
    }
  }, []);

  return (
    <ScrollView contentContainerStyle={styles.container}>
      <Text style={styles.title}>Proxy guidance for React Native (macOS / Simulator)</Text>

      <Text style={styles.sectionTitle}>Why you can't set a per-request proxy</Text>
      <Text style={styles.paragraph}>
        The built-in fetch in React Native does not expose a cross-platform option to attach an HTTP/HTTPS
        proxy agent per request. Attempts to import node-style proxy agents in a bare React Native or Expo
        environment will fail because those native/node modules are not available in the runtime.
      </Text>

      <Text style={styles.sectionTitle}>Recommended approaches</Text>
      <View style={styles.listItem}>
        <Text style={styles.bullet}>•</Text>
        <Text style={styles.listText}>
          Configure macOS network proxy (System Preferences → Network → Advanced → Proxies): set Web Proxy
          and Secure Web Proxy to 127.0.0.1:8888 and use a local proxy app (e.g., Charles) as documented.
        </Text>
      </View>
      <View style={styles.listItem}>
        <Text style={styles.bullet}>•</Text>
        <Text style={styles.listText}>
          Route traffic through a remote/server-side proxy you control and have the app call that endpoint.
        </Text>
      </View>

      <Text style={styles.sectionTitle}>Quick demo: normal fetch (no agent)</Text>
      <Button title={loading ? 'Fetching…' : 'Fetch https://httpbin.org/get'} onPress={runFetch} disabled={loading} />

      <Text style={styles.outputLabel}>Result / Error</Text>
      <Text style={styles.output}>{output || '(no result yet)'}</Text>

      <Text style={styles.note}>
        Note: If using Charles or another proxy tool, do NOT let the tool auto-manage macOS network settings when
        prompted; follow the manual configuration steps and ensure the Simulator uses the system proxy.
      </Text>
    </ScrollView>
  );
}

