import React from 'react';
import { StyleSheet, View, Alert, Platform, Text, Pressable } from 'react-native';

// Dynamically require the Expo Apple Authentication module only on iOS.
// This avoids TypeScript/packager errors on platforms where the native module
// is not installed (e.g., Android / web) while preserving correct runtime
// behavior on iOS. Typing is kept as `any` to prevent missing-declaration errors.
let AppleAuthentication: any = null;
if (Platform.OS === 'ios') {
  try {
    // Use require so TypeScript doesn't try to resolve types at compile time
    // for non-iOS targets that may not include the native module.
    // eslint-disable-next-line @typescript-eslint/no-var-requires
    AppleAuthentication = require('expo-apple-authentication');
  } catch (e) {
    AppleAuthentication = null;
  }
}

export default function App(): JSX.Element {
  const handleAppleSignIn = async () => {
    if (!AppleAuthentication) {
      Alert.alert('Not available', 'Apple Sign In is only available on iOS with the native module installed.');
      return;
    }

    try {
      const credential = await AppleAuthentication.signInAsync({
        requestedScopes: [
          AppleAuthentication.AppleAuthenticationScope.FULL_NAME,
          AppleAuthentication.AppleAuthenticationScope.EMAIL,
        ],
      });

      // Successful sign-in: handle credential as needed in your app
      Alert.alert('Signed in', JSON.stringify(credential));
    } catch (error: any) {
      // ERR_REQUEST_CANCELED is thrown when the user cancels the flow
      if (error?.code === 'ERR_REQUEST_CANCELED') {
        Alert.alert('Canceled', 'User canceled Apple sign-in.');
      } else {
        Alert.alert('Sign-in error', (error && error.message) || String(error));
      }
    }
  };

  return (
    <View style={styles.container}>
      {AppleAuthentication ? (
        <AppleAuthentication.AppleAuthenticationButton
          buttonType={AppleAuthentication.AppleAuthenticationButtonType.SIGN_IN}
          buttonStyle={AppleAuthentication.AppleAuthenticationButtonStyle.BLACK}
          cornerRadius={6}
          style={styles.appleButton}
          onPress={handleAppleSignIn}
        />
      ) : (
        <Pressable style={styles.fallbackButton} onPress={handleAppleSignIn} accessibilityRole="button">
          <Text style={styles.fallbackText}>Sign in with Apple (iOS only)</Text>
        </Pressable>
      )}
    </View>
  );
}

