import React, { useReducer, useEffect, useCallback, useState } from 'react';
import { View, TextInput, Button, Text, Platform, StyleSheet } from 'react-native';
import * as SecureStore from 'expo-secure-store';

// Small generic hook types
type UseStateHook<T> = [[boolean, T | null], (value: T | null) => void];

function useAsyncState<T>(initialValue: [boolean, T | null] = [true, null]): UseStateHook<T> {
  return useReducer(
    (state: [boolean, T | null], action: T | null = null): [boolean, T | null] => [false, action],
    initialValue
  ) as UseStateHook<T>;
}

export async function setStorageItemAsync(key: string, value: string | null) {
  if (Platform.OS === 'web') {
    try {
      if (value === null) {
        localStorage.removeItem(key);
      } else {
        localStorage.setItem(key, value);
      }
    } catch (e) {
      console.error('Local storage is unavailable:', e);
    }
  } else {
    try {
      if (value == null) {
        await SecureStore.deleteItemAsync(key);
      } else {
        await SecureStore.setItemAsync(key, value);
      }
    } catch (e) {
      console.error('SecureStore error:', e);
    }
  }
}

export function useStorageState(key: string): UseStateHook<string> {
  const [state, setState] = useAsyncState<string>();

  useEffect(() => {
    if (Platform.OS === 'web') {
      try {
        if (typeof localStorage !== 'undefined') {
          setState(localStorage.getItem(key));
        } else {
          setState(null);
        }
      } catch (e) {
        console.error('Local storage is unavailable:', e);
        setState(null);
      }
    } else {
      SecureStore.getItemAsync(key)
        .then((value) => setState(value))
        .catch((e) => {
          console.error('SecureStore getItemAsync failed:', e);
          setState(null);
        });
    }
    // key is sufficient dependency; setState is stable from useReducer
  }, [key]);

  const setValue = useCallback(
    (value: string | null) => {
      setState(value);
      // Fire-and-forget persistence; log failures
      setStorageItemAsync(key, value).catch((e) => console.error('Failed to persist value:', e));
    },
    [key]
  );

  return [state, setValue];
}

export default function StorageExample(): JSX.Element {
  const [[loading, value], setValue] = useStorageState('my-key');
  const [input, setInput] = useState('');

  useEffect(() => {
    if (!loading) {
      setInput(value ?? '');
    }
  }, [loading, value]);

  if (loading) {
    return (
      <View style={styles.center}>
        <Text>Loading...</Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Text style={styles.label}>Stored value:</Text>
      <Text style={styles.value}>{value ?? '(none)'}</Text>

      <TextInput
        value={input}
        onChangeText={setInput}
        placeholder="Enter value"
        style={styles.input}
      />

      <View style={styles.buttonsRow}>
        <Button title="Save" onPress={() => setValue(input)} />
        <View style={styles.spacer} />
        <Button title="Clear" onPress={() => setValue(null)} color="red" />
      </View>
    </View>
  );
}

