// Note: In a real app you can use a true dynamic import like:
// const math = await import('./math');
// Make sure a ./math.ts exists and that @expo/metro-runtime is installed in your entry bundle
// (Expo Router includes it by default). The example below is self-contained so it compiles
// in a single file for dataset/testing purposes.

type MathModule = { add: (a: number, b: number) => number };

// Simulated dynamic loader that behaves like import('./math') but stays in one file.
const simulatedDynamicImportMath = async (): Promise<MathModule> => {
  // Simulate file-loading delay
  await new Promise(resolve => setTimeout(resolve, 300));
  return {
    add(a: number, b: number) {
      return a + b;
    },
  };
};

export default function AsyncImportExample(): JSX.Element {
  const [result, setResult] = useState<number | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const handleImport = useCallback(async () => {
    setError(null);
    setLoading(true);
    setResult(null);
    try {
      // Replace the next line with `await import('./math')` when using a real external module
      const math = await simulatedDynamicImportMath();
      setResult(math.add(1, 2));
    } catch (e: unknown) {
      setError(e instanceof Error ? e.message : String(e));
    } finally {
      setLoading(false);
    }
  }, []);

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Async import example</Text>
      <View style={styles.row}>
        <Button title="Add 1 + 2" onPress={handleImport} disabled={loading} />
      </View>
      {loading && <Text style={styles.info}>Loading module…</Text>}
      {error && <Text style={styles.error}>Error: {error}</Text>}
      {result !== null && <Text style={styles.result}>Result: {result}</Text>}
      <Text style={styles.hint}>
        Tip: To enable chunked async bundles for web exports, install @expo/metro-runtime and
        import it from your entry bundle (Expo Router does this automatically).
      </Text>
    </View>
  );
}

