import React from 'react';
import { View, Text, StyleSheet, StyleProp, ViewStyle, TextStyle } from 'react-native';

// Minimal, self-contained Tailwind-like helper for examples.
// This avoids external dependencies and compiles in an Expo/React Native TypeScript project.

type StyleMap = ViewStyle | TextStyle;
const CLASS_MAP: Record<string, StyleMap> = {
  'flex-1': { flex: 1 },
  'justify-center': { justifyContent: 'center' },
  'items-center': { alignItems: 'center' },
  'bg-blue-100': { backgroundColor: '#ebf8ff' },
  'bg-white': { backgroundColor: '#ffffff' },
  'p-4': { padding: 16 },
  'px-4': { paddingHorizontal: 16 },
  'py-2': { paddingVertical: 8 },
  'rounded': { borderRadius: 8 },
  'text-lg': { fontSize: 18 },
  'text-sm': { fontSize: 14 },
  'font-bold': { fontWeight: '700' as TextStyle['fontWeight'] },
  'text-blue-700': { color: '#2b6cb0' },
  'text-gray-700': { color: '#4a5568' }
};

/**
 * Convert a space-separated string of "classes" to a React Native style.
 * Not a full Tailwind implementation — just a tiny helper for examples.
 */
export function tw(classes?: string): StyleProp<StyleMap> {
  if (!classes) return undefined;
  const list = classes
    .trim()
    .split(/\s+/)
    .map((c) => CLASS_MAP[c])
    .filter(Boolean) as StyleMap[];
  return list.length > 0 ? list : undefined;
}

const HomeScreen: React.FC = () => {
  return (
    <View style={tw('flex-1 justify-center items-center bg-blue-100 p-4') as StyleProp<ViewStyle>}>
      <View style={[styles.card, tw('bg-white px-4 py-2 rounded') as StyleProp<ViewStyle>]}> 
        <Text style={tw('text-lg font-bold text-blue-700') as StyleProp<TextStyle>}>
          Hello — Tailwind-style in Expo
        </Text>
        <Text style={tw('text-sm text-gray-700') as StyleProp<TextStyle>}>
          This example shows how to mimic Tailwind utilities without external packages.
        </Text>
      </View>
    </View>
  );
};

