  const _default: { logEvent: typeof logEvent };
  export { logEvent };
  export default _default;
}

import React, { useEffect } from 'react';
import { View, Text, StyleSheet } from 'react-native';

export default function App(): JSX.Element {
  useEffect(() => {
    let cancelled = false;

    (async () => {
      try {
        // Use dynamic import so TypeScript doesn't fail if the package isn't installed.
        const insights = await import('expo-insights');
        if (cancelled) return;

        // expo-insights may export a named logEvent or a default with logEvent.
        const log:
          | (typeof insights.logEvent)
          | (typeof insights.default?.logEvent)
          | undefined =
          typeof insights.logEvent === 'function'
            ? insights.logEvent
            : insights.default && typeof insights.default.logEvent === 'function'
            ? insights.default.logEvent
            : undefined;

        if (log) {
          // Send the cold start event. Payload is optional and may be extended later.
          await log('cold_start');
          // In development, this message helps verify behavior; remove or guard in production if desired.
          // eslint-disable-next-line no-console
          console.log('[expo-insights] cold_start event sent');
        } else {
          // eslint-disable-next-line no-console
          console.warn('[expo-insights] logEvent not found on module');
        }
      } catch (error) {
        // If the module is not installed or import failed, do nothing (safe fallback).
        // eslint-disable-next-line no-console
        console.warn('expo-insights not available, skipping cold_start event');
      }
    })();

    return () => {
      cancelled = true;
    };
  }, []);

  return (
    <View style={styles.container}>
      <Text style={styles.text}>
        Welcome — attempted to send cold_start via expo-insights if installed.
      </Text>
    </View>
  );
}

