// This component implements a tiny local "store" (no redux package required)
// and sends actions/state to the Redux DevTools if available. Expo SDK 50+
// exposes Redux DevTools via the Expo DevTools plugins, so this will work
// when the DevTools plugin for Redux is enabled in your Expo devtools.
export default function CounterDevtoolsDemo(): JSX.Element {
  const [count, setCount] = useState<number>(0);
  const devtoolsRef = useRef<ReturnType<NonNullable<typeof global.__REDUX_DEVTOOLS_EXTENSION__['connect']>> | null>(null);

  // Initialize connection to Redux DevTools if present
  useEffect(() => {
    const hook = global.__REDUX_DEVTOOLS_EXTENSION__;
    if (hook?.connect) {
      try {
        const connection = hook.connect({ name: 'Expo: Counter (no-redux)' });
        devtoolsRef.current = connection;
        // Send the initial state so the DevTools can show it
        connection.init({ count });

        // Optional: subscribe to messages from the DevTools (time travel, etc.)
        if (connection.subscribe) {
          connection.subscribe((message: any) => {
            // Handle time-travel / dispatch from DevTools
            // Many DevTools messages include a payload and type; handle common cases.
            try {
              if (message?.type === 'DISPATCH' && message.state) {
                // message.state is a serialized state string in some setups
                const parsed = typeof message.state === 'string' ? JSON.parse(message.state) : message.state;
                if (parsed && typeof parsed.count === 'number') {
                  setCount(parsed.count);
                }
              }
            } catch (e) {
              // Ignore malformed messages
            }
          });
        }
      } catch (e) {
        // If anything goes wrong, leave devtoolsRef as null
        devtoolsRef.current = null;
      }
    }

    // Cleanup: optional — not all devtools connections require explicit teardown
    return () => {
      devtoolsRef.current = null;
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Helper to send actions to DevTools
  const sendToDevtools = (action: { type: string; payload?: any }) => {
    try {
      devtoolsRef.current?.send?.(action, { count });
    } catch {
      // ignore send errors
    }
  };

  const increment = () => {
    const next = count + 1;
    setCount(next);
    sendToDevtools({ type: 'INCREMENT' });
  };

  const decrement = () => {
    const next = count - 1;
    setCount(next);
    sendToDevtools({ type: 'DECREMENT' });
  };

  const reset = () => {
    setCount(0);
    sendToDevtools({ type: 'RESET' });
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Expo Redux DevTools demo (no redux package)</Text>
      <Text style={styles.count}>{count}</Text>
      <View style={styles.row}>
        <Button title="-" onPress={decrement} />
        <View style={styles.spacer} />
        <Button title="Reset" onPress={reset} />
        <View style={styles.spacer} />
        <Button title="+" onPress={increment} />
      </View>
      <Text style={styles.note}>
        If you have Expo DevTools open and the Redux DevTools plugin enabled (SDK 50+), actions and state will appear there.
      </Text>
    </View>
  );
}

