import React, { useEffect, useState } from 'react';
import {
  View,
  Text,
  TextInput,
  Button,
  ActivityIndicator,
  StyleSheet,
  ScrollView,
  Alert,
} from 'react-native';
import * as Contacts from 'expo-contacts';

interface PhoneField {
  id?: string;
  number: string;
}

interface ContactPatch {
  id: string;
  name: string;
  phones: PhoneField[];
}

export default function EditContactScreen({ contactId }: { contactId: string }) {
  const [contactPatch, setContactPatch] = useState<ContactPatch | null>(null);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);

  useEffect(() => {
    let mounted = true;
    (async () => {
      try {
        const { status } = await Contacts.requestPermissionsAsync();
        if (status !== 'granted') {
          Alert.alert('Permission required', 'Contacts permission is required to edit contacts.');
          if (mounted) setLoading(false);
          return;
        }

        const contact = await Contacts.getContactByIdAsync(contactId);
        if (!contact) {
          Alert.alert('Not found', 'Contact not found');
          if (mounted) setLoading(false);
          return;
        }

        const patch: ContactPatch = {
          id: contact.id,
          name: contact.name ?? '',
          phones:
            contact.phoneNumbers?.map((p) => ({ id: p.id, number: p.number ?? '' })) ?? [],
        };

        if (mounted) setContactPatch(patch);
      } catch (e) {
        console.error(e);
        Alert.alert('Error', 'Failed to load contact');
      } finally {
        if (mounted) setLoading(false);
      }
    })();

    return () => {
      mounted = false;
    };
  }, [contactId]);

  const handleNameChange = (name: string) => {
    setContactPatch((prev) => (prev ? { ...prev, name } : prev));
  };

  const handlePhoneChange = (index: number, number: string) => {
    setContactPatch((prev) => {
      if (!prev) return prev;
      const phones = prev.phones.slice();
      phones[index] = { ...phones[index], number };
      return { ...prev, phones };
    });
  };

  const handleAddPhone = () => {
    setContactPatch((prev) => (prev ? { ...prev, phones: [...prev.phones, { number: '' }] } : prev));
  };

  const handleRemovePhone = (index: number) => {
    setContactPatch((prev) => {
      if (!prev) return prev;
      const phones = prev.phones.filter((_, i) => i !== index);
      return { ...prev, phones };
    });
  };

  const handleSave = async () => {
    if (!contactPatch) return;
    setSaving(true);
    try {
      // Build a minimal contact object accepted by expo-contacts
      const contactToUpdate: any = {
        id: contactPatch.id,
        name: contactPatch.name,
        phoneNumbers: contactPatch.phones.map((p) => ({ number: p.number })),
      };

      // updateContactAsync typing can be strict across SDK versions; cast to any to ensure compile
      await Contacts.updateContactAsync(contactToUpdate as any);
      Alert.alert('Saved', 'Contact updated successfully');
    } catch (e) {
      console.error(e);
      Alert.alert('Error', 'Failed to save contact');
    } finally {
      setSaving(false);
    }
  };

  if (loading || !contactPatch) {
    return (
      <View style={styles.centered}>
        <ActivityIndicator size="large" />
      </View>
    );
  }

  return (
    <ScrollView contentContainerStyle={styles.container} keyboardShouldPersistTaps="handled">
      <Text style={styles.label}>Edit ID: {contactPatch.id}</Text>

      <Text style={styles.label}>Name</Text>
      <TextInput
        style={styles.input}
        value={contactPatch.name}
        onChangeText={handleNameChange}
        placeholder="Contact name"
        returnKeyType="done"
      />

      <Text style={[styles.label, { marginTop: 12 }]}>Phone numbers</Text>

      {contactPatch.phones.length === 0 && (
        <Text style={styles.helper}>No phone numbers — add one below.</Text>
      )}

      {contactPatch.phones.map((phone, index) => (
        <View key={phone.id ?? index} style={styles.phoneRow}>
          <TextInput
            style={styles.phoneInput}
            value={phone.number}
            onChangeText={(text) => handlePhoneChange(index, text)}
            placeholder={`Phone #${index + 1}`}
            keyboardType="phone-pad"
          />
          <View style={styles.removeButton}>
            <Button title="Remove" onPress={() => handleRemovePhone(index)} />
          </View>
        </View>
      ))}

      <View style={styles.actionRow}>
        <Button title="Add Phone" onPress={handleAddPhone} />
      </View>

      <View style={{ height: 16 }} />

      <Button title={saving ? 'Saving...' : 'Save Contact'} onPress={handleSave} disabled={saving} />
    </ScrollView>
  );
}

