import React, { useState } from 'react';
import { View, Text, Button, FlatList, Image, StyleSheet, Alert } from 'react-native';
import * as MediaLibrary from 'expo-media-library';
import type { Asset, Album } from 'expo-media-library';

export default function AlbumManager(): JSX.Element {
  const [album, setAlbum] = useState<Album | null>(null);
  const [albumTitle, setAlbumTitle] = useState<string>('');
  const [assets, setAssets] = useState<Asset[]>([]);
  const [loading, setLoading] = useState<boolean>(false);

  const createAlbumWithFirstAsset = async () => {
    setLoading(true);
    try {
      const { status } = await MediaLibrary.requestPermissionsAsync();
      if (status !== 'granted') {
        Alert.alert('Permission required', 'Permission required to access the media library.');
        return;
      }

      const firstAssets = await MediaLibrary.getAssetsAsync({ first: 1 });
      if (!firstAssets.assets || firstAssets.assets.length === 0) {
        Alert.alert('No assets', 'No assets found in the media library.');
        return;
      }

      const asset = firstAssets.assets[0];
      const albumName = 'MyNewAlbum';

      // Try to create the album. If it already exists createAlbumAsync will throw on some platforms,
      // so handle that by fetching the existing album and adding the asset to it.
      let createdAlbum: Album | null = null;
      try {
        createdAlbum = await MediaLibrary.createAlbumAsync(albumName, asset, false);
      } catch (err) {
        // If album exists, get it and add the asset (if needed).
        createdAlbum = await MediaLibrary.getAlbumAsync(albumName);
        if (!createdAlbum) {
          throw err; // rethrow if we couldn't recover
        }
        // Add asset to the existing album (no copy) if asset not already present.
        try {
          await MediaLibrary.addAssetsToAlbumAsync([asset.id], createdAlbum.id, false);
        } catch (addErr) {
          // ignore if already present or platform-specific limitations
          console.warn('Could not add asset to album:', addErr);
        }
      }

      if (!createdAlbum) {
        Alert.alert('Error', 'Could not create or access the album.');
        return;
      }

      setAlbum(createdAlbum);
      setAlbumTitle(createdAlbum.title ?? albumName);

      // Load up to 100 assets from that album to display.
      const albumAssets = await MediaLibrary.getAssetsAsync({ album: createdAlbum.id, first: 100 });
      setAssets(albumAssets.assets ?? []);
    } catch (e) {
      console.error(e);
      Alert.alert('Error', 'An unexpected error occurred.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <View style={styles.container}>
      <Button title={loading ? 'Working…' : 'Create Album with First Asset'} onPress={createAlbumWithFirstAsset} disabled={loading} />

      {assets.length > 0 ? (
        <>
          <Text style={styles.title}>Assets in {albumTitle}:</Text>
          <FlatList
            data={assets}
            keyExtractor={(item) => item.id}
            renderItem={({ item }) => (
              <View style={styles.row}>
                <Image source={{ uri: item.uri }} style={styles.thumb} />
                <Text style={styles.filename}>{item.filename ?? item.uri}</Text>
              </View>
            )}
          />
        </>
      ) : (
        <Text style={styles.status}>{album ? 'Album is empty.' : 'No album created yet.'}</Text>
      )}
    </View>
  );
}

