export default function WebCameraInIframe(): JSX.Element {
  const [hasPermission, setHasPermission] = useState<boolean | null>(null);
  const [photoUri, setPhotoUri] = useState<string | null>(null);
  // Avoid using the Camera value as a compile-time type; keep the ref untyped to satisfy TS.
  const cameraRef = useRef<any>(null);

  useEffect(() => {
    (async () => {
      try {
        const { status } = await Camera.requestCameraPermissionsAsync();
        setHasPermission(status === 'granted');
      } catch (e) {
        setHasPermission(false);
      }
    })();
  }, []);

  const takePicture = async () => {
    try {
      if (!cameraRef.current) return;
      const result = await cameraRef.current.takePictureAsync({ base64: true });
      if (result && result.base64) {
        setPhotoUri(`data:image/jpeg;base64,${result.base64}`);
      } else if (result && result.uri) {
        // Some platforms may return a file URI instead of base64
        setPhotoUri(result.uri);
      }
    } catch (e) {
      console.error('Failed to take picture', e);
    }
  };

  if (hasPermission === null) {
    return (
      <View style={styles.center}>
        <Text>Requesting camera permission...</Text>
      </View>
    );
  }

  if (hasPermission === false) {
    return (
      <View style={styles.center}>
        <Text>No access to camera</Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Camera
        ref={cameraRef}
        style={styles.camera}
        ratio="16:9"
        // On web, expo-camera uses getUserMedia under the hood and will provide base64 when requested.
      />

      <View style={styles.controls}>
        <Button title="Take Photo" onPress={takePicture} />
      </View>

      {photoUri ? (
        <View style={styles.preview}>
          <Text style={styles.previewLabel}>Captured Photo:</Text>
          {/* Use react-native Image which maps to <img> on web via react-native-web */}
          <Image source={{ uri: photoUri }} style={styles.previewImage} resizeMode="contain" />
        </View>
      ) : null}

      {/*
        When embedding this page in a Chrome iframe, add the attribute:
        allow="microphone; camera;"
        Example: <iframe src="..." allow="microphone; camera;"></iframe>
        This enables camera access inside cross-origin iframes on modern Chrome.
      */}
    </View>
  );
}

