import React, { useEffect, useState } from 'react';
import { View, Text, Button, Platform, StyleSheet, Alert } from 'react-native';
import * as TaskManager from 'expo-task-manager';
import * as BackgroundFetch from 'expo-background-fetch';

const TASK_NAME = 'MY_PERIODIC_BACKGROUND_FETCH';

// Define the background task at module level so the native side can call it.
TaskManager.defineTask(TASK_NAME, async () => {
  try {
    // Place background work here (e.g., fetch, cleanup, sync). Keep it short.
    console.log('[BackgroundFetch] task running:', TASK_NAME);

    // Example: perform minimal work and indicate new data was fetched.
    // Real network calls are allowed but keep execution time small to avoid system termination.

    return BackgroundFetch.BackgroundFetchResult.NewData;
  } catch (error) {
    console.error('[BackgroundFetch] task error:', error);
    return BackgroundFetch.BackgroundFetchResult.Failed;
  }
});

export default function App(): JSX.Element {
  const [isRegistered, setIsRegistered] = useState<boolean>(false);

  useEffect(() => {
    // Check registration status on mount
    let mounted = true;
    (async () => {
      try {
        const registered = await TaskManager.isTaskRegisteredAsync(TASK_NAME);
        if (mounted) setIsRegistered(registered);
      } catch (err) {
        console.error('Error checking task registration:', err);
      }
    })();
    return () => {
      mounted = false;
    };
  }, []);

  async function registerTask() {
    try {
      const already = await TaskManager.isTaskRegisteredAsync(TASK_NAME);
      if (already) {
        Alert.alert('Task already registered');
        setIsRegistered(true);
        return;
      }

      // Register the task. Options: minimumInterval in seconds (Android minimum ~15min enforced by platform).
      // Note: There are no explicit Expo options to require charging or network — the OS will only run background tasks
      // when its policies (battery, network availability) allow it. Documented behavior: tasks run only if battery is sufficient or device is charging and network is available.
      await BackgroundFetch.registerTaskAsync(TASK_NAME, {
        minimumInterval: 15 * 60, // 15 minutes
        stopOnTerminate: false,   // on Android allows restart after boot if true/false depending on needs
        startOnBoot: true,
      });

      setIsRegistered(true);
      Alert.alert('Background task registered');
    } catch (err) {
      console.error('Failed to register background task:', err);
      Alert.alert('Register failed', String(err));
    }
  }

  async function unregisterTask() {
    try {
      const registered = await TaskManager.isTaskRegisteredAsync(TASK_NAME);
      if (!registered) {
        Alert.alert('Task is not registered');
        setIsRegistered(false);
        return;
      }
      await BackgroundFetch.unregisterTaskAsync(TASK_NAME);
      setIsRegistered(false);
      Alert.alert('Background task unregistered');
    } catch (err) {
      console.error('Failed to unregister background task:', err);
      Alert.alert('Unregister failed', String(err));
    }
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Expo Background Fetch Example</Text>
      <Text style={styles.info}>
        Platform: {Platform.OS} {'\n'}
        Task name: {TASK_NAME}
      </Text>
      <Text style={styles.note}>
        Note: The OS controls when background tasks run. They will only execute when system constraints (battery, network, device policy) permit.
      </Text>
      <View style={styles.row}>
        <Button title={isRegistered ? 'Registered' : 'Register Task'} onPress={registerTask} disabled={isRegistered} />
        <View style={styles.spacer} />
        <Button title="Unregister Task" onPress={unregisterTask} disabled={!isRegistered} />
      </View>
    </View>
  );
}

