export default function App() {
  const [contacts, setContacts] = useState<Contacts.Contact[]>([]);
  const [permission, setPermission] = useState<'undetermined' | 'granted' | 'denied'>('undetermined');

  useEffect(() => {
    (async () => {
      const { status } = await Contacts.requestPermissionsAsync();
      setPermission(status);
      if (status === 'granted') {
        const { data } = await Contacts.getContactsAsync({
          fields: [Contacts.Fields.Emails],
        });
        setContacts(data);
      }
    })();
  }, []);

  if (permission === 'undetermined') {
    return (
      <View style={styles.container}>
        <Text>Requesting permission...</Text>
      </View>
    );
  }

  if (permission === 'denied') {
    return (
      <View style={styles.container}>
        <Text>Permission to access contacts was denied.</Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Contacts with Emails</Text>
      <FlatList
        data={contacts.filter(c => c.emails && c.emails.length > 0)}
        keyExtractor={item => item.id}
        renderItem={({ item }) => (
          <View style={styles.item}>
            <Text style={styles.name}>{item.name}</Text>
            {item.emails?.map((email, idx) => (
              <Text key={idx} style={styles.email}>{email.email}</Text>
            ))}
          </View>
        )}
