import React, { useState } from 'react';
import { View, Text, Button, StyleSheet } from 'react-native';
import * as Network from 'expo-network';

const MacAddressScreen: React.FC = () => {
  const [mac, setMac] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const fetchMacAddress = async () => {
    setMac(null);
    setError(null);

    // The official expo-network typings may not include getMacAddressAsync on all platforms.
    // Check at runtime and call it via any to avoid TypeScript compile errors while keeping safe runtime checks.
    const maybeGetMac = (Network as any).getMacAddressAsync;
    if (typeof maybeGetMac !== 'function') {
      setError('getMacAddressAsync is not available on this platform. Use Network.getIpAddressAsync or a native module when needed.');
      return;
    }

    try {
      const result = await maybeGetMac();
      // Some implementations may return non-string shapes; normalize to string for display.
      setMac(typeof result === 'string' ? result : JSON.stringify(result));
    } catch (e: unknown) {
      const code = (e as any)?.code as string | undefined;

      // Map known expo-network error codes to friendly messages (from Expo docs)
      if (code === 'ERR_NETWORK_SOCKET_EXCEPTION') {
        setError('Socket error: Unable to access MAC address.');
      } else if (code === 'ERR_NETWORK_INVALID_PERMISSION_INTERNET') {
        setError('Invalid permissions: Please ensure ACCESS_WIFI_STATE and internet permissions are granted.');
      } else if (code === 'ERR_NETWORK_NO_ACCESS_NETWORKINFO') {
        setError('No access to network info: Please enable network access or grant required permissions.');
      } else if (e instanceof Error && e.message) {
        setError(e.message);
      } else {
        setError('An unknown error occurred while retrieving the MAC address.');
      }
    }
  };

  return (
    <View style={styles.container}>
      <Button title="Get MAC Address" onPress={fetchMacAddress} />
      {mac ? <Text style={styles.result}>MAC Address: {mac}</Text> : null}
      {error ? <Text style={styles.error}>{error}</Text> : null}
    </View>
  );
};

