import React, { useEffect } from 'react';
import { Button, View, Text, Alert } from 'react-native';
import * as TaskManager from 'expo-task-manager';
import * as BackgroundFetch from 'expo-background-fetch';

const BACKGROUND_FETCH_TASK = 'background-fetch';

// Define the background fetch task in the global scope
TaskManager.defineTask(BACKGROUND_FETCH_TASK, async () => {
  const now = Date.now();
  console.log(`Got background fetch call at date: ${new Date(now).toISOString()}`);
  // Return the result type
  return BackgroundFetch.BackgroundFetchResult.NewData;
});

async function registerBackgroundFetchAsync() {
  try {
    await BackgroundFetch.registerTaskAsync(BACKGROUND_FETCH_TASK, {
      minimumInterval: 60 * 15, // 15 minutes
      stopOnTerminate: false,
      startOnBoot: true,
    });
    Alert.alert('Background fetch registered');
  } catch (err) {
    Alert.alert('Failed to register background fetch', String(err));
  }
}

async function unregisterBackgroundFetchAsync() {
  try {
    await BackgroundFetch.unregisterTaskAsync(BACKGROUND_FETCH_TASK);
    Alert.alert('Background fetch unregistered');
  } catch (err) {
    Alert.alert('Failed to unregister background fetch', String(err));
  }
}

export default function App() {
  useEffect(() => {
    // Optionally, check status on mount
    BackgroundFetch.getStatusAsync().then(status => {
      console.log('BackgroundFetch status:', status);
    });
  }, []);

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      <Text>Expo Background Fetch Example</Text>
      <Button title="Register Background Fetch" onPress={registerBackgroundFetchAsync} />
      <Button title="Unregister Background Fetch" onPress={unregisterBackgroundFetchAsync} />
    </View>
  );
}

