import React, { useEffect, useState } from 'react';
import { View, Text, ActivityIndicator, ScrollView, Button, StyleSheet } from 'react-native';
import * as FileSystem from 'expo-file-system';

// Replace with a real SAF/content URI obtained from Android (e.g. via requestDirectoryPermissionsAsync)
const CONTENT_URI = 'content://com.android.externalstorage.documents/document/primary%3ADownload%2Fexample.txt';

export default function FileInfoExample(): JSX.Element {
  const [info, setInfo] = useState<FileSystem.FileInfo | null>(null);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState<string | null>(null);

  async function fetchInfo() {
    setLoading(true);
    setError(null);
    try {
      // getInfoAsync supports content:// URIs on Android for read-only info
      const fileInfo = await FileSystem.getInfoAsync(CONTENT_URI);
      setInfo(fileInfo);
    } catch (e) {
      setError(String(e ?? 'Unknown error'));
      setInfo(null);
    } finally {
      setLoading(false);
    }
  }

  useEffect(() => {
    fetchInfo();
  }, []);

  return (
    <ScrollView contentContainerStyle={styles.container}>
      <Text style={styles.heading}>FileSystem.getInfoAsync — content:// URI</Text>

      {loading && <ActivityIndicator style={styles.indicator} />}

      {error ? (
        <Text style={styles.error}>Error: {error}</Text>
      ) : info ? (
        <View style={styles.card}>
          {/* Common, well-typed fields are shown explicitly. Avoid accessing properties that TypeScript does not guarantee (e.g. size/modificationTime) */}
          <Text style={styles.label}>URI:</Text>
          <Text style={styles.value}>{info.uri}</Text>

          <Text style={styles.label}>Exists:</Text>
          <Text style={styles.value}>{info.exists ? 'Yes' : 'No'}</Text>

          <Text style={styles.label}>Is directory:</Text>
          <Text style={styles.value}>{info.isDirectory ? 'Yes' : 'No'}</Text>

          <Text style={styles.label}>Raw returned object:</Text>
          <Text style={styles.mono}>{JSON.stringify(info, null, 2)}</Text>
        </View>
      ) : (
        <Text style={styles.hint}>No info available yet.</Text>
      )}

      <View style={styles.buttons}>
        <Button title="Refresh" onPress={fetchInfo} />
      </View>

      <Text style={styles.note}>
        Note: On Android you may need to obtain a SAF/content URI using the Storage Access Framework (for example via
        requestDirectoryPermissionsAsync) before calling getInfoAsync. This example only reads information — writing is not
        supported for content:// URIs.
      </Text>
    </ScrollView>
  );
}

