import React, { useImperativeHandle, useRef, useState, forwardRef } from 'react';
import { View, Text, Button, StyleSheet, ViewStyle } from 'react-native';

type SplitViewHandle = {
  show: (columnName: string) => void;
};

type ColumnProps = {
  name: string;
  children?: React.ReactNode;
};

type SplitViewProps = {
  children?: React.ReactNode;
};

const Column: React.FC<ColumnProps> = ({ children }) => {
  // Column itself just renders its children; SplitView controls visibility.
  return <>{children}</>;
};

const SplitView = forwardRef<SplitViewHandle, SplitViewProps>(({ children }, ref) => {
  // active: 'both' | columnName
  const [active, setActive] = useState<string>('both');

  useImperativeHandle(ref, () => ({
    show: (columnName: string) => setActive(columnName),
  }));

  // Collect columns by reading child.props.name
  const childArray = React.Children.toArray(children) as React.ReactElement<ColumnProps>[];

  const primary = childArray.find(c => c.props.name === 'primary');
  const secondary = childArray.find(c => c.props.name === 'secondary');

  // Layout behaviour:
  // - active === 'both' => show both columns side-by-side
  // - active === 'primary' => show primary full width
  // - active === 'secondary' => show secondary full width
  return (
    <View style={styles.container}>
      {active === 'both' ? (
        // show both columns
        <View style={styles.splitRow}>
          <View style={styles.column}>{primary?.props.children ?? null}</View>
          <View style={styles.column}>{secondary?.props.children ?? null}</View>
        </View>
      ) : (
        // show only the requested column
        <View style={styles.singleColumn}>
          {childArray.map(c => (c.props.name === active ? <View key={c.props.name} style={styles.columnFull}>{c.props.children}</View> : null))}
        </View>
      )}
    </View>
  );
}) as React.ForwardRefExoticComponent<SplitViewProps & React.RefAttributes<SplitViewHandle>> & {
  Column: React.FC<ColumnProps>;
};

SplitView.Column = Column;

export default function Layout() {
  const ref = useRef<SplitViewHandle | null>(null);

  return (
    <SplitView ref={ref}>
      <SplitView.Column name="primary">
        <View style={styles.centered}>
          <Text style={styles.title}>Primary Column</Text>
          <Button title="Show secondary column" onPress={() => ref.current?.show('secondary')} />
          <View style={{ height: 8 }} />
          <Button title="Show both columns" onPress={() => ref.current?.show('both')} />
        </View>
      </SplitView.Column>

      <SplitView.Column name="secondary">
        <View style={styles.centered}>
          <Text style={styles.title}>Secondary Column</Text>
          <Button title="Show primary column" onPress={() => ref.current?.show('primary')} />
          <View style={{ height: 8 }} />
          <Button title="Show both columns" onPress={() => ref.current?.show('both')} />
        </View>
      </SplitView.Column>
    </SplitView>
  );
}

