export default function KeyboardListenerExample() {
  const [isKeyboardVisible, setIsKeyboardVisible] = useState(false);

  useEffect(() => {
    const handleKeyboardShow = () => setIsKeyboardVisible(true);
    const handleKeyboardHide = () => setIsKeyboardVisible(false);
    const showSub = Keyboard.addListener('keyboardDidShow', handleKeyboardShow);
    const hideSub = Keyboard.addListener('keyboardDidHide', handleKeyboardHide);
    return () => {
      showSub.remove();
      hideSub.remove();
    };
  }, []);

  return (
    <View style={styles.container}>
      <TextInput style={styles.input} placeholder="Tap to show keyboard" />
      {isKeyboardVisible && (
        <Button title="Dismiss Keyboard" onPress={Keyboard.dismiss} />
      )}
    </View>
  );
}

