// and finally hides the splash screen. In Expo Go the animation cannot be tested.

export default function App(): JSX.Element {
  const [isReady, setIsReady] = useState(false);

  useEffect(() => {
    let mounted = true;

    async function prepare() {
      try {
        // Prevent the splash screen from auto-hiding
        await SplashScreen.preventAutoHideAsync();

        // Simulate app preparation work (e.g. loading fonts, fetching data)
        await new Promise((resolve) => setTimeout(resolve, 2000));

        // setOptions exists on expo-splash-screen but its typed options may not include
        // animation properties across SDK versions. Casting to `any` allows calling it
        // with platform/standalone-only animation options without type errors.
        // NOTE: Animations via setOptions are only honored in standalone / development builds
        // that include the native splash-screen implementation. Expo Go will ignore them.
        if ((SplashScreen as any).setOptions) {
          try {
            (SplashScreen as any).setOptions({
              // These properties are intentionally provided for native-built apps.
              // They may be ignored in Expo Go and are not part of some type definitions,
              // so we cast to any above.
              animationType: 'fade',
              duration: 450,
            });
          } catch (e) {
            // If setOptions throws on some platforms/SDKs, ignore and continue to hide
            // the splash screen normally.
            // eslint-disable-next-line no-console
            console.warn('SplashScreen.setOptions call failed or is unsupported:', e);
          }
        }

        // Hide the native splash screen when ready
        await SplashScreen.hideAsync();

        if (mounted) setIsReady(true);
      } catch (e) {
        // If anything fails, make sure the app still renders
        // eslint-disable-next-line no-console
        console.error('Error preparing app:', e);
        if (mounted) setIsReady(true);
      }
    }

    prepare();

    return () => {
      mounted = false;
    };
  }, []);

  if (!isReady) {
    // Return null while the native splash screen is visible. Do not render the app UI yet.
    return null;
  }

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Welcome to My App!</Text>
      <Text style={styles.subtitle}>
        This demo requests a splash animation via SplashScreen.setOptions (standalone only).
      </Text>
      {Platform.OS === 'android' && (
        <Text style={styles.note}>(Animations are only effective in standalone builds.)</Text>
      )}
    </View>
  );
}

