import React, { useEffect, useState } from 'react';
import { View, Text, StyleSheet } from 'react-native';
import * as MediaLibrary from 'expo-media-library';

type AssetInfo = {
  id: string;
  filename?: string | null;
  mediaType?: string | null;
  width?: number | null;
  height?: number | null;
  creationTime?: number | null;
  modificationTime?: number | null;
};

export default function AssetPropertiesViewer(): JSX.Element {
  const [assetInfo, setAssetInfo] = useState<AssetInfo | null>(null);
  const [statusMessage, setStatusMessage] = useState<string>('Loading asset info...');

  useEffect(() => {
    let mounted = true;
    const fetchAssetInfo = async () => {
      try {
        const { status } = await MediaLibrary.requestPermissionsAsync();
        if (!mounted) return;
        if (status !== 'granted') {
          setStatusMessage('Permission to access media library was denied.');
          return;
        }

        const assetsResult = await MediaLibrary.getAssetsAsync({ first: 1, mediaType: MediaLibrary.MediaType.photo });
        if (!mounted) return;

        const [asset] = assetsResult.assets;
        if (!asset) {
          setStatusMessage('No image assets found in the media library.');
          return;
        }

        // Some fields are present directly on the asset object returned by getAssetsAsync
        const info: AssetInfo = {
          id: asset.id,
          filename: asset.filename ?? null,
          mediaType: asset.mediaType ? String(asset.mediaType) : null,
          width: typeof asset.width === 'number' ? asset.width : null,
          height: typeof asset.height === 'number' ? asset.height : null,
          creationTime: typeof asset.creationTime === 'number' ? asset.creationTime : null,
          modificationTime: typeof asset.modificationTime === 'number' ? asset.modificationTime : null,
        };

        // Optionally get more details via getAssetInfoAsync (not required for these basic properties)
        // const detailed = await MediaLibrary.getAssetInfoAsync(asset);
        // merge if needed: Object.assign(info, { ...detailed });

        setAssetInfo(info);
        setStatusMessage('');
      } catch (error) {
        console.error('Failed to fetch asset info:', error);
        if (mounted) setStatusMessage('Error fetching asset info. See console for details.');
      }
    };

    fetchAssetInfo();
    return () => {
      mounted = false;
    };
  }, []);

  if (statusMessage) {
    return (
      <View style={styles.container}>
        <Text>{statusMessage}</Text>
      </View>
    );
  }

  if (!assetInfo) {
    return (
      <View style={styles.container}>
        <Text>Loading...</Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      <Text style={styles.line}>Asset ID: {assetInfo.id}</Text>
      <Text style={styles.line}>Filename: {assetInfo.filename ?? '—'}</Text>
      <Text style={styles.line}>Media Type: {assetInfo.mediaType ?? '—'}</Text>
      <Text style={styles.line}>Width: {assetInfo.width ?? '—'}</Text>
      <Text style={styles.line}>Height: {assetInfo.height ?? '—'}</Text>
      <Text style={styles.line}>Creation Time: {assetInfo.creationTime ?? '—'}</Text>
      <Text style={styles.line}>Modification Time: {assetInfo.modificationTime ?? '—'}</Text>
    </View>
  );
}

