import React, { useEffect } from 'react';
import { Alert } from 'react-native';

// Some projects may not have TypeScript declarations for expo-screen-capture installed.
// Use a runtime require and suppress the TS module-not-found error.
// @ts-ignore
const ScreenCapture = require('expo-screen-capture');

export default function ScreenshotListener(): JSX.Element | null {
  useEffect(() => {
    let subscription: { remove: () => void } | undefined;

    const hasPermissions = async (): Promise<boolean> => {
      try {
        // requestPermissionsAsync may return an object like { status: 'granted' }
        const result = await ScreenCapture.requestPermissionsAsync?.();
        const status = result?.status ?? result;
        return status === 'granted' || status === true;
      } catch (e) {
        console.error('Failed to request screen-capture permissions:', e);
        return false;
      }
    };

    const addListenerAsync = async () => {
      if (await hasPermissions()) {
        // addScreenshotListener returns a subscription with a remove() method
        subscription = ScreenCapture.addScreenshotListener(() => {
          Alert.alert('Screenshot taken', 'Thanks for screenshotting my beautiful app 😊');
        });
      } else {
        console.error('Permissions needed to subscribe to screenshot events are missing!');
      }
    };

    addListenerAsync();

    return () => {
      try {
        subscription?.remove();
      } catch (e) {
        // swallow errors during cleanup
      }
    };
  }, []);

  return null;
}

