type CardProps = {
  children: React.ReactNode;
  style?: ViewStyle | ViewStyle[];
};

function baseCardStyle(): ViewStyle {
  return {
    backgroundColor: '#ffffff',
    borderRadius: 12,
    padding: 12,
  };
}

function elevationStyle(level = 2): ViewStyle {
  // Simple cross-platform elevation/shadow helper
  if (Platform.OS === 'android') {
    return { elevation: level } as ViewStyle;
  }
  // iOS shadow
  const shadowRadius = Math.max(1, level * 1.5);
  const shadowOpacity = 0.12 + level * 0.02;
  return {
    shadowColor: '#000',
    shadowOffset: { width: 0, height: Math.max(1, level) },
    shadowOpacity: Math.min(0.4, shadowOpacity),
    shadowRadius,
  } as ViewStyle;
}

export const Card: React.FC<CardProps> = ({ children, style }) => {
  return <View style={[baseCardStyle(), style]}>{children}</View>;
};

export const ElevatedCard: React.FC<CardProps> = ({ children, style }) => {
  return (
