}

export default async function myFunction(ctx: BuildStepContext): Promise<void> {
  const { logger } = ctx;
  logger.info('Custom EAS Build function executed!');

  // Read an input called "name" if provided, otherwise fallback to 'world'
  const nameInput = ctx.inputs?.name;
  const name = typeof nameInput === 'string' ? nameInput : 'world';
  logger.info(`Hello from custom function, ${name}!`);

  // Place a result into outputs so later steps can consume it
  ctx.outputs = ctx.outputs ?? {};
  ctx.outputs.greeting = `hello ${name}`;

  // Example: inspect environment variables
  if (ctx.env && ctx.env.CI === 'true') {
    logger.info('Detected CI environment');
  }

  // Put any async build logic here (file operations, shell commands, etc.)
}

