import React from 'react';
import { View, Text, Button, ActivityIndicator, StyleSheet } from 'react-native';
import * as Updates from 'expo-updates';

export default function App(): JSX.Element {
  const [error, setError] = React.useState<Error | null>(null);
  const [statusMessage, setStatusMessage] = React.useState<string | null>(null);
  const [busy, setBusy] = React.useState(false);

  // Install a global JS error handler and unhandled rejection listener.
  React.useEffect(() => {
    const globalAny: any = global as any;

    // Save previous global handler so we don't fully swallow existing behavior
    const previousHandler = globalAny.ErrorUtils?.getGlobalHandler?.();

    const handleError = (e: any, isFatal?: boolean) => {
      // Normalize to Error where possible
      const normalized = e instanceof Error ? e : new Error(String(e));
      setError(normalized);
      // Try a recovery attempt in the background
      tryRecover();

      // Call the previous handler (so devtools / system handlers still run)
      if (previousHandler) {
        try {
          previousHandler(e, isFatal);
        } catch {
          // ignore
        }
      }
    };

    // Set global ErrorUtils handler if available (React Native JS errors)
    if (globalAny.ErrorUtils?.setGlobalHandler) {
      globalAny.ErrorUtils.setGlobalHandler(handleError);
    }

    // Also listen for unhandled promise rejections
    const rejectionHandler = (ev: any) => {
      const reason = ev?.reason ?? ev;
      handleError(reason, false);
    };

    // Some environments expose globalThis.addEventListener
    try {
      (globalThis as any).addEventListener?.('unhandledrejection', rejectionHandler);
    } catch {
      // ignore if not available
    }

    return () => {
      // Try to restore previous handler on cleanup
      if (globalAny.ErrorUtils?.setGlobalHandler && previousHandler) {
        try {
          globalAny.ErrorUtils.setGlobalHandler(previousHandler);
        } catch {
          // ignore
        }
      }
      try {
        (globalThis as any).removeEventListener?.('unhandledrejection', rejectionHandler);
      } catch {
        // ignore
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Attempt to check/fetch an update and reload the app.
  const tryRecover = React.useCallback(async () => {
    setBusy(true);
    setStatusMessage('Checking for updates...');
    try {
      // Check if a remote update is available for the current branch
      const check = await Updates.checkForUpdateAsync();
      if (check.isAvailable) {
        setStatusMessage('Update available — downloading...');
        try {
          await Updates.fetchUpdateAsync();
          setStatusMessage('Update downloaded — reloading...');
          // Apply update by reloading the app runtime
          await Updates.reloadAsync();
          // reloadAsync typically won't return because the runtime restarts,
          // but handle the case where it does.
        } catch (fetchErr) {
          setStatusMessage('Failed to fetch or apply update.');
          console.warn('Update fetch/apply failed', fetchErr);
        }
      } else {
        setStatusMessage('No update available.');
      }
    } catch (checkErr) {
      setStatusMessage('Failed to check for updates.');
      console.warn('Update check failed', checkErr);
    } finally {
      setBusy(false);
    }
  }, []);

  const onManualReload = async () => {
    setBusy(true);
    setStatusMessage('Reloading app...');
    try {
      await Updates.reloadAsync();
    } catch (e) {
      setStatusMessage('Reload failed.');
      setError(e as Error);
    } finally {
      setBusy(false);
    }
  };

  // If no error, render the normal app UI (placeholder)
  if (!error) {
    return (
      <View style={styles.container}>
        <Text style={styles.title}>App loaded successfully</Text>
        <Text style={styles.hint}>If a launch error occurs, the app will try to recover via EAS Update.</Text>
      </View>
    );
  }

  // Error screen: show status and recovery actions
  return (
    <View style={styles.container}>
      <Text style={styles.title}>Something went wrong</Text>
      <Text style={styles.message}>{error.message}</Text>

      {statusMessage ? <Text style={styles.hint}>{statusMessage}</Text> : null}

      {busy ? <ActivityIndicator style={{ marginVertical: 12 }} /> : null}

      <View style={styles.buttons}>
        <Button title="Try fetch update" onPress={tryRecover} disabled={busy} />
        <View style={{ height: 12 }} />
        <Button title="Reload app" onPress={onManualReload} disabled={busy} />
      </View>

      <Text style={styles.small}>If this keeps happening, republish a previous safe update or roll forward with a fix.</Text>
    </View>
  );
}

