import { GestureDetector, Gesture } from 'react-native-gesture-handler';

export default function RelativeCoordsExample(): JSX.Element {
  // animatedRef should be passed to the view you want coordinates relative to
  const animatedRef = useAnimatedRef<View>();

  const handleRelativeCoords = (coords: { x: number; y: number } | null) => {
    if (coords) {
      console.log('Relative X:', coords.x, 'Relative Y:', coords.y);
    } else {
      console.log('Could not determine relative coordinates');
    }
  };

  const pan = Gesture.Pan().onEnd((event) => {
    // event.absoluteX / absoluteY come from gesture event
    const coords = getRelativeCoords(animatedRef, event.absoluteX, event.absoluteY);
    // getRelativeCoords runs on UI thread; use runOnJS to call JS function
    runOnJS(handleRelativeCoords)(coords);
  });

  return (
    <View style={styles.container}>
      <GestureDetector gesture={pan}>
        <Animated.View ref={animatedRef} style={styles.box} />
      </GestureDetector>
    </View>
  );
}

