import React from 'react';
import { View, Text, StyleSheet } from 'react-native';

type JsEngine = 'hermes' | 'jsc' | 'v8' | 'unknown';

/**
 * Detect the JS engine at runtime.
 * - Hermes sets global.HermesInternal
 * - V8-based runtimes often expose a `v8` marker or `__v8runtime`
 * - JSC does not expose a well-known global, so we treat the remaining case as 'jsc'
 */
const detectJsEngine = (): JsEngine => {
  const g = global as any;
  if (typeof g.HermesInternal === 'object' || typeof g.HermesInternal === 'function') {
    return 'hermes';
  }
  if (typeof g.v8 !== 'undefined' || typeof g.__v8runtime !== 'undefined') {
    return 'v8';
  }
  // Fallback: assume JSC when Hermes/V8 markers are absent
  return 'jsc';
};

export default function JsEngineInfo(): JSX.Element {
  const engine = detectJsEngine();

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Current JS Engine</Text>
      <Text style={styles.engine}>{engine.toUpperCase()}</Text>
      <Text style={styles.note}>
        Note: Switch the engine via app config (expo.jsEngine in app.json) and use a development build — Expo Go only supports Hermes from SDK 52+.
      </Text>
    </View>
  );
}

