export default function PushTokenExample() {
  const [token, setToken] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const registerForPushNotificationsAsync = async () => {
    if (!Device.isDevice) {
      setError('Must use physical device for Push Notifications');
      return;
    }
    const { status: existingStatus } = await Notifications.getPermissionsAsync();
    let finalStatus = existingStatus;
    if (existingStatus !== 'granted') {
      const { status } = await Notifications.requestPermissionsAsync();
      finalStatus = status;
    }
    if (finalStatus !== 'granted') {
      setError('Failed to get push token permission!');
      return;
    }
    const tokenData = await Notifications.getExpoPushTokenAsync();
    setToken(tokenData.data);
  };

  useEffect(() => {
    registerForPushNotificationsAsync();
  }, []);

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      <Text>Push Notification Token:</Text>
      <Text selectable style={{ marginVertical: 10 }}>{token || 'Fetching token...'}</Text>
      {error && <Text style={{ color: 'red' }}>{error}</Text>}
      <Button title="Refresh Token" onPress={registerForPushNotificationsAsync} />
    </View>
  );
}

