import React, { useEffect, useRef, useState } from 'react';
import { Animated, Easing, Pressable, StyleSheet, Text, View } from 'react-native';

// A self-contained Extended FAB component that mimics an "ExtendedFloatingActionButton"
// with an icon and text. It toggles between expanded (icon + label) and collapsed (icon only).
// No external UI package APIs are required, so it compiles in any React Native / Expo project.

export default function ExtendedFABExample(): JSX.Element {
  const [expanded, setExpanded] = useState(true);

  // Animated driver: 0 = collapsed, 1 = expanded
  const anim = useRef(new Animated.Value(expanded ? 1 : 0)).current;

  useEffect(() => {
    Animated.timing(anim, {
      toValue: expanded ? 1 : 0,
      duration: 220,
      easing: Easing.out(Easing.cubic),
      useNativeDriver: false, // animating width/opacity so keep false
    }).start();
  }, [expanded, anim]);

  const width = anim.interpolate({ inputRange: [0, 1], outputRange: [56, 176] });
  const labelOpacity = anim.interpolate({ inputRange: [0, 0.2, 1], outputRange: [0, 0, 1] });
  const labelTranslate = anim.interpolate({ inputRange: [0, 1], outputRange: [6, 0] });

  return (
    <View style={styles.screen} pointerEvents="box-none">
      {/* Position the extended FAB at bottom-right of the screen */}
      <View style={styles.container} pointerEvents="box-none">
        <Animated.View style={[styles.pill, { width }] as any}>
          <Pressable
            onPress={() => setExpanded(v => !v)}
            android_ripple={{ color: 'rgba(255,255,255,0.12)', radius: 28 }}
            style={styles.pressable}
            accessibilityRole="button"
            accessibilityState={{ expanded }}
            accessibilityLabel={expanded ? 'Collapse action' : 'Expand action'}
          >
            {/* Simple emoji icon used to avoid external icon dependencies */}
            <View style={styles.iconWrapper}>
              <Text style={styles.icon}>✎</Text>
            </View>

            <Animated.Text
              style={[
                styles.label,
                { opacity: labelOpacity, transform: [{ translateX: labelTranslate }] },
              ]}
              numberOfLines={1}
            >
