import React, { useEffect } from 'react';
import { Alert, Linking, View, Text } from 'react-native';

// Helper: detect typical OAuth/AuthSession redirect patterns.
// Auth redirects commonly include either an OAuth `code` or `error` in the
// query string, or tokens like `access_token` / `id_token` in the URL hash.
function isAuthSessionRedirect(url: string): boolean {
  if (!url) return false;
  const [beforeHash, hash = ''] = url.split('#');
  const query = beforeHash.includes('?') ? beforeHash.split('?')[1] : '';

  // Check hash for implicit-flow tokens
  if (hash && /(^|&)(access_token|id_token)=/.test(hash)) return true;

  // Check query for authorization code flow or errors
  if (query && /(^|&)(code|error)=/.test(query)) return true;

  return false;
}

export default function App(): JSX.Element {
  useEffect(() => {
    // Handler for incoming Linking events
    const handleDeepLink = (event: { url: string }) => {
      const { url } = event;
      if (!url) return;

      // Ignore AuthSession-style redirects so AuthSession (or other
      // auth-handling code) can handle them exclusively.
      if (isAuthSessionRedirect(url)) {
        // Optionally: log or silently ignore
        // console.debug('Filtered AuthSession redirect:', url);
        return;
      }

      // Handle other deep links here
      Alert.alert('Received deep link', url);
    };

    // Subscribe to URL events
    const subscription = Linking.addEventListener('url', handleDeepLink);

    // Also check the initial URL the app was opened with
    Linking.getInitialURL().then((initialUrl) => {
      if (initialUrl && !isAuthSessionRedirect(initialUrl)) {
        Alert.alert('App opened with deep link', initialUrl);
      }
    }).catch(() => {
      // ignore errors reading initial URL
    });

    return () => {
      // Clean up subscription
      subscription.remove();
    };
  }, []);

  return (
    <View style={{ flex: 1, alignItems: 'center', justifyContent: 'center' }}>
      <Text>Deep link listener active (AuthSession redirects are filtered)</Text>
    </View>
  );
}

