export default function ParallelBuilds() {
  const [loading, setLoading] = useState(false);
  const [results, setResults] = useState<any[]>([]);

  const handleTrigger = async () => {
    setLoading(true);
    setResults([]);
    // Example: trigger two different workflows in parallel
    const workflows = ['production', 'staging'];
    const buildPromises = workflows.map(wf => triggerBuild(wf));
    const res = await Promise.all(buildPromises);
    setResults(res);
    setLoading(false);
