  );
}

import React, { useEffect, useRef, useState } from 'react';
import { View, Text, StyleSheet } from 'react-native';
import * as Clipboard from 'expo-clipboard';

export default function ClipboardListener(): JSX.Element {
  const [message, setMessage] = useState<string>('Waiting for clipboard changes...');
  const last = useRef<string | null>(null);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  useEffect(() => {
    let active = true;

    async function checkClipboard() {
      try {
        const text = await Clipboard.getStringAsync();
        if (!active) return;

        // Initialize stored value on first read
        if (last.current === null) {
          last.current = text;
          return;
        }

        // If different, update message
        if (text !== last.current) {
          last.current = text;
          setMessage(text ? `Clipboard changed: ${text}` : 'Clipboard changed (empty)');
        }
      } catch (e) {
        // Ignore read errors on some platforms / permission states
      }
    }

    // Do an initial check immediately, then poll
    checkClipboard();
    intervalRef.current = setInterval(checkClipboard, 1000);

    return () => {
      active = false;
      if (intervalRef.current !== null) {
        clearInterval(intervalRef.current);
      }
    };
  }, []);

  return (
    <View style={styles.container}>
      <Text style={styles.text} numberOfLines={3} ellipsizeMode="tail">
        {message}
      </Text>
    </View>
  );
}

