import React, { useState } from 'react';
import { View, Text, Button, Platform, StyleSheet } from 'react-native';
import * as Application from 'expo-application';

export default function InstallReferrerExample(): JSX.Element {
  const [referrer, setReferrer] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [loading, setLoading] = useState(false);

  const fetchReferrer = async () => {
    setError(null);
    setReferrer(null);

    if (Platform.OS !== 'android') {
      setError('getInstallReferrerAsync is only available on Android.');
      return;
    }

    setLoading(true);
    try {
      // getInstallReferrerAsync returns a string (the install referrer) or null
      const result = await Application.getInstallReferrerAsync();
      setReferrer(result ?? null);
    } catch (e: unknown) {
      // Normalize the error shape because native modules may throw different shapes
      const err = e as { code?: string; responseCode?: number; message?: string };

      switch (err.code) {
        case 'ERR_APPLICATION_INSTALL_REFERRER':
          setError(
            `Install referrer error. responseCode=${
              typeof err.responseCode === 'number' ? err.responseCode : 'unknown'
            }`
          );
          break;
        case 'ERR_APPLICATION_INSTALL_REFERRER_SERVICE_DISCONNECTED':
          setError('Install referrer service disconnected. Try again later.');
          break;
        default:
          setError(err.message ?? String(e));
      }
    } finally {
      setLoading(false);
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Install Referrer (Android)</Text>
      <Button title={loading ? 'Loading…' : 'Get Install Referrer'} onPress={fetchReferrer} disabled={loading} />

      {referrer !== null && (
        <View style={styles.box}>
          <Text style={styles.label}>Install Referrer:</Text>
          <Text style={styles.value}>{referrer || '<empty>'}</Text>
        </View>
      )}

      {error && (
        <View style={styles.box}>
          <Text style={styles.errorLabel}>Error:</Text>
          <Text style={styles.errorValue}>{error}</Text>
        </View>
      )}

      <Text style={styles.note}>
        Note: The install referrer API is provided by Google Play and only works on Android devices installed from the Play Store.
      </Text>
    </View>
  );
}

