import React, { useState } from 'react';
import { Button, Text, View, StyleSheet } from 'react-native';
import { NativeModulesProxy } from 'expo-modules-core';

// Type shape for the native module. Adjust methods/arguments to match your native implementation.
type CustomModuleType = {
  doSomething?: (message: string) => Promise<string> | string;
};

// Access the module through NativeModulesProxy so the code is renderer-agnostic
const CustomModule = (NativeModulesProxy as any).CustomModule as CustomModuleType | undefined;

export default function CustomModuleExample(): JSX.Element {
  const [result, setResult] = useState<string | null>(null);
  const [busy, setBusy] = useState(false);

  const handlePress = async () => {
    setBusy(true);
    try {
      if (CustomModule && typeof CustomModule.doSomething === 'function') {
        // Native method might return a promise or a synchronous value; normalize with Promise.resolve
        const res = await Promise.resolve(CustomModule.doSomething!('Hello from JS!'));
        setResult(res == null ? String(res) : res);
      } else {
        setResult('CustomModule not available on this platform');
      }
    } catch (error) {
      setResult(error instanceof Error ? error.message : String(error));
    } finally {
      setBusy(false);
    }
  };

  return (
    <View style={styles.container}>
      <Button title={busy ? 'Calling...' : 'Call Native Module'} onPress={handlePress} disabled={busy} />
      {result ? <Text style={styles.result}>Result: {result}</Text> : null}
      <Text style={styles.hint}>
        Uses NativeModulesProxy from expo-modules-core so the same JS works with both architectures.
      </Text>
    </View>
  );
}

