export default function BrightnessErrorExample() {
  const [error, setError] = useState<string | null>(null);

  const setSystemBrightness = async () => {
    setError(null);
    try {
      await Brightness.setSystemBrightnessAsync(0.5);
    } catch (e: any) {
      // Handle specific Expo Brightness error codes
      if (e.code === 'ERR_BRIGHTNESS_PERMISSIONS_DENIED') {
        setError('Permission denied: SYSTEM_BRIGHTNESS not granted.');
      } else if (e.code === 'ERR_BRIGHTNESS_SYSTEM') {
        setError('System error occurred while setting brightness.');
      } else if (e.code === 'ERR_INVALID_ARGUMENT') {
