      {Platform.OS !== 'android' && (
        <Text style={{ marginTop: 10 }}>
          System brightness can only be set on Android.
        </Text>
      )}
      {error && (
        <Text style={{ color: 'red', marginTop: 10 }}>{error}</Text>
      )}
