import React, { useEffect } from 'react';
import { View, Text, Linking } from 'react-native';
import * as Notifications from 'expo-notifications';

export default function App(): JSX.Element {
  useEffect(() => {
    // Centralized handler that accepts a string or null
    const handleLink = (url: string | null) => {
      if (!url) return;
      // Replace this with navigation logic in a real app
      console.log('Handling deep link URL:', url);
    };

    // Handler for Linking events
    const onReceiveURL = (event: { url: string }) => {
      handleLink(event.url ?? null);
    };

    const linkingSubscription = Linking.addEventListener('url', onReceiveURL);

    // Handler for notification responses
    const notificationSubscription = Notifications.addNotificationResponseReceivedListener(response => {
      // Safely extract data.url with runtime checks to satisfy TypeScript
      try {
        const data = response?.notification?.request?.content?.data;

        // data can be anything; check for common shapes
        if (typeof data === 'string') {
          // If the data payload itself is a URL string
          handleLink(data);
          return;
        }

        if (data && typeof data === 'object') {
          const possibleUrl = (data as any).url;
          if (typeof possibleUrl === 'string') {
            handleLink(possibleUrl);
            return;
          }
        }

        // If no url found, no-op or handle other data
      } catch (e) {
        // Defensive: don't crash if shape isn't what's expected
        console.warn('Failed to parse notification data for URL', e);
      }
    });

    return () => {
      // Clean up listeners
      linkingSubscription.remove();
      notificationSubscription.remove();
    };
  }, []);

  return (
    <View style={{ flex: 1, alignItems: 'center', justifyContent: 'center' }}>
      <Text>Expo Notifications deep link demo</Text>
    </View>
  );
}

