// Safely probe known locations for a release channel (classic updates, EAS, and common extras).
function getReleaseChannel(): string {
  // Try the legacy manifest fields (may be typed differently across SDKs) using any casts
  const manifestAny = (Constants as any).manifest || (Constants as any).manifest2 || null;
  const expoConfigAny = (Constants as any).expoConfig || null;

  const candidates: Array<string | undefined> = [
    // classic: manifest.releaseChannel
    manifestAny?.releaseChannel,
    // classic: manifest.extra.releaseChannel
    manifestAny?.extra?.releaseChannel,
    // newer: expoConfig.extra.releaseChannel
    expoConfigAny?.extra?.releaseChannel,
    // expo-updates (EAS): Updates.channel or Updates.releaseChannel (not guaranteed)
    (Updates as any).channel,
    (Updates as any).releaseChannel,
    // expo-updates manifest (if present)
    (Updates as any).manifest?.releaseChannel,
  ];

  for (const c of candidates) {
    if (typeof c === 'string' && c.length > 0) return c;
  }

  // Fallback to default channel name when nothing is set
  return 'default';
}

const ReleaseChannelInfo: React.FC = () => {
  const [channel, setChannel] = useState<string>('default');

  useEffect(() => {
    setChannel(getReleaseChannel());
  }, []);

  return (
    <View style={styles.container}>
      <Text style={styles.label}>Current Release Channel:</Text>
      <Text style={styles.channel}>{channel}</Text>
    </View>
