// Replace these with your project's values
const SUPABASE_URL = 'https://your-project.supabase.co';
const SUPABASE_ANON_KEY = 'your-anon-key';
const TABLE_NAME = 'your_table';

type Row = { id?: number | string; [key: string]: any };

export default function SupabaseTableList(): JSX.Element {
  const [rows, setRows] = useState<Row[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    const controller = new AbortController();
    const fetchRows = async () => {
      try {
        const url = `${SUPABASE_URL}/rest/v1/${encodeURIComponent(TABLE_NAME)}?select=*`;
        const res = await fetch(url, {
          method: 'GET',
          headers: {
            Accept: 'application/json',
            apikey: SUPABASE_ANON_KEY,
            Authorization: `Bearer ${SUPABASE_ANON_KEY}`,
          },
          signal: controller.signal,
        });

        if (!res.ok) {
          const text = await res.text();
          throw new Error(`HTTP ${res.status}: ${text}`);
        }

        const json = (await res.json()) as Row[];
        setRows(json);
      } catch (err: any) {
        if (err.name === 'AbortError') return;
        setError(err.message ?? String(err));
      } finally {
        setLoading(false);
      }
    };

    fetchRows();
    return () => controller.abort();
  }, []);

  if (loading) {
    return (
      <SafeAreaView style={styles.container}>
        <ActivityIndicator size="large" />
      </SafeAreaView>
    );
  }

  if (error) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.center}>
          <Text style={styles.errorText}>Error fetching data:</Text>
          <Text selectable>{error}</Text>
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      <FlatList
        data={rows}
        keyExtractor={(item, index) => (item.id != null ? String(item.id) : String(index))}
        renderItem={({ item }) => (
          <View style={styles.item}>
            <Text style={styles.itemJson}>{JSON.stringify(item, null, 2)}</Text>
          </View>
        )}
        ItemSeparatorComponent={() => <View style={styles.separator} />}
      />
    </SafeAreaView>
  );
}

