import React, { useState, useEffect } from 'react';
import { View, Text, Button, Image, ScrollView, StyleSheet } from 'react-native';
import * as MediaLibrary from 'expo-media-library';

export default function App() {
  const [albums, setAlbums] = useState<MediaLibrary.Album[] | null>(null);
  const [permissionResponse, requestPermission] = MediaLibrary.usePermissions();

  async function getAlbums() {
    if (permissionResponse?.status !== 'granted') {
      await requestPermission();
    }
    const fetchedAlbums = await MediaLibrary.getAlbumsAsync({ includeSmartAlbums: true });
    setAlbums(fetchedAlbums);
  }

  return (
    <ScrollView contentContainerStyle={styles.container}>
      <Button title="Load Albums" onPress={getAlbums} />
      {albums && albums.map((album) => (
        <AlbumEntry key={album.id} album={album} />
      ))}
    </ScrollView>
  );
}

function AlbumEntry({ album }: { album: MediaLibrary.Album }) {
  const [assets, setAssets] = useState<MediaLibrary.Asset[]>([]);

  useEffect(() => {
    async function getAlbumAssets() {
      const albumAssets = await MediaLibrary.getAssetsAsync({ album });
      setAssets(albumAssets.assets);
    }
    getAlbumAssets();
  }, [album]);

  return (
    <View style={styles.albumContainer}>
      <Text style={{ fontWeight: 'bold' }}>{album.title} - {album.assetCount ?? 'no'} assets</Text>
      <ScrollView horizontal>
        {assets.map((asset) => (
          <Image
            key={asset.id}
            source={{ uri: asset.uri }}
            style={{ width: 60, height: 60, marginRight: 8, borderRadius: 4 }}
          />
        ))}
      </ScrollView>
    </View>
  );
}

