import React, { useEffect, useState } from 'react';
import { View, Text, Button, TextInput } from 'react-native';
import Storage from 'expo-sqlite/kv-store';

export default function KeyValueExample() {
  const [key, setKey] = useState('');
  const [value, setValue] = useState('');
  const [storedValue, setStoredValue] = useState<string | null>(null);

  const saveValue = async () => {
    await Storage.setItem(key, value);
    setKey('');
    setValue('');
  };

  const loadValue = async () => {
    const v = await Storage.getItem(key);
    setStoredValue(v);
  };

  const removeValue = async () => {
    await Storage.removeItem(key);
    setStoredValue(null);
  };

  return (
    <View style={{ padding: 20 }}>
      <TextInput
        placeholder="Key"
        value={key}
        onChangeText={setKey}
        style={{ borderWidth: 1, marginBottom: 8, padding: 8 }}
      />
      <TextInput
        placeholder="Value"
        value={value}
        onChangeText={setValue}
        style={{ borderWidth: 1, marginBottom: 8, padding: 8 }}
      />
      <Button title="Save Value" onPress={saveValue} />
      <View style={{ height: 8 }} />
      <Button title="Load Value" onPress={loadValue} />
      <View style={{ height: 8 }} />
      <Button title="Remove Value" onPress={removeValue} />
      <View style={{ marginTop: 16 }}>
        <Text>Stored Value: {storedValue === null ? 'None' : storedValue}</Text>
      </View>
    </View>
  );
}

import React, { useRef, useEffect } from 'react';
import { View, StyleSheet, Dimensions } from 'react-native';
// Suppress missing type declarations for expo-gl if the project does not provide them
// @ts-ignore
import { GLView } from 'expo-gl';

export default function App(): JSX.Element {
  const animationRef = useRef<number | null>(null);

  // Keep a stable reference to the renderer so cleanup can cancel it
  const onContextCreate = async (gl: any) => {
    // Example: set clear color once
    gl.clearColor(0.0, 0.5, 0.5, 1.0);

    const render = () => {
      // Clear the drawing buffer
      gl.clear(gl.COLOR_BUFFER_BIT);

      // Flush / present the rendered frame to the GLView
      // endFrameEXP is provided by expo-gl's GL context
      if (typeof gl.endFrameEXP === 'function') {
        gl.endFrameEXP();
      }

      // Queue next frame
      animationRef.current = requestAnimationFrame(render);
    };

    // Start the loop
    render();
  };

  useEffect(() => {
    return () => {
      // Cancel any pending animation frame on unmount
      if (animationRef.current !== null) {
        cancelAnimationFrame(animationRef.current);
      }
    };
  }, []);

  return (
    <View style={styles.container}>
      <GLView style={styles.glview} onContextCreate={onContextCreate} />
    </View>
  );
}

