const submitBinary = (platform: 'android' | 'ios', filePath: string) => {
  // Replace 'android' or 'ios' and filePath as needed
  const command = `eas submit --platform ${platform} --path ${filePath}`;
  exec(command, (error, stdout, stderr) => {
    if (error) {
      Alert.alert('Submission Error', stderr);
    } else {
      Alert.alert('Submission Success', stdout);
    }
  });
};

