export default function DateTimePickerExample(): JSX.Element {
  const [date, setDate] = useState<Date>(new Date());
  const [show, setShow] = useState<boolean>(false);
  const [mode, setMode] = useState<'date' | 'time'>('date');

  const handleChange = (_event: any, selected?: Date) => {
    const current = selected ?? date;
    // On Android the picker is a dialog that should be dismissed after selection.
    // On iOS the picker can remain visible (inline/modal behavior differs by platform).
    setShow(Platform.OS === 'ios');
    setDate(current);
  };

  return (
    <View style={styles.container}>
      <View style={styles.buttonsRow}>
        <Button
          title='Show Date Picker'
          onPress={() => {
            setMode('date');
            setShow(true);
          }}
        />
        <View style={styles.spacer} />
        <Button
          title='Show Time Picker'
          onPress={() => {
            setMode('time');
            setShow(true);
          }}
        />
      </View>

      <Text style={styles.selected}>Selected: {date.toLocaleString()}</Text>

      {show && (
        <DateTimePicker
          value={date}
          mode={mode}
          display='default'
          onChange={handleChange}
        />
      )}
    </View>
  );
}

