import React, { useState } from 'react';
import { View, Text, Button, StyleSheet } from 'react-native';
import * as Network from 'expo-network';

type NetworkError = Error & { code?: string };

export default function NetworkMacExample(): JSX.Element {
  const [loading, setLoading] = useState(false);
  const [result, setResult] = useState<{ kind: 'mac' | 'ip'; value: string } | null>(null);
  const [error, setError] = useState<string | null>(null);

  const fetchAddress = async () => {
    setLoading(true);
    setResult(null);
    setError(null);

    try {
      // Some SDK versions do not expose getMacAddressAsync on the Network module's TS type.
      // Access it dynamically and fall back to getIpAddressAsync if not available.
      const maybeGetMac = (Network as any).getMacAddressAsync;

      if (typeof maybeGetMac === 'function') {
        const mac: string = await maybeGetMac();
        setResult({ kind: 'mac', value: mac });
        return;
      }

      // Fallback: call getIpAddressAsync (this is available on expo-network).
      const ip = await Network.getIpAddressAsync();
      setResult({ kind: 'ip', value: ip });
    } catch (e) {
      const err = e as NetworkError;
      // Map documented error codes (from expo-network docs) to friendly messages.
      // These codes may appear when attempting to read MAC address info on some platforms.
      let friendly = err.message || 'Unknown error';

      switch (err.code) {
        case 'ERR_NETWORK_SOCKET_EXCEPTION':
          friendly = 'Socket error while creating or accessing network socket.';
          break;
        case 'ERR_NETWORK_INVALID_PERMISSION_INTERNET':
          friendly = 'Missing or invalid Android permission (ACCESS_WIFI_STATE) required to read network info.';
          break;
        case 'ERR_NETWORK_NO_ACCESS_NETWORKINFO':
          friendly = 'Unable to access network information on this device or platform.';
          break;
        default:
          // Preserve original message when available.
          friendly = err.message ?? String(err);
      }

      setError(`${err.code ?? 'ERROR'}: ${friendly}`);
    } finally {
      setLoading(false);
    }
  };

  return (
    <View style={styles.container}>
      <Button title={loading ? 'Fetching...' : 'Get MAC / IP Address'} onPress={fetchAddress} disabled={loading} />

      {result && (
        <Text style={styles.result}>
          {result.kind === 'mac' ? 'MAC Address: ' : 'IP Address: '}
          {result.value}
        </Text>
      )}

      {error && <Text style={styles.error}>Error: {error}</Text>}

      <Text style={styles.note}>
        Note: Some Expo SDK versions do not expose getMacAddressAsync on the typed module. This component first tries
        to call it dynamically and otherwise falls back to getIpAddressAsync. Error codes from the Expo docs are mapped
        to friendly messages.
      </Text>
    </View>
  );
}

const styles = StyleSheet.create({
  container: { padding: 16 },
  result: { marginTop: 12, fontSize: 16, color: '#111' },
  error: { marginTop: 12, color: 'red' },
  note: { marginTop: 16, fontSize: 12, color: '#666' },
});

