import React, { useRef, useState } from 'react';
import {
  Animated,
  EmitterSubscription,
  LayoutRectangle,
  Platform,
  StyleSheet,
  View,
  Image as RNImage,
  Text,
  Pressable,
  NativeSyntheticEvent,
  LayoutChangeEvent,
} from 'react-native';
import { Host, HStack, VStack } from '@expo/ui/swift-ui';

type Layout = LayoutRectangle | null;

export default function MatchedGeometryLikeExample(): JSX.Element {
  const [expanded, setExpanded] = useState(false);
  const [thumbLayout, setThumbLayout] = useState<Layout>(null);
  const [targetLayout, setTargetLayout] = useState<Layout>(null);

  // animated value 0 -> thumbnail, 1 -> expanded
  const t = useRef(new Animated.Value(0)).current;

  // measure handlers
  function onThumbLayout(e: LayoutChangeEvent) {
    setThumbLayout(e.nativeEvent.layout);
  }
  function onTargetLayout(e: LayoutChangeEvent) {
    setTargetLayout(e.nativeEvent.layout);
  }

  // start expand/collapse animation
  function toggle() {
    const toValue = expanded ? 0 : 1;
    setExpanded((s) => !s);
    Animated.spring(t, {
      toValue,
      useNativeDriver: false, // animating layout-like properties
      bounciness: 8,
    }).start();
  }

  // source image
  const uri = 'https://placekitten.com/400/400';

  // derive animated styles only if we have measurements
  const animatedStyle = (() => {
    if (!thumbLayout || !targetLayout) {
      // fallback: scale from center of thumbnail
      const fallbackScale = t.interpolate({ inputRange: [0, 1], outputRange: [1, 2.2] });
      const fallbackTranslateY = t.interpolate({ inputRange: [0, 1], outputRange: [0, -40] });
      return {
        transform: [{ translateY: fallbackTranslateY }, { scale: fallbackScale }],
      } as const;
    }

    // compute from thumb -> target (both absolute within same container)
    const fromX = thumbLayout.x;
    const fromY = thumbLayout.y;
    const fromW = thumbLayout.width;
    const fromH = thumbLayout.height;

    const toX = targetLayout.x + (targetLayout.width - targetLayout.width) / 2; // center math (kept straightforward)
    const toY = targetLayout.y;
    const toW = targetLayout.width;
    const toH = targetLayout.height;

    // Interpolate left, top, width, height
    const left = t.interpolate({ inputRange: [0, 1], outputRange: [fromX, toX] });
    const top = t.interpolate({ inputRange: [0, 1], outputRange: [fromY, toY] });
    const width = t.interpolate({ inputRange: [0, 1], outputRange: [fromW, toW] });
    const height = t.interpolate({ inputRange: [0, 1], outputRange: [fromH, toH] });

    // Return animated style using absolute positioning
    return {
      position: 'absolute' as const,
      left,
      top,
      width,
      height,
      borderRadius: t.interpolate({ inputRange: [0, 1], outputRange: [fromW / 8, 12] }),
      overflow: 'hidden' as const,
    };
  })();

  return (
    <Host>
      <VStack spacing={16} style={styles.container}>
        <HStack spacing={12} style={styles.row}>
          <Text style={styles.title}>Matched-geometry-like transition</Text>
        </HStack>

        {/* Target area (where expanded image will end up). Measure it for interpolation. */}
        <View onLayout={onTargetLayout} style={styles.targetArea} pointerEvents="none">
          <Text style={styles.targetLabel}>Expanded area</Text>
        </View>

        <HStack spacing={16} style={styles.row}>
          {/* Thumbnail - measure its layout */}
          <Pressable onPress={toggle} onLayout={onThumbLayout} style={styles.thumbWrapper}>
            <RNImage source={{ uri }} style={styles.thumbImage} resizeMode="cover" />
          </Pressable>

          <VStack spacing={8} style={{ flex: 1 }}>
            <Text numberOfLines={2}>Tap the thumbnail to expand into the target area above. This uses React Native Animated to simulate matched geometry effects without Namespace.</Text>
            <Pressable onPress={toggle} style={styles.button} accessibilityRole="button">
              <Text style={styles.buttonText}>{expanded ? 'Collapse' : 'Expand'}</Text>
            </Pressable>
          </VStack>
        </HStack>

        {/* Animated overlay: drawn above everything to animate from thumb -> target */}
        <View pointerEvents="box-none" style={StyleSheet.absoluteFill}>
          {/* Render only when either measurement exists to avoid flicker */}
          {(thumbLayout || targetLayout) && (
            <Animated.View style={animatedStyle}>
              <RNImage source={{ uri }} style={styles.fullImage} resizeMode="cover" />
            </Animated.View>
          )}
        </View>
      </VStack>
    </Host>
  );
}

