import React, { useState } from 'react';
import { Button, Image, View, Text } from 'react-native';
import * as ImagePicker from 'expo-image-picker';

export default function App() {
  const [image, setImage] = useState<string | null>(null);
  const [permissionStatus, requestPermission] = ImagePicker.useMediaLibraryPermissions();

  const pickImage = async () => {
    if (!permissionStatus?.granted) {
      const { granted } = await requestPermission();
      if (!granted) {
        alert('Media library permission is required!');
        return;
      }
    }
    const result = await ImagePicker.launchImageLibraryAsync({
      mediaTypes: ImagePicker.MediaTypeOptions.Images,
      allowsEditing: false,
      quality: 1,
    });
    if (!result.canceled && result.assets.length > 0) {
      setImage(result.assets[0].uri);
    }
  };

  return (
    <View style={{ flex: 1, alignItems: 'center', justifyContent: 'center' }}>
      <Button title="Pick an image from library" onPress={pickImage} />
      {image && <Image source={{ uri: image }} style={{ width: 200, height: 200, marginTop: 20 }} />}
      {!permissionStatus?.granted && (
        <Text style={{ color: 'red', marginTop: 10 }}>Media library permission not granted.</Text>
      )}
    </View>
  );
}

import crypto from 'crypto';

/**
 * Verify an Expo EAS webhook HMAC-SHA1 signature.
 *
 * - signatureHeader is the value of the request header (e.g. req.headers['expo-signature'])
 *   It may be either a raw hex string or prefixed like `sha1=...`.
 * - rawBody must be the raw request body bytes (string or Buffer). Many frameworks
 *   require a middleware to expose the raw body; if not available this falls back
 *   to JSON.stringify(req.body) which is less robust but common in simple setups.
 *
 * Returns true if the signature matches the HMAC-SHA1 digest of rawBody using secret.
 */
export function verifyEasWebhookSignature(
  rawBody: string | Buffer,
  signatureHeader: string | undefined | null,
  secret: string
): boolean {
  if (!signatureHeader) return false;

  // Normalize header: accept both `sha1=<hex>` and raw hex
  const match = signatureHeader.match(/^(?:sha1=)?([a-f0-9]+)$/i);
  if (!match) return false;
  const sigHex = match[1];

  // Compute HMAC-SHA1 of the raw body
  const hmac = crypto.createHmac('sha1', secret);
  if (Buffer.isBuffer(rawBody)) {
    hmac.update(rawBody);
  } else {
    hmac.update(Buffer.from(rawBody, 'utf8'));
  }
  const digestHex = hmac.digest('hex');

  try {
    const a = Buffer.from(digestHex, 'hex');
    const b = Buffer.from(sigHex, 'hex');
    if (a.length !== b.length) return false;
    // Use timingSafeEqual to avoid timing attacks
    return crypto.timingSafeEqual(a, b);
  } catch (err) {
    // If hex decoding fails or any other error, treat as invalid
    return false;
  }
}

/**
 * Helper to create an Express-compatible handler. It avoids framework-specific types
 * so it can be dropped into most Node/Express/Serverless handlers. The handler expects
 * the raw body to be available on `req.rawBody` (Buffer or string). If not present
 * it falls back to JSON.stringify(req.body).
 *
 * Usage (Express):
 *   // In Express you must capture the raw body. Example middleware before bodyParser:
 *   // app.use((req, _, next) => { let data = Buffer.alloc(0); req.on('data', c => data = Buffer.concat([data, c])); req.on('end', () => { req.rawBody = data; next(); }); });
 *   app.post('/eas-webhook', createEasWebhookHandler('EXPO_WEBHOOK_SECRET'));
 */
export function createEasWebhookHandler(envVarName = 'EXPO_WEBHOOK_SECRET') {
  return async function handler(req: any, res: any) {
    const secret = process.env[envVarName];
    if (!secret) {
      res.statusCode = 500;
      return res.json?.({ error: 'Webhook secret not configured' }) ?? res.end('Webhook secret not configured');
    }

    // Prefer a raw buffer if provided by middleware; otherwise stringify the parsed body
    let rawBody: string | Buffer;
    if (typeof req.rawBody !== 'undefined') {
      rawBody = req.rawBody;
    } else if (typeof req.body === 'string') {
      rawBody = req.body;
    } else {
      rawBody = JSON.stringify(req.body ?? {});
    }

    const signatureHeader = (req.headers && (req.headers['expo-signature'] || req.headers['x-expo-signature'])) ?? undefined;

    if (!verifyEasWebhookSignature(rawBody, Array.isArray(signatureHeader) ? String(signatureHeader[0]) : signatureHeader, secret)) {
      res.statusCode = 401;
      return res.json?.({ error: 'Invalid signature' }) ?? res.end('Invalid signature');
    }

    // At this point the request is verified. Parse payload if needed and handle it.
    // The payload is typically the JSON body. If rawBody was used, parse it safely.
    let payload: any = req.body;
    if (typeof payload === 'undefined') {
      try {
        payload = typeof rawBody === 'string' ? JSON.parse(rawBody) : JSON.parse(rawBody.toString('utf8'));
      } catch {
        payload = null; // keep null if parsing fails
      }
    }

    // Example: respond and let caller handle actual processing
    res.statusCode = 200;
    return res.json?.({ received: true, payload }) ?? res.end('received');
  };
}

export default { verifyEasWebhookSignature, createEasWebhookHandler };

