import React from 'react';
import { View, Button, StyleSheet } from 'react-native';
import Animated, {
  useSharedValue,
  useAnimatedStyle,
  withTiming,
  Easing,
} from 'react-native-reanimated';

// This example shows how to reproduce a CSS-like transitionTimingFunction
// by passing a custom easing function (e.g. cubic-bezier) to withTiming's config.
// The cubic-bezier(0.4, 0, 0.2, 1) curve below matches a common ease-in-out curve.

export default function App(): JSX.Element {
  const offset = useSharedValue(0);
  const toggled = React.useRef(false);

  const animatedStyle = useAnimatedStyle(() => ({
    transform: [{ translateX: offset.value }],
  }));

  const onToggle = () => {
    toggled.current = !toggled.current;
    const toValue = toggled.current ? 150 : 0;

    // Provide duration and an easing function. Easing.bezier(...) maps to cubic-bezier(...).
    offset.value = withTiming(toValue, {
      duration: 600,
      easing: Easing.bezier(0.4, 0, 0.2, 1),
    });
  };

  return (
    <View style={styles.container}>
      <View style={styles.boxContainer}>
        <Animated.View style={[styles.box, animatedStyle]} />
      </View>
      <Button title="Toggle" onPress={onToggle} />
    </View>
  );
}

