// Map Apple Authorization error codes (matches Apple Authorization error list)
const getErrorMessage = (code: string) => {
  switch (code) {
    case 'ERR_INVALID_OPERATION':
      return 'Invalid authorization operation.';
    case 'ERR_INVALID_RESPONSE':
      return 'The authorization request returned an invalid response.';
    case 'ERR_INVALID_SCOPE':
      return 'An invalid scope was requested for Apple Authentication.';
    case 'ERR_REQUEST_CANCELED':
      return 'The user canceled the authorization request.';
    case 'ERR_REQUEST_FAILED':
      return 'The authorization attempt failed. See the error message for details.';
    case 'ERR_REQUEST_NOT_HANDLED':
      return 'The authorization request was not handled correctly by the app.';
    case 'ERR_REQUEST_NOT_INTERACTIVE':
      return 'The authorization request is not interactive (cannot prompt the user).';
    case 'ERR_REQUEST_UNKNOWN':
      return 'An unknown authorization error occurred.';
    default:
      return code ? `Apple sign-in error: ${code}` : 'An unknown Apple sign-in error occurred.';
  }
};

type SignInFn = () => Promise<unknown>;

type Props = {
  // Optional: pass in the actual Apple sign-in function (e.g. AppleAuthentication.signInAsync)
  signIn?: SignInFn;
  label?: string;
};

export default function AppleSignInButton({ signIn, label = 'Sign in with Apple' }: Props) {
  const handlePress = useCallback(async () => {
    try {
      if (!signIn) {
        Alert.alert('Not configured', 'No signIn function provided. Pass the Apple sign-in function via the `signIn` prop.');
        return;
      }
      await signIn();
      Alert.alert('Success', 'Signed in with Apple');
    } catch (error: unknown) {
      // The Apple Authentication libraries typically put a short code on error.code
      // Fall back to reading .message when code is not present
      const e: any = error as any;
      const code = typeof e?.code === 'string' ? e.code : '';
      const message = getErrorMessage(code);
      // Provide both high-level message and any underlying error text for debugging
      const details = typeof e?.message === 'string' && e.message !== code ? `\n\nDetails: ${e.message}` : '';
      Alert.alert('Apple Sign-In Error', message + details);
    }
  }, [signIn]);

  return (
    <View style={styles.container}>
      <TouchableOpacity onPress={handlePress} activeOpacity={0.85} style={styles.button}>
        <Text style={styles.buttonText}>{label}</Text>
      </TouchableOpacity>
    </View>
  );
}

