const CMS_API_URL = 'https://example-cms.com/api/posts'; // Replace with your CMS endpoint

type Post = {
  id: string | number;
  title: string;
  body: string;
  [key: string]: any;
};

export default function BlogPostsScreen(): JSX.Element {
  const [posts, setPosts] = useState<Post[]>([]);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let mounted = true;

    async function fetchPosts(): Promise<void> {
      try {
        const res = await fetch(CMS_API_URL);
        if (!res.ok) {
          throw new Error(`Network response was not ok (${res.status})`);
        }
        const json = await res.json();

        // Support a few common shapes: array, { posts: [...] }, { data: [...] }
        let items: Post[] = [];
        if (Array.isArray(json)) items = json;
        else if (Array.isArray(json.posts)) items = json.posts;
        else if (Array.isArray(json.data)) items = json.data;

        if (mounted) {
          setPosts(items);
          setError(items.length === 0 ? 'No posts available.' : null);
        }
      } catch (err: unknown) {
        if (!mounted) return;
        const message = err instanceof Error ? err.message : String(err);
        setError(`Failed to load posts: ${message}`);
      } finally {
        if (mounted) setLoading(false);
      }
    }

    fetchPosts();

    return () => {
      mounted = false;
    };
  }, []);

  if (loading) {
    return (
      <SafeAreaView style={styles.centered}>
        <ActivityIndicator size="large" />
      </SafeAreaView>
    );
  }

  if (error) {
    return (
      <SafeAreaView style={styles.centered}>
        <Text style={styles.errorText}>{error}</Text>
      </SafeAreaView>
    );
  }

  const renderItem = ({ item }: ListRenderItemInfo<Post>) => (
    <View style={styles.postContainer}>
      <Text style={styles.title}>{item.title}</Text>
      <Text style={styles.body}>{item.body}</Text>
    </View>
  );

  return (
    <SafeAreaView style={styles.container}>
      <FlatList<Post>
        data={posts}
        keyExtractor={(item, index) => (item && item.id != null ? String(item.id) : String(index))}
        renderItem={renderItem}
        contentContainerStyle={styles.list}
        ItemSeparatorComponent={() => <View style={styles.separator} />}
      />
    </SafeAreaView>
  );
}

