import { Magnetometer } from 'expo-sensors';

export default function MagnetometerExample() {
  const [data, setData] = useState({ x: 0, y: 0, z: 0 });
  const [subscription, setSubscription] = useState<null | { remove: () => void }>(null);

  const subscribe = () => {
    setSubscription(
      Magnetometer.addListener(result => {
        setData(result);
      })
    );
  };

  const unsubscribe = () => {
    subscription && subscription.remove();
    setSubscription(null);
  };

  useEffect(() => {
    subscribe();
    return () => unsubscribe();
  }, []);

  return (
    <View style={styles.container}>
      <Text style={styles.text}>Magnetometer:</Text>
      <Text style={styles.text}>
        x: {data.x.toFixed(2)} y: {data.y.toFixed(2)} z: {data.z.toFixed(2)}
      </Text>
      <View style={styles.buttonContainer}>
        <Button title={subscription ? 'Unsubscribe' : 'Subscribe'} onPress={subscription ? unsubscribe : subscribe} />
      </View>
    </View>
  );
}

