import React, { useEffect } from 'react';
import { Alert, Button, Platform, StyleSheet, Text, View } from 'react-native';
import * as Calendar from 'expo-calendar';

type LocalSource = { isLocalAccount: boolean; name: string };

async function getDefaultCalendarSource(): Promise<Calendar.Source | undefined> {
  // getDefaultCalendarAsync may return undefined in some environments; guard accordingly
  try {
    const defaultCalendar = await Calendar.getDefaultCalendarAsync();
    return defaultCalendar?.source;
  } catch (e) {
    console.warn('Could not get default calendar source', e);
    return undefined;
  }
}

async function createCalendar(): Promise<void> {
  try {
    // On iOS, use the real Source returned by the API. On Android, provide a minimal local source object.
    const sourceOrLocal: Calendar.Source | LocalSource | undefined =
      Platform.OS === 'ios'
        ? await getDefaultCalendarSource()
        : { isLocalAccount: true, name: 'Expo Calendar' };

    // Build params conditionally so TypeScript doesn't complain about missing `id` on the Android branch.
    const baseParams: any = {
      title: 'Expo Calendar',
      color: 'blue',
      entityType: Calendar.EntityTypes.EVENT,
      name: 'internalCalendarName',
      ownerAccount: 'personal',
      accessLevel: Calendar.CalendarAccessLevel.OWNER,
    };

    // If sourceOrLocal is a Calendar.Source with an id, include sourceId + source. Otherwise include only source.
    if (sourceOrLocal && 'id' in sourceOrLocal && typeof (sourceOrLocal as any).id === 'string') {
      baseParams.sourceId = (sourceOrLocal as Calendar.Source).id;
      baseParams.source = sourceOrLocal as Calendar.Source;
    } else if (sourceOrLocal) {
      // Android/local fallback: pass the minimal source object
      baseParams.source = sourceOrLocal as LocalSource;
    }

    const newCalendarID = await Calendar.createCalendarAsync(baseParams);
    Alert.alert('Calendar Created', `Your new calendar ID is: ${newCalendarID}`);
  } catch (error) {
    console.error('Error creating calendar', error);
    Alert.alert('Error', 'Could not create calendar. Check console for details.');
  }
}

export default function CreateCalendarExample(): JSX.Element {
  useEffect(() => {
    (async () => {
      try {
        const { status } = await Calendar.requestCalendarPermissionsAsync();
        if (status !== 'granted') {
