        }
      } catch (e) {
        console.warn('Permission request failed', e);
      }
    })();
  }, []);

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Create a New Calendar</Text>
      <Button title="Create Calendar" onPress={createCalendar} />
    </View>
  );
}

