import React from 'react';
import { View, Text, StyleSheet, ViewStyle } from 'react-native';

type Alignment =
  | 'center'
  | 'leading'
  | 'trailing'
  | 'top'
  | 'bottom'
  | 'topLeading'
  | 'topTrailing'
  | 'bottomLeading'
  | 'bottomTrailing';

function alignmentToStyle(a: Alignment): ViewStyle {
  switch (a) {
    case 'leading':
      return { justifyContent: 'center', alignItems: 'flex-start' };
    case 'trailing':
      return { justifyContent: 'center', alignItems: 'flex-end' };
    case 'top':
      return { justifyContent: 'flex-start', alignItems: 'center' };
    case 'bottom':
      return { justifyContent: 'flex-end', alignItems: 'center' };
    case 'topLeading':
      return { justifyContent: 'flex-start', alignItems: 'flex-start' };
    case 'topTrailing':
      return { justifyContent: 'flex-start', alignItems: 'flex-end' };
    case 'bottomLeading':
      return { justifyContent: 'flex-end', alignItems: 'flex-start' };
    case 'bottomTrailing':
      return { justifyContent: 'flex-end', alignItems: 'flex-end' };
    case 'center':
    default:
      return { justifyContent: 'center', alignItems: 'center' };
  }
}

export function ZStack({
  children,
  alignment = 'center',
}: {
  children: React.ReactNode;
  alignment?: Alignment;
}) {
  const childrenArray = React.Children.toArray(children);
  if (childrenArray.length === 0) return null;

  // First child renders normally to establish intrinsic size. Remaining children
  // are absolutely positioned over it and aligned according to `alignment`.
  const first = childrenArray[0];
  const overlays = childrenArray.slice(1);
  const alignStyle = alignmentToStyle(alignment);

  return (
    <View style={styles.container}>
      {first}
      {overlays.map((child, i) => (
        <View key={i} style={[styles.overlayFill, alignStyle]} pointerEvents="box-none">
          {child}
        </View>
      ))}
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    position: 'relative',
  },
  overlayFill: {
    position: 'absolute',
    top: 0,
    left: 0,
    right: 0,
    bottom: 0,
  },
});

