import React, { useState, useMemo } from 'react';
import {
  View,
  Text,
  StyleSheet,
  Pressable,
  ViewStyle,
  TextStyle,
  ColorValue,
} from 'react-native';

type SegmentedControlProps = {
  values: string[];
  selectedIndex?: number; // controlled if provided
  onChange?: (index: number) => void;
  containerStyle?: ViewStyle;
  segmentStyle?: ViewStyle;
  selectedTextColor?: ColorValue;
  textStyle?: TextStyle;
};

function SegmentedControl({
  values,
  selectedIndex: selectedIndexProp,
  onChange,
  containerStyle,
  segmentStyle,
  selectedTextColor = '#fff',
  textStyle,
}: SegmentedControlProps) {
  // support controlled or uncontrolled usage
  const [internalIndex, setInternalIndex] = useState(0);
  const isControlled = typeof selectedIndexProp === 'number';
  const selectedIndex = isControlled ? (selectedIndexProp as number) : internalIndex;

  const handlePress = (index: number) => {
    if (!isControlled) setInternalIndex(index);
    onChange?.(index);
  };

  const segments = useMemo(() => values.map((v, i) => ({ label: v, index: i })), [values]);

  return (
    <View style={[styles.segmentedContainer, containerStyle]} accessible accessibilityRole="tablist">
      {segments.map(({ label, index }) => {
        const selected = index === selectedIndex;
        return (
          <Pressable
            key={label + index}
            onPress={() => handlePress(index)}
            accessibilityRole="tab"
            accessibilityState={{ selected }}
            style={({ pressed }) => [
              styles.segment,
              segmentStyle,
              selected ? styles.segmentSelected : styles.segmentUnselected,
              // slight pressed feedback
              pressed && { opacity: 0.8 },
              // rounded ends for first/last
              index === 0 && styles.leftRadius,
              index === segments.length - 1 && styles.rightRadius,
            ]}
          >
            <Text style={[styles.segmentText, textStyle, selected && { color: selectedTextColor }]}>{label}</Text>
          </Pressable>
        );
      })}
    </View>
  );
}

export default function App() {
  const options = ['First', 'Second', 'Third'];
  const [selected, setSelected] = useState(0);

  return (
    <View style={styles.appContainer}>
      <Text style={styles.title}>Segmented Control Demo</Text>
      <SegmentedControl
        values={options}
        selectedIndex={selected}
        onChange={index => setSelected(index)}
        containerStyle={{ width: '90%' }}
      />
      <Text style={styles.selectionText}>Selected: {options[selected]}</Text>

      {/* Example: uncontrolled usage (omit selectedIndex) */}
      <View style={{ height: 24 }} />
      <Text style={styles.subtitle}>Uncontrolled example</Text>
      <SegmentedControl
        values={['One', 'Two']}
        onChange={index => console.log('Uncontrolled selected', index)}
        containerStyle={{ width: 220 }}
      />
    </View>
  );
}

