};

type SubscriptionLike = { remove: () => void };

export default function DeviceMotionExample(): JSX.Element {
  const [data, setData] = useState<MotionData | null>(null);
  const [subscription, setSubscription] = useState<SubscriptionLike | null>(null);

  // Request permissions on iOS if available, then subscribe.
  const subscribe = async () => {
    try {
      // Some SDK versions expose requestPermissionsAsync on the DeviceMotion module.
      if (Platform.OS === 'ios' && typeof (DeviceMotion as any).requestPermissionsAsync === 'function') {
        // the return shape can vary by SDK; defensively handle both { status } and { granted }
        const perm = await (DeviceMotion as any).requestPermissionsAsync();
        const status = perm?.status ?? (perm?.granted ? 'granted' : 'denied');
        if (status !== 'granted' && status !== 'granted') {
          Alert.alert('Permission required', 'Device motion permission was not granted.');
          return;
        }
      }

      // Set update interval if available. Accept either sync or async setter names.
      if (typeof (DeviceMotion as any).setUpdateInterval === 'function') {
        (DeviceMotion as any).setUpdateInterval(500); // ms
      } else if (typeof (DeviceMotion as any).setUpdateIntervalAsync === 'function') {
        await (DeviceMotion as any).setUpdateIntervalAsync(500);
      }

      // Add listener. Some SDKs return a subscription with remove().
      const sub: SubscriptionLike = (DeviceMotion as any).addListener((motion: MotionData) => {
        setData(motion);
      });

      setSubscription(sub);
    } catch (error) {
      console.error('Failed to subscribe to DeviceMotion:', error);
      Alert.alert('Error', 'Unable to start device motion updates.');
    }
  };

  const unsubscribe = () => {
    if (subscription) {
      try {
        subscription.remove();
      } catch (e) {
        // ignore remove errors
      }
      setSubscription(null);
      setData(null);
    }
  };

  useEffect(() => {
    // clean up on unmount
    return () => unsubscribe();
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  const fmt = (n?: number) => (n === undefined || n === null ? '—' : n.toFixed(2));

  return (
    <View style={styles.container}>
      <View style={styles.buttonRow}>
        <Button title={subscription ? 'Stop' : 'Start'} onPress={subscription ? unsubscribe : subscribe} />
      </View>

      <View style={styles.section}>
        <Text style={styles.label}>Rotation</Text>
        <Text style={styles.value}>
          alpha: {fmt(data?.rotation?.alpha)}  beta: {fmt(data?.rotation?.beta)}  gamma: {fmt(data?.rotation?.gamma)}
        </Text>
      </View>

      <View style={styles.section}>
        <Text style={styles.label}>Acceleration</Text>
        <Text style={styles.value}>
          x: {fmt(data?.acceleration?.x)}  y: {fmt(data?.acceleration?.y)}  z: {fmt(data?.acceleration?.z)}
        </Text>
      </View>

      <View style={styles.section}>
        <Text style={styles.label}>Gravity</Text>
        <Text style={styles.value}>
          x: {fmt(data?.gravity?.x)}  y: {fmt(data?.gravity?.y)}  z: {fmt(data?.gravity?.z)}
        </Text>
      </View>

      <View style={styles.section}>
        <Text style={styles.label}>Orientation</Text>
        <Text style={styles.value}>{data?.orientation ?? '—'}</Text>
      </View>
    </View>
  );
}

