import React, { useEffect } from 'react';
import { View, StyleSheet } from 'react-native';
import Animated, {
  useSharedValue,
  useAnimatedProps,
  interpolateColor,
  processColor,
  withTiming,
  withRepeat,
} from 'react-native-reanimated';

// A tiny, strongly-typed custom component that accepts a "colors" prop.
// Use a permissive type for "colors" because processColor can return numbers
// (platform-processed colors) or arrays of such values.
interface BoxProps {
  colors?: any;
}

const Box: React.FC<BoxProps> = ({ colors }) => {
  // colors may be an array of processed color values or a single value.
  let backgroundColor: any = undefined;
  if (Array.isArray(colors) && colors.length > 0) {
    backgroundColor = colors[0];
  } else if (colors != null) {
    backgroundColor = colors;
  }

  // Cast to any to satisfy React Native style typing when using processed colors.
  return <View style={[styles.box, { backgroundColor: backgroundColor as any }]} />;
};

// Create an Animated version of the custom component. Passing animatedProps to
// this component will update the `colors` prop on the native side.
const AnimatedBox = Animated.createAnimatedComponent(Box);

export default function App(): JSX.Element {
  const colorProgress = useSharedValue(0);

  // animate the progress back and forth
  useEffect(() => {
    colorProgress.value = withRepeat(withTiming(1, { duration: 2000 }), -1, true);
  }, [colorProgress]);

  // Tell TypeScript the shape of the animated props we will return.
  const animatedProps = useAnimatedProps<Partial<{ colors: any }>>(() => {
    const mainColor = interpolateColor(colorProgress.value, [0, 1], ['#ff0000', '#0000ff']);
    const bgColor = interpolateColor(colorProgress.value, [0, 1], ['#00ff00', '#ffff00']);

    // This prop name (`colors`) is custom — it's not automatically processed by
    // Reanimated, so wrap it with processColor so the native side will receive
    // platform-friendly color values.
    return {
      colors: processColor([mainColor, bgColor]),
    };
  });

  return (
    <AnimatedBox
      // animatedProps is how createAnimatedComponent receives per-frame props
      // for custom prop keys. The component will receive `colors` with the
      // processed value on the native side.
      animatedProps={animatedProps}
    />
  );
}

