import React from 'react';
import { View, Image, ActivityIndicator, StyleSheet } from 'react-native';
import { useIncomingShare } from 'expo-sharing';

// Helper to safely extract a usable URI from various possible payload shapes
function getUriFromPayload(payload: unknown): string | undefined {
  const p = payload as any;
  if (!p) return undefined;

  // Common possible fields where an image URI may live
  if (typeof p.uri === 'string') return p.uri;
  if (typeof p.url === 'string') return p.url;
  if (typeof p.localUri === 'string') return p.localUri;

  // Some payloads include a file or files array
  if (p.file && typeof p.file.uri === 'string') return p.file.uri;
  if (Array.isArray(p.files) && p.files.length > 0 && typeof p.files[0]?.uri === 'string') {
    return p.files[0].uri;
  }

  // Fallback: some resolved payloads put the data on a `data` field (could be base64 or a path)
  if (typeof p.data === 'string' && (p.data.startsWith('file://') || p.data.startsWith('data:'))) {
    return p.data;
  }

  return undefined;
}

export default function ShareReceived(): JSX.Element {
  const { resolvedSharedPayloads, isResolving } = useIncomingShare();

  if (isResolving) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" />
      </View>
    );
  }

  return (
    <View style={styles.container}>
      {resolvedSharedPayloads.map((payload, index) => {
        // Guard on contentType if present; otherwise attempt to extract a URI and try rendering
        const contentType = (payload as any)?.contentType as string | undefined;
        const looksLikeImage = typeof contentType === 'string' ? contentType.startsWith('image') : undefined;

        const uri = getUriFromPayload(payload);
        if ((looksLikeImage === undefined && uri) || looksLikeImage) {
          if (!uri) return null; // nothing to render if we couldn't resolve a URI
          return (
            <Image
              key={index}
              source={{ uri }}
              style={styles.image}
              resizeMode="contain"
            />
          );
        }

        return null;
      })}
    </View>
  );
}

