  const handleCreateAndWrite = async (): Promise<void> => {
    try {
      // writeAsStringAsync creates the file if it doesn't exist
      await FileSystem.writeAsStringAsync(fileUri, 'Hello, world!', {
        encoding: FileSystem.EncodingType.UTF8,
      });
      Alert.alert('Success', 'File created and written!');
    } catch (error) {
      Alert.alert('Error', String(error));
    }
  };

  const handleRead = async (): Promise<void> => {
    try {
      const info = await FileSystem.getInfoAsync(fileUri);
      if (!info.exists) {
        Alert.alert('Not found', 'The file does not exist.');
        return;
      }
      const text = await FileSystem.readAsStringAsync(fileUri, {
        encoding: FileSystem.EncodingType.UTF8,
      });
      setContent(text);
    } catch (error) {
      Alert.alert('Error', String(error));
    }
  };

  const handleDelete = async (): Promise<void> => {
    try {
      const info = await FileSystem.getInfoAsync(fileUri);
      if (!info.exists) {
        Alert.alert('Info', 'No file to delete.');
        return;
      }
      await FileSystem.deleteAsync(fileUri, { idempotent: true });
      setContent('');
      Alert.alert('Deleted', 'File deleted successfully.');
    } catch (error) {
      Alert.alert('Error', String(error));
    }
  };

  return (
    <View style={styles.container}>
      <Button title="Create & Write File" onPress={handleCreateAndWrite} />
      <View style={styles.spacer} />
      <Button title="Read File" onPress={handleRead} />
      <View style={styles.spacer} />
      <Button title="Delete File" onPress={handleDelete} />
      <Text style={styles.text}>File Content: {content}</Text>
    </View>
  );
}

