import { ExpoConfig } from '@expo/config-types';

// A lightweight config-plugin-style function that ensures the
// "expo-router" plugin is present with sitemap: false.
// Place this file in your project (e.g., tools/withDisableSitemap.ts)
// and reference it from app.config.js or app.json plugin resolution if desired.

type ExpoPluginEntry = string | [string, Record<string, unknown>];

export default function withDisableExpoRouterSitemap(config: ExpoConfig): ExpoConfig {
  const pluginName = 'expo-router';
  const desiredEntry: ExpoPluginEntry = [pluginName, { sitemap: false }];

  const existingPlugins = Array.isArray(config.plugins) ? [...config.plugins] : [];

  // Remove any existing expo-router entries so we can replace with our desired config
  const filtered = existingPlugins.filter((entry) => {
    if (typeof entry === 'string') return entry !== pluginName;
    if (Array.isArray(entry) && entry.length > 0) return entry[0] !== pluginName;
    return true;
  });

  filtered.push(desiredEntry);

  return {
    ...config,
    plugins: filtered,
  };
}

