import React, { useEffect, useState } from 'react';
import { View, Text, ActivityIndicator, StyleSheet, Dimensions, ScrollView } from 'react-native';

type UsagePoint = { date: string; count: number };

type Props = {
  apiUrl?: string; // e.g. 'https://expo.dev/accounts/[account]/projects/[project]/deployments/production/[runtime-version]/stats'
  maxBarsToShow?: number; // limit number of bars shown for small screens
};

const DEFAULT_API = 'https://expo.dev/accounts/[account]/projects/[project]/deployments/production/[runtime-version]/stats';

export default function UpdateUsageChart({ apiUrl = DEFAULT_API, maxBarsToShow = 30 }: Props) {
  const [usage, setUsage] = useState<UsagePoint[] | null>(null);
  const [loading, setLoading] = useState<boolean>(true);
  const [error, setError] = useState<string | null>(null);

  useEffect(() => {
    let mounted = true;
    setLoading(true);
    setError(null);

    fetch(apiUrl)
      .then((res) => {
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        return res.json();
      })
      .then((json) => {
        // The deployments page does not provide a stable public JSON API documented here.
        // Typical shape assumed for this UI: { usage: [{ date: '2026-03-20', count: 12 }, ...] }
        const raw: any = json;
        const list: UsagePoint[] = Array.isArray(raw?.usage)
          ? raw.usage.map((u: any) => ({ date: String(u.date ?? ''), count: Number(u.count ?? 0) }))
          : [];

        if (mounted) {
          setUsage(list);
          setLoading(false);
        }
      })
      .catch((e) => {
        if (mounted) {
          setError('Failed to load stats');
          setUsage(null);
          setLoading(false);
        }
      });

    return () => {
      mounted = false;
    };
  }, [apiUrl]);

  if (loading) return <ActivityIndicator style={styles.centered} />;
  if (error) return <Text style={[styles.centered, styles.error]}>{error}</Text>;
  if (!usage || usage.length === 0) return <Text style={[styles.centered]}>No usage data available.</Text>;

  // Keep most recent data and limit to maxBarsToShow
  const sorted = [...usage].sort((a, b) => (a.date < b.date ? -1 : a.date > b.date ? 1 : 0));
  const recent = sorted.slice(-maxBarsToShow);

  const counts = recent.map((u) => u.count);
  const maxCount = Math.max(...counts, 1);

  const chartHeight = 160;
  const barWidth = 28;
  const gap = 10;
  const totalWidth = recent.length * (barWidth + gap) + 16;
  const windowWidth = Math.max(Dimensions.get('window').width - 32, totalWidth);

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Update Usage Over Time</Text>
      <View style={styles.chartWrapper}>
        <View style={styles.yAxisLabelContainer}>
          <Text style={styles.yAxisLabel}>{maxCount}</Text>
        </View>
        <ScrollView horizontal contentContainerStyle={{ paddingHorizontal: 8 }} showsHorizontalScrollIndicator={false}>
          <View style={[styles.chartArea, { height: chartHeight, width: Math.max(windowWidth, totalWidth) }]}>
            {recent.map((pt, i) => {
              const height = maxCount > 0 ? Math.round((pt.count / maxCount) * chartHeight) : 0;
              const label = formatLabel(pt.date);
              return (
                <View key={i} style={{ width: barWidth, marginRight: gap, alignItems: 'center' }}>
                  <View style={styles.barBackground}>
                    <View style={[styles.barFill, { height, maxHeight: chartHeight }]} />
                  </View>
                  <Text style={styles.countLabel}>{pt.count}</Text>
                  <Text numberOfLines={1} style={styles.xLabel}>{label}</Text>
                </View>
              );
            })}
          </View>
        </ScrollView>
      </View>
      <Text style={styles.note}>Data shown is the number of users who ran each update (per deployments page).</Text>
    </View>
  );
}

function formatLabel(dateStr: string) {
  // Attempt to return MM-DD for ISO-like dates, otherwise return the raw string cropped
  if (!dateStr) return '';
  const isoMatch = dateStr.match(/^(\d{4})-(\d{2})-(\d{2})/);
  if (isoMatch) return `${isoMatch[2]}-${isoMatch[3]}`;
  return dateStr.length > 6 ? dateStr.slice(0, 6) : dateStr;
}

