  labelStyle,
}: DisclosureGroupProps) {
  // Determine if component is controlled
  const controlled = typeof isExpanded === 'boolean';
  const [expanded, setExpanded] = useState<boolean>(controlled ? (isExpanded as boolean) : defaultExpanded);

  // Sync controlled prop -> internal state
  useEffect(() => {
    if (controlled) {
      setExpanded(isExpanded as boolean);
    }
  }, [isExpanded, controlled]);

  function toggle() {
    const next = !expanded;
    // animate expand/collapse
    LayoutAnimation.configureNext(LayoutAnimation.Presets.easeInEaseOut);

    if (!controlled) {
      setExpanded(next);
    }
    onChange?.(next);
  }

  const arrowStyle = [styles.arrow, { transform: [{ rotate: expanded ? '90deg' : '0deg' }] }];

  return (
    <View style={[styles.container, containerStyle]}>
      <TouchableOpacity
        activeOpacity={0.7}
        onPress={toggle}
        accessibilityRole="button"
        accessibilityState={{ expanded }}
        style={styles.labelRow}
      >
        <View style={styles.labelWrapper}>
          {typeof label === 'string' ? (
            <Text style={[styles.labelText, labelStyle]}>{label}</Text>
          ) : (
            label
          )}
        </View>
        <Text aria-hidden style={arrowStyle}>
          ▶
        </Text>
      </TouchableOpacity>

      {expanded ? <View style={styles.content}>{children}</View> : null}
    </View>
  );
}

