import React, { useState } from 'react';
import { View, Text, Button, FlatList, Alert, ActivityIndicator, StyleSheet } from 'react-native';
import * as Updates from 'expo-updates';

const CHANNELS = [
  { key: 'preview', name: 'Preview Channel' },
  { key: 'staging', name: 'Staging Channel' },
  { key: 'production', name: 'Production Channel' },
];

export default function ChannelSelector(): JSX.Element {
  const [loading, setLoading] = useState(false);

  const loadChannel = async (channel: string) => {
    setLoading(true);
    try {
      // Some expo-updates versions expose a `channel` field on the module that the native layer reads.
      // TypeScript definitions may not include a setter helper like `setChannel`. Use a safe cast so this
      // compiles while still setting the runtime value when supported by the native runtime.
      (Updates as unknown as { channel?: string }).channel = channel;

      // Ask the runtime if there is an update available for the currently-configured update URL (now using the selected channel).
      const update = await Updates.checkForUpdateAsync();

      if (update.isAvailable) {
        await Updates.fetchUpdateAsync();
        // Inform the user and restart to apply the downloaded update.
        Alert.alert('Update available', 'An update was downloaded. Restart to apply it.', [
          {
            text: 'Restart now',
            onPress: () => {
              void Updates.reloadAsync();
            },
          },
          { text: 'Later', style: 'cancel' },
        ]);
      } else {
        Alert.alert('No update found', `No update was found on channel: ${channel}`);
      }
    } catch (e) {
      Alert.alert('Error checking updates', String(e));
    } finally {
      setLoading(false);
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Select Update Channel</Text>
      <FlatList
        data={CHANNELS}
        keyExtractor={(item) => item.key}
        ItemSeparatorComponent={() => <View style={styles.sep} />}
        renderItem={({ item }) => (
          <View style={styles.row}>
            <Button title={item.name} onPress={() => loadChannel(item.key)} disabled={loading} />
          </View>
        )}
        ListFooterComponent={loading ? <ActivityIndicator style={styles.loader} /> : null}
      />
      <Text style={styles.hint}>
        Tip: Use this only in preview builds. Production builds should not expose channel switching to end users.
      </Text>
    </View>
  );
}

