const getInstallReferrer = async () => {
  try {
    const referrer = await Application.getInstallReferrerAsync();
    return referrer;
  } catch (error: any) {
    // Handle specific error codes
    switch (error.code) {
      case 'ERR_APPLICATION_INSTALL_REFERRER_UNAVAILABLE':
        Alert.alert('Referrer unavailable', 'Play Store not installed or API not provided.');
        break;
      case 'ERR_APPLICATION_INSTALL_REFERRER_CONNECTION':
        Alert.alert('Connection error', 'Could not connect to the Play Store.');
        break;
      case 'ERR_APPLICATION_INSTALL_REFERRER_REMOTE_EXCEPTION':
        Alert.alert('Remote exception', 'Play Store process crashed or is unavailable.');
        break;
      default:
        Alert.alert('Unknown error', error.message || 'An unknown error occurred.');
    }
    return null;
  }
};

