export default function AnimatedChildResize() {
  const [parentWidth, setParentWidth] = useState(200);
  const childWidthPercent = 0.5; // 50% of parent
  const animatedWidth = useSharedValue(parentWidth * childWidthPercent);

  // Update animatedWidth if parent resizes after animation
  useEffect(() => {
    animatedWidth.value = parentWidth * childWidthPercent;
  }, [parentWidth]);

  const animatedStyle = useAnimatedStyle(() => ({
    width: animatedWidth.value,
    height: 50,
    backgroundColor: 'tomato',
  }));

  const handleAnimate = () => {
    animatedWidth.value = withTiming(parentWidth * 0.8, { duration: 1000 });
  };

  const handleParentLayout = (e: LayoutChangeEvent) => {
    setParentWidth(e.nativeEvent.layout.width);
  };

  return (
    <View style={styles.container}>
      <Button title="Animate Child Width" onPress={handleAnimate} />
      <View
        style={[styles.parent, { width: parentWidth }]}
        onLayout={handleParentLayout}
      >
        <Animated.View style={animatedStyle} />
      </View>
      <Button title="Resize Parent" onPress={() => setParentWidth(w => (w === 200 ? 300 : 200))} />
    </View>
  );
}

