import React from 'react';
import { View, Text, StyleSheet, ScrollView } from 'react-native';
import Animated, {
  useAnimatedRef,
  useScrollOffset,
  useDerivedValue,
  runOnJS,
} from 'react-native-reanimated';

export default function ScrollOffsetExample(): JSX.Element {
  // useAnimatedRef returns the correct AnimatedRef<T> type that useScrollOffset expects
  const scrollRef = useAnimatedRef<ScrollView>();

  // useScrollOffset accepts the animated ref returned by useAnimatedRef
  const scrollOffset = useScrollOffset(scrollRef);

  // Mirror the shared value to React state so it can be shown in a regular Text component
  // (This avoids needing animatedProps for Text in this simple example.)
  const [offsetDisplay, setOffsetDisplay] = React.useState<number>(0);

  // useDerivedValue runs on the UI thread; use runOnJS to update React state safely
  useDerivedValue(() => {
    // Format on UI thread, then pass a primitive to runOnJS to avoid extra bridging
    const val = Number(scrollOffset.value.toFixed(2));
    runOnJS(setOffsetDisplay)(val);
    return scrollOffset.value;
  }, [scrollOffset]);

  return (
    <View style={styles.container}>
      <Animated.ScrollView
        ref={scrollRef}
        style={styles.scroll}
        contentContainerStyle={styles.content}
        scrollEventThrottle={16}
      >
        {Array.from({ length: 30 }).map((_, i) => (
          <View key={i} style={styles.item}>
            <Text>Item {i + 1}</Text>
          </View>
        ))}
      </Animated.ScrollView>

      <View style={styles.overlay} pointerEvents="none">
        <Text style={styles.overlayText}>Scroll Offset: {offsetDisplay}</Text>
      </View>
    </View>
  );
}

