import React, { useEffect, useState } from 'react';
import { View, Text, StyleSheet } from 'react-native';
import { useSQLiteContext } from 'expo-sqlite';

interface Todo {
  id?: number;
  value: string;
  intValue: number;
}

export default function TodosList(): JSX.Element {
  // The hook returns the SQLite context provided by the Expo SQLite provider.
  // Cast to a minimal shape to keep TypeScript happy if the exact types are not present.
  const db = useSQLiteContext() as
    | { getAllAsync?: (sql: string, ...params: any[]) => Promise<Todo[]> }
    | null;

  const [todos, setTodos] = useState<Todo[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    let mounted = true;
    async function fetchTodos() {
      if (!db?.getAllAsync) {
        // If the provider/hook isn't available, mark loading false so UI doesn't hang.
        if (mounted) setLoading(false);
        return;
      }
      try {
        const result = await db.getAllAsync('SELECT * FROM todos');
        if (mounted && Array.isArray(result)) setTodos(result as Todo[]);
      } catch (error) {
        // Log error and keep UI stable
        // In production you might surface this to the user
        // or attempt a migration/initialization sequence.
        // eslint-disable-next-line no-console
        console.error('Failed to fetch todos', error);
      } finally {
        if (mounted) setLoading(false);
      }
    }
    fetchTodos();
    return () => {
      mounted = false;
    };
  }, [db]);

  if (loading) {
    return (
      <View style={styles.container}>
        <Text>Loading todos…</Text>
      </View>
    );
  }

  return (
    <View style={styles.container}>
      {todos.length === 0 ? (
        <Text>No todos found.</Text>
      ) : (
        todos.map((todo, idx) => (
          <Text key={todo.id ?? idx} style={styles.item}>
            {`${todo.intValue} - ${todo.value}`}
          </Text>
        ))
      )}
    </View>
  );
}

