export default function SecureTokenExample() {
  const [token, setToken] = useState('');
  const [storedToken, setStoredToken] = useState('');

  const saveToken = async () => {
    await SecureStore.setItemAsync('userToken', token, {
      keychainAccessible: SecureStore.AFTER_FIRST_UNLOCK_THIS_DEVICE_ONLY,
    });
    setToken('');
  };

  const getToken = async () => {
    const value = await SecureStore.getItemAsync('userToken');
    setStoredToken(value || '');
  };

  const deleteToken = async () => {
    await SecureStore.deleteItemAsync('userToken');
    setStoredToken('');
  };

  return (
    <View style={styles.container}>
      <TextInput
        style={styles.input}
        placeholder="Enter token"
        value={token}
        onChangeText={setToken}
        autoCapitalize="none"
      />
      <Button title="Save Token" onPress={saveToken} />
      <Button title="Get Token" onPress={getToken} />
      <Button title="Delete Token" onPress={deleteToken} />
      <Text style={styles.label}>Stored Token: {storedToken}</Text>
    </View>
  );
}

