// Exports a ready-to-write assetlinks.json and helper snippets for use in an Expo Router / Next.js project.
// Replace package_name and the fingerprint value(s) with your app's actual values.

export type AndroidAppTarget = {
  namespace: 'android_app';
  package_name: string;
  sha256_cert_fingerprints: string[];
};

export type AssetLink = {
  relation: string[]; // e.g. ["delegate_permission/common.handle_all_urls"]
  target: AndroidAppTarget;
};

export const assetLinks: AssetLink[] = [
  {
    relation: ["delegate_permission/common.handle_all_urls"],
    target: {
      namespace: 'android_app',
      // TODO: replace com.example with your app's package name
      package_name: 'com.example',
      // TODO: replace with your app's SHA256 certificate fingerprint(s)
      sha256_cert_fingerprints: [
        '14:6D:E9:83:51:7F:66:01:84:93:4F:2F:5E:E0:8F:3A:D6:F4:CA:41:1A:CF:45:BF:8D:10:76:76:CD'
      ]
    }
  }
];

/**
 * Returns the canonical JSON text to write to public/.well-known/assetlinks.json
 */
export function getAssetLinksJson(pretty = true): string {
  return pretty ? JSON.stringify(assetLinks, null, 2) : JSON.stringify(assetLinks);
}

/**
 * Short instructions for where to place the file so Android App Links will work:
 *
 * 1) For static hosting (recommended): create the file
 *      public/.well-known/assetlinks.json
 *    at the root of your Next.js / Expo Router project (the `public` folder is served at the app root).
 *    Paste the result of getAssetLinksJson() into that file before building.
 *
 * 2) If you must serve it at runtime using Next.js pages/api, create a file at
 *      pages/.well-known/assetlinks.json.ts
 *    with the following minimal handler (no external `next` types required):
 */
export const nextApiHandlerSnippet = `// pages/.well-known/assetlinks.json.ts
// Minimal, untyped handler for Next.js that returns the assetlinks JSON.
import type { NextApiRequest, NextApiResponse } from 'next';

const assetLinks = ${getAssetLinksJson(true)};

export default function handler(req: any, res: any) {
  res.setHeader('Content-Type', 'application/json');
  res.status(200).json(assetLinks);
}
`;

/**
 * Returns a short human instruction string explaining how to publish the file.
 */
export function installInstructions(): string {
  return [
    'Place a file named public/.well-known/assetlinks.json in your project (its contents are:)',
    getAssetLinksJson(true),
    '\nIf you use Next.js / Expo Router and prefer an API route instead, create pages/.well-known/assetlinks.json.ts using the nextApiHandlerSnippet provided in this module.'
  ].join('\n\n');
}

export default {
  assetLinks,
  getAssetLinksJson,
  nextApiHandlerSnippet,
  installInstructions
};

