type User = { id: string; name: string } | null;

// Self-contained example hook. Replace with your real auth logic or context in a real app.
function useAuth(): { user: User; loading: boolean } {
  const [user, setUser] = useState<User>(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    // Simulate an async auth check. In a real app, check auth state from context, SecureStore, or an API.
    const t = setTimeout(() => {
      // To demo the redirect, leave user as null (unauthenticated).
      // To test the authenticated path, set a user like: setUser({ id: '1', name: 'Jane' });
      setUser(null);
      setLoading(false);
    }, 250);

    return () => clearTimeout(t);
  }, []);

  return { user, loading };
}

export default function Page(): JSX.Element {
  const { user, loading } = useAuth();

  // Show a loading state while the auth check completes
  if (loading) {
    return (
      <View style={styles.container}>
        <ActivityIndicator size="large" />
      </View>
    );
  }

  // If there's no user, immediately redirect to the login screen
  if (!user) {
    return <Redirect href="/login" />;
  }

  // Authenticated UI
  return (
    <View style={styles.container}>
      <Text style={styles.text}>Welcome Back!</Text>
    </View>
  );
}

