import Animated, { useSharedValue, useAnimatedStyle, withSpring, withRepeat } from 'react-native-reanimated';

export default function BouncingBox() {
  const translateY = useSharedValue(0);

  const startBounce = () => {
    translateY.value = withRepeat(
      withSpring(-100, { damping: 8, stiffness: 120 }),
      -1, // repeat indefinitely
      true // reverse direction each time
    );
  };

  const stopBounce = () => {
    translateY.value = withSpring(0);
  };

  const animatedStyle = useAnimatedStyle(() => ({
    transform: [{ translateY: translateY.value }],
  }));

  return (
    <View style={styles.container}>
      <Animated.View style={[styles.box, animatedStyle]} />
      <View style={styles.buttons}>
        <Button title="Start Bounce" onPress={startBounce} />
        <Button title="Stop" onPress={stopBounce} />
      </View>
    </View>
  );
}

