import React, { useEffect, useRef } from 'react';
import { View, Text, StyleSheet, Animated, Easing } from 'react-native';

// Demonstrates three concurrent animations (scale, translateX, opacity)
// each using its own "animationDirection": 'alternate' | 'normal' | 'reverse'.
// This example uses the built-in Animated API so it compiles in a standard
// React Native / Expo TypeScript project.

export default function App(): JSX.Element {
  // bounceIn: scale from 0.5 -> 1
  const scale = useRef(new Animated.Value(0.5)).current;
  // move: translateX from 0 -> 100
  const translateX = useRef(new Animated.Value(0)).current;
  // slide: opacity from 0 -> 1
  const opacity = useRef(new Animated.Value(0)).current;

  // Configuration
  const duration = 2000;
  const directions: Array<'alternate' | 'normal' | 'reverse'> = [
    'alternate',
    'normal',
    'reverse',
  ];

  useEffect(() => {
    // Helper to create a timing animation between from->to using useNativeDriver
    const timing = (
      value: Animated.Value,
      toValue: number,
      dur: number,
    ) =>
      Animated.timing(value, {
        toValue,
        duration: dur,
        easing: Easing.inOut(Easing.ease),
        useNativeDriver: true,
      });

    // bounceIn animation (scale 0.5 -> 1)
    const bounceAnim = (() => {
      const from = 0.5;
      const to = 1;
      const direction = directions[0];
      if (direction === 'alternate') {
        // forward then backward, looped
        return Animated.loop(
          Animated.sequence([timing(scale, to, duration), timing(scale, from, duration)]),
        );
      }
      if (direction === 'reverse') {
        // start at `to` and animate to `from`, then reset to `to` and repeat
        scale.setValue(to);
        return Animated.loop(timing(scale, from, duration));
      }
      // normal: loop forward from `from` to `to` then reset to `from`
      scale.setValue(from);
      return Animated.loop(timing(scale, to, duration));
    })();

    // move animation (translateX 0 -> 100)
    const moveAnim = (() => {
      const from = 0;
      const to = 100;
      const direction = directions[1];
      if (direction === 'alternate') {
        return Animated.loop(
          Animated.sequence([timing(translateX, to, duration), timing(translateX, from, duration)]),
        );
      }
      if (direction === 'reverse') {
        translateX.setValue(to);
        return Animated.loop(timing(translateX, from, duration));
      }
      // normal
      translateX.setValue(from);
      return Animated.loop(timing(translateX, to, duration));
    })();

    // slide animation (opacity 0 -> 1)
    const slideAnim = (() => {
      const from = 0;
      const to = 1;
      const direction = directions[2];
      if (direction === 'alternate') {
        return Animated.loop(
          Animated.sequence([timing(opacity, to, duration), timing(opacity, from, duration)]),
        );
      }
      if (direction === 'reverse') {
        opacity.setValue(to);
        return Animated.loop(timing(opacity, from, duration));
      }
      // normal
      opacity.setValue(from);
      return Animated.loop(timing(opacity, to, duration));
    })();

    // Start all animations in parallel
    const composite = Animated.parallel([bounceAnim, moveAnim, slideAnim]);
    composite.start();

    // Cleanup: stop animations on unmount
    return () => composite.stop();
  }, [duration, directions, opacity, scale, translateX]);

  return (
    <View style={styles.container}>
      <Animated.View
        style={[
          styles.box,
          {
            opacity: opacity,
            transform: [{ scale }, { translateX }],
          },
        ]}
      >
        <Text style={styles.text}>Animated Box</Text>
      </Animated.View>

      <View style={styles.legend}>
        <Text style={styles.legendText}>Directions:</Text>
        <Text style={styles.legendText}>bounceIn: {directions[0]}</Text>
        <Text style={styles.legendText}>move: {directions[1]}</Text>
        <Text style={styles.legendText}>slide: {directions[2]}</Text>
      </View>
    </View>
  );
}

