import React, { useState } from 'react';
import { View, Button, Text, StyleSheet } from 'react-native';
import * as LocalAuthentication from 'expo-local-authentication';

export default function BiometricAuthExample() {
  const [result, setResult] = useState<string | null>(null);

  const handleAuthenticate = async () => {
    const hasHardware = await LocalAuthentication.hasHardwareAsync();
    if (!hasHardware) {
      setResult('No biometric hardware available.');
      return;
    }
    const supported = await LocalAuthentication.supportedAuthenticationTypesAsync();
    if (supported.length === 0) {
      setResult('No supported authentication types.');
      return;
    }
    const enrolled = await LocalAuthentication.isEnrolledAsync();
    if (!enrolled) {
      setResult('No biometrics enrolled.');
      return;
    }
    const auth = await LocalAuthentication.authenticateAsync({
      promptMessage: 'Authenticate with biometrics',
      fallbackLabel: 'Use Passcode',
    });
    setResult(auth.success ? 'Authenticated!' : 'Authentication failed.');
  };

  return (
    <View style={styles.container}>
      <Button title="Authenticate" onPress={handleAuthenticate} />
      {result && <Text style={styles.result}>{result}</Text>}
    </View>
  );
}

