import React from 'react';
import { View, Text, NativeModules, StyleSheet } from 'react-native';
import Constants from 'expo-constants';

const safeGetManifest = (): Record<string, any> | null => {
  // Constants.manifest may be an EmbeddedManifest without typed sdkVersion/reactNativeVersion.
  // Cast to any to safely access commonly-present fields across Expo versions.
  const c: any = Constants;
  return c.manifest ?? c.manifest2 ?? c.expoConfig ?? null;
};

const formatRNVersion = (obj: any) => {
  if (!obj) return null;
  // PlatformConstants.reactNativeVersion usually has { major, minor, patch }
  if (typeof obj === 'object' && ('major' in obj || 'minor' in obj)) {
    const major = obj.major ?? 0;
    const minor = obj.minor ?? 0;
    const patch = obj.patch ?? 0;
    return `${major}.${minor}.${patch}`;
  }
  // If it's a string (e.g. a dependency version from manifest) return as-is
  if (typeof obj === 'string') return obj;
  return null;
};

const VersionInfo: React.FC = () => {
  const manifest = safeGetManifest();

  // Expo SDK version: try manifest fields commonly used across Expo versions
  const sdkVersion = (manifest && (manifest.sdkVersion ?? manifest.expo?.sdkVersion)) ?? (Constants as any).expoVersion ?? null;

  // React Native version: prefer native PlatformConstants, fallback to manifest entries
  const platformConstants = (NativeModules as any)?.PlatformConstants ?? (NativeModules as any)?.PlatformConstantsProxy ?? null;
  const rnVersionFromNative = formatRNVersion(platformConstants?.reactNativeVersion ?? platformConstants?.ReactNativeVersion);

  // Fallbacks: manifest.reactNativeVersion or manifest.dependencies['react-native']
  const rnVersionFromManifest = formatRNVersion((manifest && (manifest.reactNativeVersion ?? manifest.dependencies?.['react-native'])) ?? null);

  const rnVersion = rnVersionFromNative ?? rnVersionFromManifest ?? 'Unknown';
  const sdkText = sdkVersion ?? 'Unknown';

  return (
    <View style={styles.container}>
      <Text style={styles.line}>Expo SDK Version: {String(sdkText)}</Text>
      <Text style={styles.line}>React Native Version (bundled on device): {String(rnVersion)}</Text>
      <Text style={styles.hint}>
        If versions look mismatched: check package.json and app.json/app.config.js to align react-native and expo sdk, and update Expo Go if needed.
      </Text>
    </View>
  );
};

const styles = StyleSheet.create({
  container: { padding: 16 },
  line: { fontSize: 16, marginBottom: 8 },
  hint: { fontSize: 12, color: '#666' },
});

export default VersionInfo;

