import React, { useEffect, useState } from 'react';
import { View, Text, Button, StyleSheet, Alert } from 'react-native';
import * as Location from 'expo-location';
import * as TaskManager from 'expo-task-manager';

const LOCATION_TASK_NAME = 'background-location-task';

// Define the task with explicit typing for the task body so TypeScript knows
// that `data` contains a `locations` array when Location.startLocationUpdatesAsync is used.
TaskManager.defineTask(
  LOCATION_TASK_NAME,
  async (taskData: TaskManager.TaskManagerTaskBody<{ locations: Location.LocationObject[] }>) => {
    const { data, error } = taskData;
    if (error) {
      // Task manager reported an error
      console.error('Background location task error:', error);
      return;
    }

    if (data && 'locations' in data) {
      const { locations } = data as { locations: Location.LocationObject[] };
      // Handle received locations (this runs in the background)
      // Keep work minimal here — e.g., send to your server or store locally.
      console.log(`[${LOCATION_TASK_NAME}] Received ${locations.length} location(s)`);
      locations.forEach((loc) => console.log('lat:', loc.coords.latitude, 'lon:', loc.coords.longitude));
    }
  }
);

export default function App(): JSX.Element {
  const [started, setStarted] = useState(false);

  useEffect(() => {
    // Check if task is defined (development safety)
    if (!TaskManager.isTaskDefined(LOCATION_TASK_NAME)) {
      console.warn(`${LOCATION_TASK_NAME} is not defined.`);
    }
  }, []);

  const ensurePermissions = async (): Promise<boolean> => {
    try {
      const { status: fgStatus } = await Location.requestForegroundPermissionsAsync();
      if (fgStatus !== 'granted') {
        Alert.alert('Permission required', 'Foreground location permission is required.');
        return false;
      }

      // Background permission APIs differ by platform; request explicitly on iOS/Android
      const { status: bgStatus } = await Location.requestBackgroundPermissionsAsync();
      if (bgStatus !== 'granted') {
        Alert.alert('Permission required', 'Background location permission is required for this feature.');
        return false;
      }

      return true;
    } catch (err) {
      console.error('Permission request error:', err);
      return false;
    }
  };

  const startBackgroundLocation = async () => {
    const ok = await ensurePermissions();
    if (!ok) return;

    try {
      await Location.startLocationUpdatesAsync(LOCATION_TASK_NAME, {
        // Recommended options for background location
        accuracy: Location.Accuracy.High,
        // On iOS, showsBackgroundLocationIndicator requires an Info.plist justification and will show the blue bar
        showsBackgroundLocationIndicator: true,
        pausesUpdatesAutomatically: false,
        // Activity type influences system behavior on iOS
        activityType: Location.ActivityType.Fitness,
        // Optionally control distance interval or time interval
        // distanceInterval: 50, // meters
      });

      setStarted(true);
      Alert.alert('Background location', 'Started background location updates.');
    } catch (err) {
      console.error('Failed to start background location updates:', err);
      Alert.alert('Error', 'Could not start background location updates.');
    }
  };

  const stopBackgroundLocation = async () => {
    try {
      await Location.stopLocationUpdatesAsync(LOCATION_TASK_NAME);
      setStarted(false);
      Alert.alert('Background location', 'Stopped background location updates.');
    } catch (err) {
      console.error('Failed to stop background location updates:', err);
      Alert.alert('Error', 'Could not stop background location updates.');
    }
  };

  return (
    <View style={styles.container}>
      <Text style={styles.title}>Background Location (Expo)</Text>
      <Text style={styles.desc}>
        This example defines a top-level TaskManager task and starts/stops background location updates.
      </Text>
      <View style={styles.buttons}>
        <Button title="Start Background Location" onPress={startBackgroundLocation} disabled={started} />
        <View style={styles.spacer} />
        <Button title="Stop Background Location" onPress={stopBackgroundLocation} disabled={!started} />
      </View>
      <Text style={styles.note}>
        Note: On iOS add UIBackgroundModes = ["location"] to ios/YourApp/Supporting/Expo.plist (or Info.plist for native
        projects). Use a development build — background location is not supported in Expo Go.
      </Text>
    </View>
  );
}

