export default function LocationPermissionScreen() {
  const [status, setStatus] = useState<Location.PermissionStatus | null>(null);
  const [bgStatus, setBgStatus] = useState<Location.PermissionStatus | null>(null);

  useEffect(() => {
    (async () => {
      const { status } = await Location.requestForegroundPermissionsAsync();
      setStatus(status);
    })();
  }, []);

  const requestBackground = async () => {
    if (Platform.OS === 'ios' || Platform.OS === 'android') {
      const { status } = await Location.requestBackgroundPermissionsAsync();
      setBgStatus(status);
    }
  };

  const openSettings = () => {
    Linking.openURL('app-settings:');
  };

  return (
    <View style={{ flex: 1, justifyContent: 'center', alignItems: 'center' }}>
      <Text>Foreground permission: {status}</Text>
      <Button title="Request Background Permission" onPress={requestBackground} />
      {bgStatus === 'denied' && (
        <View style={{ marginTop: 20 }}>
          <Text>Background permission denied. Please enable it in Settings.</Text>
          <Button title="Open Settings" onPress={openSettings} />
        </View>
      )}
    </View>
  );
}

