import { getDefaultConfig } from 'expo/metro-config';

// Get the default Expo Metro config and mark it as mutable for TypeScript.
const config = getDefaultConfig(__dirname) as any;

// Keep a reference to the original resolver function if present.
const originalResolveRequest = config.resolver?.resolveRequest;

// Replace the resolver with a shallow-cloned resolver that overrides resolveRequest.
config.resolver = {
  ...(config.resolver || {}),
  resolveRequest: (context: any, moduleName: string, platform?: string) => {
    // When building for web, treat 'lodash' as an empty module.
    if (platform === 'web' && moduleName === 'lodash') {
      return { type: 'empty' };
    }

    // Prefer calling the original resolver if available.
    if (typeof originalResolveRequest === 'function') {
      return originalResolveRequest(context, moduleName, platform);
    }

    // Fallback to context.resolveRequest if provided by Metro.
    if (context && typeof context.resolveRequest === 'function') {
      return context.resolveRequest(context, moduleName, platform);
    }

    // If all else fails, return null to let Metro handle it.
    return null;
  },
};

export default config;

