const IS_PRODUCTION = false; // Set to true for production
const nativeDeviceToken = 'YOUR_DEVICE_TOKEN';
const authorizationToken = 'YOUR_JWT_TOKEN';
const BUNDLE_IDENTIFIER = 'YOUR-BUNDLE-IDENTIFIER';

