import React from 'react';
import Animated, { useSharedValue, useAnimatedStyle } from 'react-native-reanimated';

// Simple test component that uses a shared value for width
export const TestComponent: React.FC = () => {
  const width = useSharedValue(100);
  const animatedStyle = useAnimatedStyle(() => ({ width: width.value }));
  return <Animated.View testID="box" style={animatedStyle} />;
};

/**
 * Extracts the flattened style object for the element with testID 'box' from
 * a render result returned by @testing-library/react-native's render().
 *
 * This helper intentionally uses broad `any` types so the module itself
 * compiles in projects that don't have test-runner type declarations.
 *
 * Usage example (in your Jest test file):
 *
 * import { render } from '@testing-library/react-native';
 * import { TestComponent, assertAnimatedStyle } from './check';
 *
 * test('animated width equals 100', () => {
 *   const res = render(<TestComponent />);
 *   // Provide Jest's expect matcher to make a clear assertion inside the helper
 *   assertAnimatedStyle(res, { width: 100 }, (received, expected) => {
 *     expect(received).toMatchObject(expected);
 *   });
 * });
 */
export function getRenderedBoxStyle(renderResult: any): Record<string, unknown> | undefined {
  if (!renderResult) return undefined;
  // Support testing-library/react-native render result
  const byId = typeof renderResult.getByTestId === 'function' ? renderResult.getByTestId : renderResult.getByQuerySelector;
  const box = typeof renderResult.getByTestId === 'function' ? renderResult.getByTestId('box') : undefined;

  // If not available, try returned JSON or root queries
  const node = box ?? (renderResult?.toJSON ? renderResult.toJSON() : undefined);

  // Many test renderers put style on props.style
  const styleProp = node?.props?.style ?? node?.style ?? undefined;
  if (!styleProp) return undefined;

  // Flatten array styles if needed
  if (Array.isArray(styleProp)) {
    return Object.assign({}, ...styleProp.map((s: any) => (s == null ? {} : s)));
  }
  if (typeof styleProp === 'object') return styleProp as Record<string, unknown>;
  return undefined;
}

/**
 * Assert that the rendered TestComponent has expected animated style properties.
 *
 * - renderResult: the value returned from render(<TestComponent />)
 * - expectedStyle: partial style object to check, e.g. { width: 100 }
 * - matcher: optional function to run the assertion (receives receivedStyle and expectedStyle).
 *            If omitted, a simple equality check is performed and an Error is thrown on mismatch.
 */
export function assertAnimatedStyle(
  renderResult: any,
  expectedStyle: Record<string, unknown>,
  matcher?: (received: Record<string, unknown> | undefined, expected: Record<string, unknown>) => void
): void {
  const style = getRenderedBoxStyle(renderResult);

  if (typeof matcher === 'function') {
    matcher(style, expectedStyle);
    return;
  }

  // Default check: ensure all expected keys strictly equal the rendered style values
  const missing: string[] = [];
  for (const key of Object.keys(expectedStyle)) {
    const exp = (expectedStyle as any)[key];
    const got = style ? (style as any)[key] : undefined;
    if (got !== exp) missing.push(`${key}: expected ${String(exp)}, got ${String(got)}`);
  }
  if (missing.length > 0) {
    throw new Error('Animated style mismatch: ' + missing.join('; ') + `; full style: ${JSON.stringify(style)}`);
  }
}

